'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import { Users, Plus, Search, Edit, Trash2 } from 'lucide-react';
import { useToast, Modal, Input, Button, Select } from '@/components/ui';
import { useTranslation } from '@/hooks/useTranslation';

const groups = [
    { id: 1, name: 'VIP Clients', members: 24, discount: 15, color: '#F59E0B', description: 'High-value repeat clients with priority booking', status: 'active' },
    { id: 2, name: 'Regular Members', members: 86, discount: 5, color: '#3B82F6', description: 'Standard membership with basic benefits', status: 'active' },
    { id: 3, name: 'New Clients', members: 32, discount: 10, color: '#10B981', description: 'First-time visitors with welcome offer', status: 'active' },
    { id: 4, name: 'Corporate Partners', members: 15, discount: 20, color: '#8B5CF6', description: 'Company partnership program employees', status: 'active' },
    { id: 5, name: 'Student Discount', members: 18, discount: 25, color: '#EC4899', description: 'Verified students with valid ID', status: 'active' },
    { id: 6, name: 'Loyalty Platinum', members: 8, discount: 30, color: '#6B7280', description: 'Top-tier loyalty program members', status: 'draft' },
];

const s: Record<string, React.CSSProperties> = {
    page: { display: 'flex', flexDirection: 'column', gap: 'var(--space-5)' },
    tabs: { display: 'flex', gap: 'var(--space-1)', borderBottom: '2px solid var(--border-color)' },
    tab: { padding: 'var(--space-3) var(--space-4)', fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', color: 'var(--text-tertiary)', borderBottom: '2px solid transparent', marginBottom: '-2px', whiteSpace: 'nowrap', textDecoration: 'none' },
    tabActive: { color: 'var(--color-primary-500)', borderBottomColor: 'var(--color-primary-500)' },
    toolbar: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 'var(--space-3)', flexWrap: 'wrap' },
    searchBox: { position: 'relative', flex: 1, maxWidth: 320 },
    searchIcon: { position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-tertiary)' },
    searchInput: { width: '100%', height: 40, paddingLeft: 40, border: '1px solid var(--border-color)', borderRadius: 'var(--radius-lg)', background: 'var(--bg-primary)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)' },
    addBtn: { display: 'flex', alignItems: 'center', gap: 'var(--space-2)', padding: 'var(--space-2) var(--space-5)', background: 'var(--color-primary-500)', color: 'white', borderRadius: 'var(--radius-lg)', fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)' },
    grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: 'var(--space-5)' },
    card: { background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-xl)', overflow: 'hidden' },
    cardHead: { padding: 'var(--space-5)', display: 'flex', alignItems: 'center', gap: 'var(--space-3)' },
    icon: { width: 44, height: 44, borderRadius: 'var(--radius-lg)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', flexShrink: 0 },
    cardTitle: { fontSize: 'var(--text-lg)', fontWeight: 'var(--font-semibold)' },
    cardDesc: { fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)', marginTop: 2 },
    cardBody: { padding: '0 var(--space-5) var(--space-4)', display: 'flex', gap: 'var(--space-5)' },
    stat: { textAlign: 'center' },
    statVal: { fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)' },
    statLbl: { fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' },
    cardFooter: { display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-2)', padding: 'var(--space-3) var(--space-5)', borderTop: '1px solid var(--border-color)' },
    btnIcon: { display: 'flex', alignItems: 'center', justifyContent: 'center', width: 32, height: 32, borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)', background: 'var(--bg-primary)', cursor: 'pointer', color: 'var(--text-secondary)' },
};

export default function CustomerGroupsPage() {
    const { addToast } = useToast();
    const { t, lang } = useTranslation();
    const [search, setSearch] = useState('');
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [selectedGroup, setSelectedGroup] = useState<any>(null);

    const filtered = groups.filter(g => g.name.toLowerCase().includes(search.toLowerCase()));

    return (
        <div style={{ ...s.page, direction: lang === 'ar' ? 'rtl' : 'ltr' } as React.CSSProperties}>
            <div style={s.tabs as React.CSSProperties}>
                <Link href="/customers" style={s.tab as React.CSSProperties}>{t('custGroups.tabClients')}</Link>
                <Link href="/customers/groups" style={{ ...s.tab, ...s.tabActive } as React.CSSProperties}>{t('custGroups.tabGroups')}</Link>
                <Link href="/customers/statements" style={s.tab as React.CSSProperties}>{t('custGroups.tabStatements')}</Link>
                <Link href="/customers/last-visits" style={s.tab as React.CSSProperties}>{t('custGroups.tabLastVisits')}</Link>
            </div>

            <div style={s.toolbar as React.CSSProperties}>
                <div style={s.searchBox as React.CSSProperties}>
                    <Search size={16} style={{ ...s.searchIcon, ...(lang === 'ar' ? { right: 12, left: 'auto' } : { left: 12, right: 'auto' }) } as React.CSSProperties} />
                    <input style={{ ...s.searchInput, ...(lang === 'ar' ? { paddingRight: 40, paddingLeft: 12 } : { paddingLeft: 40, paddingRight: 12 }) } as React.CSSProperties} placeholder={t('custGroups.searchPlaceholder')} value={search} onChange={e => setSearch(e.target.value)} />
                </div>
                <button style={s.addBtn as React.CSSProperties} onClick={() => setIsAddOpen(true)}><Plus size={16} /> {t('custGroups.newGroup')}</button>
            </div>

            <div style={s.grid as React.CSSProperties}>
                {filtered.map(g => (
                    <div key={g.id} style={s.card as React.CSSProperties}>
                        <div style={s.cardHead as React.CSSProperties}>
                            <div style={{ ...s.icon, background: g.color } as React.CSSProperties}><Users size={20} /></div>
                            <div>
                                <div style={s.cardTitle as React.CSSProperties}>{g.name}</div>
                                <div style={s.cardDesc as React.CSSProperties}>{g.description}</div>
                            </div>
                        </div>
                        <div style={s.cardBody as React.CSSProperties}>
                            <div style={s.stat as React.CSSProperties}>
                                <div style={s.statVal as React.CSSProperties}>{g.members}</div>
                                <div style={s.statLbl as React.CSSProperties}>{t('custGroups.members')}</div>
                            </div>
                            <div style={s.stat as React.CSSProperties}>
                                <div style={{ ...s.statVal, color: 'var(--color-primary-600)' } as React.CSSProperties}>{g.discount}%</div>
                                <div style={s.statLbl as React.CSSProperties}>{t('custGroups.discount')}</div>
                            </div>
                        </div>
                        <div style={s.cardFooter as React.CSSProperties}>
                            <button style={s.btnIcon as React.CSSProperties} onClick={() => { setSelectedGroup(g); setIsEditOpen(true); }}><Edit size={14} /></button>
                            <button style={{ ...s.btnIcon, color: 'var(--color-error)' } as React.CSSProperties} onClick={() => { setSelectedGroup(g); setIsDeleteOpen(true); }}><Trash2 size={14} /></button>
                        </div>
                    </div>
                ))}
            </div>

            {/* Add Group Modal */}
            <Modal
                open={isAddOpen}
                onClose={() => setIsAddOpen(false)}
                title={t('custGroups.createGroup')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('custGroups.cancel')}</Button>
                        <Button onClick={() => { setIsAddOpen(false); addToast('success', t('custGroups.msgCreated')); }}>{t('custGroups.saveGroup')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('custGroups.groupName')} placeholder="e.g. VIP Clients" />
                    <Input label={t('custGroups.description')} placeholder="Short description of this group..." />
                    <Input label={t('custGroups.discountPercent')} type="number" defaultValue={0} />
                    <Select label={t('custGroups.status')} options={[{ label: t('custGroups.active'), value: 'active' }, { label: t('custGroups.draft'), value: 'draft' }]} />
                </div>
            </Modal>

            {/* Edit Group Modal */}
            <Modal
                open={isEditOpen}
                onClose={() => { setIsEditOpen(false); setSelectedGroup(null); }}
                title={t('custGroups.editGroup')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('custGroups.cancel')}</Button>
                        <Button onClick={() => { setIsEditOpen(false); addToast('success', t('custGroups.msgUpdated')); }}>{t('custGroups.saveChanges')}</Button>
                    </div>
                }
            >
                {selectedGroup && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        <Input label={t('custGroups.groupName')} defaultValue={selectedGroup.name} />
                        <Input label={t('custGroups.description')} defaultValue={selectedGroup.description} />
                        <Input label={t('custGroups.discountPercent')} type="number" defaultValue={selectedGroup.discount} />
                        <Select label={t('custGroups.status')} defaultValue={selectedGroup.status} options={[{ label: t('custGroups.active'), value: 'active' }, { label: t('custGroups.draft'), value: 'draft' }]} />
                    </div>
                )}
            </Modal>

            {/* Delete Confirmation Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedGroup(null); }}
                title={t('custGroups.deleteGroup')}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('custGroups.cancel')}</Button>
                        <Button variant="destructive" onClick={() => { setIsDeleteOpen(false); addToast('error', t('custGroups.msgDeleted')); }}>{t('custGroups.confirmDelete')}</Button>
                    </div>
                }
            >
                <div>
                    <p style={{ color: 'var(--text-secondary)' }}>
                        {t('custGroups.deleteConfirm')} <strong>{selectedGroup?.name}</strong> {t('custGroups.groupQuestion')}
                    </p>
                </div>
            </Modal>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import Link from 'next/link';
import { Search, AlertCircle, Phone } from 'lucide-react';
import { useTranslation } from '@/hooks/useTranslation';

const data = [
    { id: 1, client: 'Fatima Ali', phone: '+20 123 456 789', lastService: 'Hair Coloring', lastEmployee: 'Sara Ahmed', lastDate: '2026-02-17', daysSince: 0, followUp: false },
    { id: 2, client: 'Rania Khalil', phone: '+20 111 222 333', lastService: 'Keratin Treatment', lastEmployee: 'Sara Ahmed', lastDate: '2026-02-16', daysSince: 1, followUp: false },
    { id: 3, client: 'Noura Ahmed', phone: '+20 100 200 300', lastService: 'Swedish Massage', lastEmployee: 'Layla Hassan', lastDate: '2026-02-10', daysSince: 7, followUp: false },
    { id: 4, client: 'Huda Saleh', phone: '+20 155 666 777', lastService: 'HydraFacial', lastEmployee: 'Nora Ali', lastDate: '2026-02-03', daysSince: 14, followUp: true },
    { id: 5, client: 'Maryam Ibrahim', phone: '+20 122 333 444', lastService: 'Classic Facial', lastEmployee: 'Nora Ali', lastDate: '2026-01-20', daysSince: 28, followUp: true },
    { id: 6, client: 'Sama Latif', phone: '+20 133 444 555', lastService: 'Gel Manicure', lastEmployee: 'Hana Youssef', lastDate: '2026-01-10', daysSince: 38, followUp: true },
    { id: 7, client: 'Dana Faris', phone: '+20 144 555 666', lastService: 'Deep Tissue', lastEmployee: 'Reem Mohamed', lastDate: '2025-12-25', daysSince: 54, followUp: true },
    { id: 8, client: 'Lina Qasim', phone: '+20 166 777 888', lastService: 'Pedicure', lastEmployee: 'Hana Youssef', lastDate: '2025-12-01', daysSince: 78, followUp: true },
];

const s: Record<string, React.CSSProperties> = {
    page: { display: 'flex', flexDirection: 'column', gap: 'var(--space-5)' },
    tabs: { display: 'flex', gap: 'var(--space-1)', borderBottom: '2px solid var(--border-color)' },
    tab: { padding: 'var(--space-3) var(--space-4)', fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', color: 'var(--text-tertiary)', borderBottom: '2px solid transparent', marginBottom: '-2px', whiteSpace: 'nowrap', textDecoration: 'none' },
    tabActive: { color: 'var(--color-primary-500)', borderBottomColor: 'var(--color-primary-500)' },
    toolbar: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 'var(--space-3)', flexWrap: 'wrap' },
    searchBox: { position: 'relative', flex: 1, maxWidth: 320 },
    searchIcon: { position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-tertiary)' },
    searchInput: { width: '100%', height: 40, paddingLeft: 40, border: '1px solid var(--border-color)', borderRadius: 'var(--radius-lg)', background: 'var(--bg-primary)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)' },
    table: { width: '100%', background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-xl)', overflow: 'hidden' },
    th: { padding: 'var(--space-3) var(--space-4)', textAlign: 'left', fontSize: 'var(--text-xs)', fontWeight: 'var(--font-semibold)', color: 'var(--text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', background: 'var(--bg-secondary)' },
    td: { padding: 'var(--space-3) var(--space-4)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)', borderTop: '1px solid var(--border-color)' },
    badge: { display: 'inline-flex', alignItems: 'center', gap: 4, padding: '2px 8px', borderRadius: 'var(--radius-full)', fontSize: 11, fontWeight: 'var(--font-semibold)' },
    callBtn: { display: 'inline-flex', alignItems: 'center', gap: 4, padding: '4px 10px', borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)', background: 'var(--bg-primary)', cursor: 'pointer', fontSize: 12, color: 'var(--color-primary-600)' },
};

function getDaysBadge(days: number, t: any) {
    if (days <= 7) return { bg: 'var(--color-success-light)', color: 'var(--color-success)', label: `${days} ${t('custVisits.daysAgo')}` };
    if (days <= 30) return { bg: 'var(--color-warning-light)', color: 'var(--color-warning)', label: `${days} ${t('custVisits.daysAgo')}` };
    return { bg: 'var(--color-error-light)', color: 'var(--color-error)', label: `${days} ${t('custVisits.daysAgo')}` };
}

export default function LastVisitsPage() {
    const { t, lang } = useTranslation();
    const [search, setSearch] = useState('');
    const filtered = data.filter(d => d.client.toLowerCase().includes(search.toLowerCase()));

    return (
        <div style={{ ...s.page, direction: lang === 'ar' ? 'rtl' : 'ltr' } as React.CSSProperties}>
            <div style={s.tabs as React.CSSProperties}>
                <Link href="/customers" style={s.tab as React.CSSProperties}>{t('custGroups.tabClients')}</Link>
                <Link href="/customers/groups" style={s.tab as React.CSSProperties}>{t('custGroups.tabGroups')}</Link>
                <Link href="/customers/statements" style={s.tab as React.CSSProperties}>{t('custGroups.tabStatements')}</Link>
                <Link href="/customers/last-visits" style={{ ...s.tab, ...s.tabActive } as React.CSSProperties}>{t('custGroups.tabLastVisits')}</Link>
            </div>

            <div style={s.toolbar as React.CSSProperties}>
                <div style={s.searchBox as React.CSSProperties}><Search size={16} style={{ ...s.searchIcon, ...(lang === 'ar' ? { right: 12, left: 'auto' } : { left: 12, right: 'auto' }) } as React.CSSProperties} /><input style={{ ...s.searchInput, ...(lang === 'ar' ? { paddingRight: 40, paddingLeft: 12 } : { paddingLeft: 40, paddingRight: 12 }) } as React.CSSProperties} placeholder={t('custStmts.searchPlaceholder')} value={search} onChange={e => setSearch(e.target.value)} /></div>
            </div>

            <table style={s.table as React.CSSProperties}>
                <thead><tr>{[t('custStmts.colClient'), t('custProfile.lblPhone'), t('custVisits.colLastService'), t('custProfile.colEmp'), t('custVisits.colLastVisit'), t('custVisits.colDaysSince'), t('custVisits.colFollowUp'), ''].map((h, i) => <th key={i} style={{ ...s.th, textAlign: lang === 'ar' ? 'right' : 'left' } as React.CSSProperties}>{h}</th>)}</tr></thead>
                <tbody>
                    {filtered.map(row => {
                        const daysInfo = getDaysBadge(row.daysSince, t);
                        return (
                            <tr key={row.id}>
                                <td style={{ ...s.td, fontWeight: 'var(--font-medium)' } as React.CSSProperties}>{row.client}</td>
                                <td style={s.td as React.CSSProperties} dir="ltr" className={lang === 'ar' ? 'text-right' : 'text-left'}>{row.phone}</td>
                                <td style={s.td as React.CSSProperties}>{row.lastService}</td>
                                <td style={s.td as React.CSSProperties}>{row.lastEmployee}</td>
                                <td style={s.td as React.CSSProperties}>{row.lastDate}</td>
                                <td style={s.td as React.CSSProperties}><span style={{ ...s.badge, background: daysInfo.bg, color: daysInfo.color } as React.CSSProperties}>{daysInfo.label}</span></td>
                                <td style={s.td as React.CSSProperties}>
                                    {row.followUp && <span style={{ ...s.badge, background: 'var(--color-warning-light)', color: 'var(--color-warning)' } as React.CSSProperties}><AlertCircle size={12} className={lang === 'ar' ? 'ml-1' : 'mr-1'} /> {t('custVisits.needsFollowUp')}</span>}
                                </td>
                                <td style={s.td as React.CSSProperties}><button style={s.callBtn as React.CSSProperties}><Phone size={12} className={lang === 'ar' ? 'ml-1' : 'mr-1'} /> {t('custVisits.callBtn')}</button></td>
                            </tr>
                        );
                    })}
                </tbody>
            </table>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { DropdownMenu, EmptyState, useToast, SlideOver, Input, Select, Modal, Button } from '@/components/ui';
import { useRouter } from 'next/navigation';
import {
    Search,
    ChevronLeft,
    ChevronRight,
    MoreVertical,
    Phone,
    Mail,
    Star,
    AlertTriangle,
    Users,
    UserPlus,
    CreditCard,
} from 'lucide-react';
import styles from './customers.module.css';
import { useTranslation } from '@/hooks/useTranslation';

const clients = [
    { id: 'C001', name: 'Fatima Al-Rashid', phone: '+20 123 456 789', email: 'fatima@email.com', visits: 24, spend: 8400, lastVisit: 'Feb 15, 2026', vip: true, hasAllergy: true, group: 'VIP', status: 'active' },
    { id: 'C002', name: 'Aisha Mohammed', phone: '+20 111 222 333', email: 'aisha@email.com', visits: 19, spend: 6250, lastVisit: 'Feb 12, 2026', vip: true, hasAllergy: false, group: 'VIP', status: 'active' },
    { id: 'C003', name: 'Maryam Ibrahim', phone: '+20 100 200 300', email: 'maryam@email.com', visits: 17, spend: 5800, lastVisit: 'Feb 10, 2026', vip: false, hasAllergy: false, group: 'Regular', status: 'active' },
    { id: 'C004', name: 'Huda Saleh', phone: '+20 155 666 777', email: 'huda@email.com', visits: 15, spend: 4900, lastVisit: 'Feb 8, 2026', vip: false, hasAllergy: true, group: 'Regular', status: 'active' },
    { id: 'C005', name: 'Noura Ahmed', phone: '+20 199 888 999', email: 'noura@email.com', visits: 12, spend: 3600, lastVisit: 'Feb 5, 2026', vip: false, hasAllergy: false, group: 'Regular', status: 'active' },
    { id: 'C006', name: 'Rania Khalil', phone: '+20 133 444 555', email: 'rania@email.com', visits: 8, spend: 2400, lastVisit: 'Jan 28, 2026', vip: false, hasAllergy: false, group: 'New', status: 'active' },
    { id: 'C007', name: 'Dana Faris', phone: '+20 177 333 222', email: 'dana@email.com', visits: 6, spend: 1800, lastVisit: 'Jan 20, 2026', vip: false, hasAllergy: false, group: 'New', status: 'inactive' },
    { id: 'C008', name: 'Lina Tariq', phone: '+20 122 555 666', email: 'lina@email.com', visits: 3, spend: 750, lastVisit: 'Jan 10, 2026', vip: false, hasAllergy: false, group: 'New', status: 'inactive' },
];

export default function CustomersPage() {
    const [search, setSearch] = useState('');
    const [groupFilter, setGroupFilter] = useState('all');

    // CRUD State
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [selectedClient, setSelectedClient] = useState<any>(null);

    const router = useRouter();
    const { addToast } = useToast();
    const { t } = useTranslation();

    const filtered = clients.filter((c) => {
        const matchSearch =
            c.name.toLowerCase().includes(search.toLowerCase()) ||
            c.phone.includes(search) ||
            c.email.toLowerCase().includes(search.toLowerCase());
        const matchGroup = groupFilter === 'all' || c.group.toLowerCase() === groupFilter;
        return matchSearch && matchGroup;
    });

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-6)' }}>
            {/* KPI Row */}
            <div className={styles.kpiRow}>
                <div className={styles.kpiCard}>
                    <div className={styles.kpiIcon} style={{ background: 'var(--color-primary-50)', color: 'var(--color-primary-600)' }}>
                        <Users size={22} />
                    </div>
                    <div>
                        <div className={styles.kpiValue}>{clients.length}</div>
                        <div className={styles.kpiLabel}>{t('customers.totalClients')}</div>
                    </div>
                </div>
                <div className={styles.kpiCard}>
                    <div className={styles.kpiIcon} style={{ background: '#FEF3C7', color: '#B45309' }}>
                        <Star size={22} />
                    </div>
                    <div>
                        <div className={styles.kpiValue}>{clients.filter((c) => c.vip).length}</div>
                        <div className={styles.kpiLabel}>{t('customers.vipClients')}</div>
                    </div>
                </div>
                <div className={styles.kpiCard}>
                    <div className={styles.kpiIcon} style={{ background: 'var(--color-info-light)', color: 'var(--color-info)' }}>
                        <UserPlus size={22} />
                    </div>
                    <div>
                        <div className={styles.kpiValue}>{clients.filter((c) => c.group === 'New').length}</div>
                        <div className={styles.kpiLabel}>{t('customers.newThisMonth')}</div>
                    </div>
                </div>
                <div className={styles.kpiCard}>
                    <div className={styles.kpiIcon} style={{ background: 'var(--color-error-light)', color: 'var(--color-error)' }}>
                        <AlertTriangle size={22} />
                    </div>
                    <div>
                        <div className={styles.kpiValue}>{clients.filter((c) => c.status === 'inactive').length}</div>
                        <div className={styles.kpiLabel}>{t('customers.inactive')}</div>
                    </div>
                </div>
            </div>

            <div className={styles.controls}>
                <div className={styles.searchWrapper}>
                    <Search size={16} className={styles.searchIcon} />
                    <input
                        className={styles.searchInput}
                        placeholder={t('customers.search')}
                        value={search}
                        onChange={(e) => setSearch(e.target.value)}
                    />
                </div>
                <div style={{ display: 'flex', gap: 'var(--space-3)' }}>
                    <select
                        className={styles.selectFilter}
                        value={groupFilter}
                        onChange={(e) => setGroupFilter(e.target.value)}
                    >
                        <option value="all">{t('customers.allGroups')}</option>
                        <option value="vip">{t('customers.vip')}</option>
                        <option value="regular">{t('customers.regular')}</option>
                        <option value="new">{t('customers.new')}</option>
                    </select>
                    <button className={styles.btnPrimary} onClick={() => setIsAddOpen(true)}>
                        <UserPlus size={16} /> {t('customers.addClient')}
                    </button>
                </div>
            </div>

            <div className={styles.tableCard}>
                {filtered.length > 0 ? (
                    <>
                        <table className={styles.dataTable}>
                            <thead>
                                <tr>
                                    <th>{t('customers.colClient')}</th>
                                    <th>{t('customers.colContact')}</th>
                                    <th>{t('customers.colGroup')}</th>
                                    <th>{t('customers.colVisits')}</th>
                                    <th>{t('customers.colTotalSpend')}</th>
                                    <th>{t('customers.colLastVisit')}</th>
                                    <th>{t('customers.colFlags')}</th>
                                    <th></th>
                                </tr>
                            </thead>
                            <tbody>
                                {filtered.map((c) => (
                                    <tr key={c.id} onClick={() => router.push(`/customers/${c.id}`)} style={{ cursor: 'pointer' }}>
                                        <td>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-3)' }}>
                                                <div className={styles.avatar}>
                                                    {c.name.split(' ').map((n) => n[0]).join('').slice(0, 2)}
                                                </div>
                                                <div>
                                                    <div style={{ fontWeight: 'var(--font-semibold)', display: 'flex', alignItems: 'center', gap: 'var(--space-1)' }}>
                                                        {c.name}
                                                        {c.vip && <Star size={14} fill="#F59E0B" stroke="#F59E0B" />}
                                                    </div>
                                                    <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{c.id}</div>
                                                </div>
                                            </div>
                                        </td>
                                        <td>
                                            <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
                                                <span style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-1)', fontSize: 'var(--text-sm)' }}>
                                                    <Phone size={12} style={{ color: 'var(--text-tertiary)' }} /> {c.phone}
                                                </span>
                                                <span style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-1)', fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>
                                                    <Mail size={12} /> {c.email}
                                                </span>
                                            </div>
                                        </td>
                                        <td>
                                            <span className={`${styles.groupBadge} ${styles[`group${c.group}`]}`}>
                                                {c.group}
                                            </span>
                                        </td>
                                        <td style={{ fontWeight: 'var(--font-medium)' }}>{c.visits}</td>
                                        <td style={{ fontWeight: 'var(--font-semibold)', color: 'var(--color-primary-600)' }}>
                                            {c.spend.toLocaleString()} EGP
                                        </td>
                                        <td>
                                            <span style={{ color: c.status === 'inactive' ? 'var(--color-error)' : 'var(--text-secondary)' }}>
                                                {c.lastVisit}
                                            </span>
                                        </td>
                                        <td>
                                            <div style={{ display: 'flex', gap: 'var(--space-1)' }}>
                                                {c.hasAllergy && (
                                                    <span className={styles.flagBadge} title={t('customers.hasAllergies')}>
                                                        <AlertTriangle size={12} /> {t('customers.allergy')}
                                                    </span>
                                                )}
                                            </div>
                                        </td>
                                        <td>
                                            <DropdownMenu
                                                trigger={
                                                    <button
                                                        className={styles.actionBtn}
                                                    >
                                                        <MoreVertical size={16} />
                                                    </button>
                                                }
                                                items={[
                                                    { label: t('customers.viewProfile'), icon: <Users size={14} />, onClick: () => router.push(`/customers/${c.id}`) },
                                                    { label: t('customers.edit'), icon: <CreditCard size={14} />, onClick: () => { setSelectedClient(c); setIsEditOpen(true); } },
                                                    { label: t('customers.delete'), destructive: true, icon: <AlertTriangle size={14} />, onClick: () => { setSelectedClient(c); setIsDeleteOpen(true); } },
                                                ]}
                                            />
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                        <div className={styles.pagination}>
                            <span className={styles.pageInfo}>{t('customers.showing')} {filtered.length} {t('customers.of')} {clients.length}</span>
                            <div className={styles.pageButtons}>
                                <button className={styles.pageBtn}><ChevronLeft size={16} /></button>
                                <button className={`${styles.pageBtn} ${styles.pageBtnActive}`}>1</button>
                                <button className={styles.pageBtn}><ChevronRight size={16} /></button>
                            </div>
                        </div>
                    </>
                ) : (
                    <div style={{ padding: 'var(--space-12) 0' }}>
                        <EmptyState
                            icon={<Users size={32} color="var(--text-tertiary)" />}
                            title={t('customers.noClients')}
                            description={t('customers.noClientsDesc')}
                        />
                    </div>
                )}
            </div>

            {/* Add Client SlideOver */}
            <SlideOver
                open={isAddOpen}
                onClose={() => setIsAddOpen(false)}
                title={t('customers.addClientTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('customers.cancel')}</Button>
                        <Button onClick={() => { setIsAddOpen(false); addToast('success', t('customers.toastCreated')); }}>{t('customers.saveClient')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('customers.fullName')} placeholder="e.g. Fatima Al-Rashid" />
                    <Input label={t('customers.phoneOption')} placeholder="+20 1XX XXX XXXX" />
                    <Input label={t('customers.emailOption')} placeholder="client@example.com" />
                    <Select label={t('customers.groupLabel')} options={[
                        { label: t('customers.regular'), value: 'Regular' },
                        { label: t('customers.vip'), value: 'VIP' },
                        { label: t('customers.new'), value: 'New' }
                    ]} />
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-2)', marginTop: 'var(--space-2)' }}>
                        <label style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)' }}>{t('customers.notesLabel')}</label>
                        <textarea
                            className={styles.searchInput}
                            style={{ height: '80px', padding: 'var(--space-3)' }}
                            placeholder={t('customers.notesPlaceholder')}
                        />
                    </div>
                </div>
            </SlideOver>

            {/* Edit Client SlideOver */}
            <SlideOver
                open={isEditOpen}
                onClose={() => { setIsEditOpen(false); setSelectedClient(null); }}
                title={t('customers.editClientTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('customers.cancel')}</Button>
                        <Button onClick={() => { setIsEditOpen(false); addToast('success', t('customers.toastUpdated')); }}>{t('customers.saveChanges')}</Button>
                    </div>
                }
            >
                {selectedClient && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        <Input label={t('customers.fullName')} defaultValue={selectedClient.name} />
                        <Input label={t('customers.phoneOption')} defaultValue={selectedClient.phone} />
                        <Input label={t('customers.emailOption')} defaultValue={selectedClient.email} />
                        <Select label={t('customers.groupLabel')} defaultValue={selectedClient.group} options={[
                            { label: t('customers.regular'), value: 'Regular' },
                            { label: t('customers.vip'), value: 'VIP' },
                            { label: t('customers.new'), value: 'New' }
                        ]} />
                    </div>
                )}
            </SlideOver>

            {/* Delete Confirmation Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedClient(null); }}
                title={t('customers.deleteClientTitle')}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('customers.cancel')}</Button>
                        <Button variant="destructive" onClick={() => { setIsDeleteOpen(false); addToast('error', t('customers.toastDeleted')); }}>{t('customers.deleteConfirm')}</Button>
                    </div>
                }
            >
                <div>
                    <p style={{ color: 'var(--text-secondary)' }}>
                        {t('customers.deleteWarning')}
                    </p>
                </div>
            </Modal>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
