];

const modules = ['dashboard', 'sales', 'transactions', 'returns', 'customers', 'employees', 'marketing', 'reports', 'settings'];

const employeeReviews = [
    { id: '1', customer: 'Fatima Al-Rashid', rating: 5, date: 'Feb 15, 2026', comment: 'Sara is an amazing stylist! The best hair coloring I\'ve ever had.' },
    { id: '2', customer: 'Aisha Mohammed', rating: 4, date: 'Feb 10, 2026', comment: 'Very professional. Took a bit longer than expected, but great results.' },
    { id: '3', customer: 'Huda Saleh', rating: 5, date: 'Jan 28, 2026', comment: 'Always a pleasure getting my hair done here.' },
];

export default function EmployeeProfilePage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = React.use(params);
    const { t, lang } = useTranslation();
    const router = useRouter();
    const [activeTab, setActiveTab] = useState('performance');
    const { addToast } = useToast();

    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isPermissionsOpen, setIsPermissionsOpen] = useState(false);
    const [isActivityOpen, setIsActivityOpen] = useState(false);
    const [isResetPasswordOpen, setIsResetPasswordOpen] = useState(false);
    const [isSuspendOpen, setIsSuspendOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [isEditServicesOpen, setIsEditServicesOpen] = useState(false);
    const [newServiceSelection, setNewServiceSelection] = useState('none');
    const [isScheduleEditOpen, setIsScheduleEditOpen] = useState(false);
    const [editableSchedule, setEditableSchedule] = useState(schedule.map(d => ({ ...d })));

    const [empServices, setEmpServices] = useState([
        { name: 'Hair Cut & Style', commission: '15%' },
        { name: 'Hair Coloring', commission: '20%' },
        { name: 'Keratin Treatment', commission: '25%' },
        { name: 'Blow Dry', commission: '10%' },
    ]);

    const availableServices = [
        { value: 'none', label: 'Select a service...' },
        { value: 'Beard Trim', label: 'Beard Trim' },
        { value: 'Root Touch Up', label: 'Root Touch Up' },
        { value: 'Balayage', label: 'Balayage' },
        { value: 'Scalp Massage', label: 'Scalp Massage' },
    ];

    const [editEmp, setEditEmp] = useState({
        fname: 'Sarah',
        lname: 'Ahmed',
        phone: '+20 100 123 4567',
        email: 'sarah.ahmed@waqty.app',
        role: 'employee',
        jobTitle: 'Senior Stylist',
        branch: 'Downtown'
    });

    const handleActionClick = (action: string) => {
        if (action === 'Edit Profile') setIsEditOpen(true);
        else if (action === 'Manage Permissions') setIsPermissionsOpen(true);
        else if (action === 'View Activity Log') setIsActivityOpen(true);
        else if (action === 'Reset Password') setIsResetPasswordOpen(true);
        else if (action === 'Suspend Account') setIsSuspendOpen(true);
        else if (action === 'Delete Employee') setIsDeleteOpen(true);
        else addToast('info', `${action} ${t('empProfile.actionDev')}`);
    };

    const handleReportReview = (reviewId: string) => {
        addToast('success', t('empProfile.reviewReportedMsg'));
    };

    const handleSaveEdit = () => {
        setIsEditOpen(false);
        addToast('success', t('empProfile.profileUpd'));
    };

    const renderPerformance = () => (
        <div className={styles.content}>
            <div className={styles.mainPanel}>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 'var(--space-4)' }}>
                    <KPICard
                        icon={<DollarSign size={20} />}
                        iconBg="var(--color-success-100)"
                        iconColor="var(--color-success-600)"
                        value={employee.stats.revenue}
                        label={t('empProfile.kpiRev')}
                        trend={{ value: '12%', up: true }}
                    />
                    <KPICard
                        icon={<UserCheck size={20} />}
                        iconBg="var(--color-primary-100)"
                        iconColor="var(--color-primary-600)"
                        value={employee.stats.retention}
                        label={t('empProfile.kpiRet')}
                        trend={{ value: '5%', up: true }}
                    />
                    <KPICard
                        icon={<Calendar size={20} />}
                        iconBg="var(--color-purple-100)"
                        iconColor="var(--color-purple-600)"
                        value={employee.stats.appointments}
                        label={t('empProfile.kpiAppts')}
                        trend={{ value: '2', up: false }}
                    />
                    <KPICard
                        icon={<Award size={20} />}
                        iconBg="var(--color-amber-100)"
                        iconColor="var(--color-amber-600)"
                        value={employee.stats.rating}
                        label={t('empProfile.kpiRating')}
                    />
                </div>

                <div className={styles.card} style={{ marginTop: 'var(--space-6)' }}>
                    <div className={styles.cardHeader}>
                        <span className={styles.cardTitle}><TrendingUp size={18} className={lang === 'ar' ? 'ml-2' : 'mr-2'} /> {t('empProfile.perfAnalytics')}</span>
                    </div>
                    <div className={styles.cardBody} style={{ height: '300px', paddingTop: 'var(--space-4)' }}>
                        <ResponsiveContainer width="100%" height="100%">
                            <AreaChart data={revenueData} margin={{ top: 10, right: 30, left: 0, bottom: 0 }}>
                                <defs>
                                    <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                                        <stop offset="5%" stopColor="var(--color-primary-500)" stopOpacity={0.3} />
                                        <stop offset="95%" stopColor="var(--color-primary-500)" stopOpacity={0} />
                                    </linearGradient>
                                </defs>
                                <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{ fill: 'var(--text-tertiary)', fontSize: 12 }} />
                                <YAxis orientation={lang === 'ar' ? 'right' : 'left'} axisLine={false} tickLine={false} tick={{ fill: 'var(--text-tertiary)', fontSize: 12 }} tickFormatter={(val) => `${val / 1000}k`} />
                                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="var(--border-color)" />
                                <RechartsTooltip
                                    contentStyle={{ borderRadius: '8px', border: '1px solid var(--border-color)', boxShadow: 'var(--shadow-md)' }}
                                    formatter={(value: any) => [`${value} EGP`, 'Revenue']}
                                />
                                <Area type="monotone" dataKey="revenue" stroke="var(--color-primary-500)" strokeWidth={3} fillOpacity={1} fill="url(#colorRevenue)" />
                            </AreaChart>
                        </ResponsiveContainer>
                    </div>
                </div>

                <div className={styles.card}>
                    <div className={styles.cardHeader}>
                        <span className={styles.cardTitle}><Clock size={18} className={lang === 'ar' ? 'ml-2' : 'mr-2'} /> {t('empProfile.recentActivity')}</span>
                    </div>
                    <div className={styles.cardBody}>
                        <Timeline events={recentActivity} />
                    </div>
                </div>
            </div>

            <div className={styles.sidePanel}>
                <div className={styles.card}>
                    <div className={styles.cardHeader}>
                        <span className={styles.cardTitle}>{t('empProfile.assignedServ')}</span>
                        <Button variant="ghost" size="sm" iconOnly onClick={() => setIsEditServicesOpen(true)}><Edit size={14} /></Button>
                    </div>
                    <div className={styles.cardBody}>
                        <div className={styles.serviceList}>
                            {empServices.map((s, i) => (
                                <div key={i} className={styles.serviceItem}>
                                    <span className={styles.serviceName}>{s.name}</span>
                                    <span className={styles.serviceComm}>{s.commission}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );

    const renderSchedule = () => (
        <div className={styles.mainPanel}>
            <div className={styles.card}>
                <div className={styles.cardHeader}>
                    <span className={styles.cardTitle}>{t('empProfile.weeklySchedule')}</span>
                    <Button variant="outline" size="sm" onClick={() => { setEditableSchedule(schedule.map(d => ({ ...d }))); setIsScheduleEditOpen(true); }}>{t('empProfile.editSchedule')}</Button>
                </div>
                <div className={styles.cardBody}>
                    <div className={styles.scheduleGrid}>
                        {schedule.map((day, i) => (
                            <div key={i} className={styles.scheduleDay}>
                                <div className={styles.dayName}>{day.day}</div>
                                {day.off ? (
                                    <div className={styles.dayOff}>{t('empProfile.dayOff')}</div>
                                ) : (
                                    <div className={styles.dayTime}>
                                        {day.start}<br />
                                        {t('empProfile.to')}<br />
                                        {day.end}
                                        {day.breakStart && (
                                            <div style={{ fontSize: '10px', color: 'var(--color-warning)', marginTop: '4px' }}>
                                                {t('empProfile.break')} {day.breakStart} – {day.breakEnd}
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
    );

    const renderReviews = () => (
        <div className={styles.mainPanel}>
            <div className={styles.card}>
                <div className={styles.cardHeader}>
                    <span className={styles.cardTitle}>{t('empProfile.reviews')}</span>
                </div>
                {employeeReviews.length > 0 ? (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        {employeeReviews.map(review => (
                            <div key={review.id} style={{ padding: 'var(--space-4)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-lg)', background: 'var(--bg-secondary)' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 'var(--space-2)' }}>
                                    <div>
                                        <div style={{ fontWeight: 'var(--font-semibold)' }}>{review.customer}</div>
                                        <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{review.date}</div>
                                    </div>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-3)' }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '2px', color: 'var(--color-warning)' }}>
                                            <Star size={14} fill="currentColor" />
                                            <span style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-bold)', color: 'var(--text-primary)' }}>{review.rating}.0</span>
                                        </div>
                                        <Button variant="ghost" size="sm" onClick={() => handleReportReview(review.id)} style={{ color: 'var(--color-error)' }} iconOnly>
                                            <Flag size={14} />
                                        </Button>
                                    </div>
                                </div>
                                <p style={{ fontSize: 'var(--text-sm)', color: 'var(--text-secondary)' }}>{review.comment}</p>
                            </div>
                        ))}
                    </div>
                ) : (
                    <div style={{ padding: 'var(--space-8) 0' }}>
                        <EmptyState
                            icon={<MessageSquare size={32} color="var(--text-tertiary)" />}
                            title={t('empProfile.noReviewsTitle')}
                            description={t('empProfile.noReviewsDesc')}
                        />
                    </div>
                )}
            </div>
        </div>
    );

    return (
        <div className={styles.page} style={{ direction: lang === 'ar' ? 'rtl' : 'ltr' }}>
            {/* Header */}
            <div className={styles.header}>
                <div style={{ marginBottom: 'var(--space-4)' }}>
                    <Button variant="ghost" onClick={() => router.push('/employees')} size="sm">
                        {"← Back to Employees"}
                    </Button>
                </div>
                <div className={styles.headerTop}>
                    <div className={styles.profileInfo}>
                        <div className={styles.avatar}>{employee.avatar}</div>
                        <div className={styles.details}>
                            <h1>
                                {employee.name}
                                <Badge color="primary">{employee.position}</Badge>
                            </h1>
                            <div className={styles.meta}>
                                <span className={styles.metaItem}><Briefcase size={14} className={lang === 'ar' ? 'ml-1' : 'mr-1'} /> {employee.department}</span>
                                <span className={styles.metaItem}><User size={14} className={lang === 'ar' ? 'ml-1' : 'mr-1'} /> ID: {employee.id}</span>
                                <Badge color="success">{t('empProfile.activeBadge')}</Badge>
                            </div>
                        </div>
                    </div>
                    <div className={styles.actions}>
                        <DropdownMenu
                            trigger={<Button variant="outline" iconOnly><MoreHorizontal size={20} /></Button>}
                            align={lang === 'ar' ? 'left' : 'right'}
                            items={[
                                { label: t('empProfile.managePermBtn'), icon: <Shield size={16} />, onClick: () => handleActionClick('Manage Permissions') },
                                { label: t('empProfile.viewLogBtn'), icon: <Activity size={16} />, onClick: () => handleActionClick('View Activity Log') },
                                { label: t('empProfile.resetPwdBtn'), icon: <Lock size={16} />, onClick: () => handleActionClick('Reset Password') },
                                { label: t('empProfile.suspendBtn'), icon: <Clock size={16} />, onClick: () => handleActionClick('Suspend Account') },
                                { label: t('empProfile.deleteBtn'), icon: <Trash2 size={16} />, onClick: () => handleActionClick('Delete Employee'), destructive: true },
                            ]}
                        />
                        <Button variant="outline" onClick={() => handleActionClick('Edit Profile')}><Edit size={16} className={lang === 'ar' ? 'ml-2' : 'mr-2'} /> {t('empProfile.editAction')}</Button>
                    </div>
                </div>

                <div className={styles.headerStats}>
                    <div className={styles.statItem}>
                        <span className={styles.statValue}>{employee.performance}%</span>
                        <span className={styles.statLabel}>{t('empProfile.tabPerformance')}</span>
                    </div>
                    <div className={styles.statItem}>
                        <span className={styles.statValue}>{employee.joined}</span>
                        <span className={styles.statLabel}>{t('empProfile.joinedLabel')}</span>
                    </div>
                    <div className={styles.statItem}>
                        <span className={styles.statValue}>{employee.phone}</span>
                        <span className={styles.statLabel}>{t('empProfile.phoneLabel')}</span>
                    </div>
                </div>
            </div>

            {/* Tabs */}
            <Tabs
                active={activeTab}
                onChange={setActiveTab}
                items={[
                    { key: 'performance', label: t('empProfile.tabPerformance'), icon: <TrendingUp size={16} /> },
                    { key: 'schedule', label: t('empProfile.tabSchedule'), icon: <Calendar size={16} /> },
                    { key: 'attendance', label: t('empProfile.tabAttendance'), icon: <Clock size={16} /> },
                    { key: 'reviews', label: t('empProfile.tabReviews'), icon: <MessageSquare size={16} /> },
                ]}
            />

            {/* Content */}
            {activeTab === 'performance' && renderPerformance()}
            {activeTab === 'schedule' && renderSchedule()}
            {activeTab === 'reviews' && renderReviews()}
            {activeTab === 'attendance' && (
                <EmptyState
                    icon={<Clock size={48} />}
                    title={t('empProfile.emptyAttTitle')}
                    description={t('empProfile.emptyAttDesc')}
                />
            )}

            <Modal open={isEditOpen} onClose={() => setIsEditOpen(false)} title={t('empProfile.editTitle')}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-4)' }}>
                        <Input
                            label={t('empProfile.lblFName')}
                            placeholder="Sarah"
                            value={editEmp.fname}
                            onChange={(e) => setEditEmp({ ...editEmp, fname: e.target.value })}
                        />
                        <Input
                            label={t('empProfile.lblLName')}
                            placeholder="Ahmed"
                            value={editEmp.lname}
                            onChange={(e) => setEditEmp({ ...editEmp, lname: e.target.value })}
                        />
                    </div>
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-4)' }}>
                        <Input
                            label={t('empProfile.lblPhone')}
                            placeholder="+20 100 123 4567"
                            value={editEmp.phone}
                            onChange={(e) => setEditEmp({ ...editEmp, phone: e.target.value })}
                        />
                        <Input
                            label={t('empProfile.lblEmail')}
                            type="email"
                            placeholder="sarah.ahmed@waqty.app"
                            value={editEmp.email}
                            onChange={(e) => setEditEmp({ ...editEmp, email: e.target.value })}
                        />
                    </div>

                    <div style={{ borderTop: '1px solid var(--border-color)', margin: 'var(--space-2) 0' }}></div>

                    <Select
                        label={t('empProfile.lblRole')}
                        value={editEmp.role}
                        onChange={(e) => setEditEmp({ ...editEmp, role: e.target.value })}
                        options={[
                            { value: 'admin', label: 'Admin (Full Access)' },
                            { value: 'manager', label: 'Manager (Branch Access)' },
                            { value: 'employee', label: 'Employee (Limited Access)' },
                        ]}
                    />

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-4)' }}>
                        <Select
                            label={t('empProfile.lblJobTitle')}
                            value={editEmp.jobTitle}
                            onChange={(e) => setEditEmp({ ...editEmp, jobTitle: e.target.value })}
                            options={[
                                { value: 'Senior Stylist', label: 'Senior Stylist' },
                                { value: 'Junior Stylist', label: 'Junior Stylist' },
                                { value: 'Hair Colorist', label: 'Hair Colorist' },
                            ]}
                        />
                        <Select
                            label={t('empProfile.lblBranch')}
                            value={editEmp.branch}
                            onChange={(e) => setEditEmp({ ...editEmp, branch: e.target.value })}
                            options={[
                                { value: 'Downtown', label: 'Downtown' },
                                { value: 'Mall of Arabia', label: 'Mall of Arabia' },
                                { value: 'New Cairo', label: 'New Cairo' },
                            ]}
                        />
                    </div>

                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)', marginTop: 'var(--space-4)' }}>
                        <Button variant="outline" onClick={() => setIsEditOpen(false)}>{t('empProfile.btnCancel')}</Button>
                        <Button onClick={handleSaveEdit}>{t('empProfile.btnSave')}</Button>
                    </div>
                </div>
            </Modal>

            {/* Manage Permissions Modal */}
            <Modal open={isPermissionsOpen} onClose={() => setIsPermissionsOpen(false)} title={t('empProfile.permTitle')}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <p style={{ color: 'var(--text-secondary)', fontSize: 'var(--text-sm)' }}>
                        {t('empProfile.permDesc1')}<strong>{employee.name}</strong>{t('empProfile.permDesc2')}
                    </p>
                    <div style={{ border: '1px solid var(--border-color)', borderRadius: 'var(--radius-lg)', overflow: 'hidden' }}>
                        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                            <thead style={{ background: 'var(--bg-secondary)' }}>
                                <tr>
                                    <th style={{ padding: 'var(--space-2) var(--space-3)', textAlign: lang === 'ar' ? 'right' : 'left', fontSize: 12, fontWeight: 'var(--font-semibold)', color: 'var(--text-tertiary)', borderBottom: '1px solid var(--border-color)' }}>{t('empProfile.colMod')}</th>
                                    <th style={{ padding: 'var(--space-2) var(--space-3)', textAlign: 'center', fontSize: 12, fontWeight: 'var(--font-semibold)', color: 'var(--text-tertiary)', borderBottom: '1px solid var(--border-color)' }}>{t('empProfile.colView')}</th>
                                    <th style={{ padding: 'var(--space-2) var(--space-3)', textAlign: 'center', fontSize: 12, fontWeight: 'var(--font-semibold)', color: 'var(--text-tertiary)', borderBottom: '1px solid var(--border-color)' }}>{t('empProfile.colCreate')}</th>
                                    <th style={{ padding: 'var(--space-2) var(--space-3)', textAlign: 'center', fontSize: 12, fontWeight: 'var(--font-semibold)', color: 'var(--text-tertiary)', borderBottom: '1px solid var(--border-color)' }}>{t('empProfile.colEdit')}</th>
                                    <th style={{ padding: 'var(--space-2) var(--space-3)', textAlign: 'center', fontSize: 12, fontWeight: 'var(--font-semibold)', color: 'var(--text-tertiary)', borderBottom: '1px solid var(--border-color)' }}>{t('empProfile.colDel')}</th>
                                </tr>
                            </thead>
                            <tbody>
                                {modules.map(m => (
                                    <tr key={m}>
                                        <td style={{ padding: 'var(--space-2) var(--space-3)', fontSize: 13, borderBottom: '1px solid var(--border-color)' }}>{t(`modules.${m}` as any)}</td>
                                        <td style={{ padding: 'var(--space-2) var(--space-3)', textAlign: 'center', borderBottom: '1px solid var(--border-color)' }}><input type="checkbox" defaultChecked={m === 'dashboard' || m === 'sales'} /></td>
                                        <td style={{ padding: 'var(--space-2) var(--space-3)', textAlign: 'center', borderBottom: '1px solid var(--border-color)' }}><input type="checkbox" defaultChecked={m === 'sales'} /></td>
                                        <td style={{ padding: 'var(--space-2) var(--space-3)', textAlign: 'center', borderBottom: '1px solid var(--border-color)' }}><input type="checkbox" defaultChecked={false} /></td>
                                        <td style={{ padding: 'var(--space-2) var(--space-3)', textAlign: 'center', borderBottom: '1px solid var(--border-color)' }}><input type="checkbox" defaultChecked={false} /></td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)', marginTop: 'var(--space-4)' }}>
                        <Button variant="outline" onClick={() => setIsPermissionsOpen(false)}>{t('empProfile.btnCancel')}</Button>
                        <Button onClick={() => { setIsPermissionsOpen(false); addToast('success', t('empProfile.toastPermSec')); }}>{t('empProfile.btnSavePerm')}</Button>
                    </div>
                </div>
            </Modal>

            {/* View Activity Log Modal */}
            <Modal open={isActivityOpen} onClose={() => setIsActivityOpen(false)} title={t('empProfile.actModalTitle')}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)', maxHeight: '60vh', overflowY: 'auto' }}>
                    <Timeline events={recentActivity} />
                    <div style={{ display: 'flex', justifyContent: 'flex-end', marginTop: 'var(--space-2)' }}>
                        <Button variant="outline" onClick={() => setIsActivityOpen(false)}>{t('empProfile.btnClose')}</Button>
                    </div>
                </div>
            </Modal>

            {/* Reset Password Modal */}
            <Modal open={isResetPasswordOpen} onClose={() => setIsResetPasswordOpen(false)} title={t('empProfile.resPwdTitle')}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <p style={{ color: 'var(--text-secondary)', fontSize: 'var(--text-sm)' }}>
                        {t('empProfile.resPwdDesc1')}<strong>{employee.name}</strong>{t('empProfile.resPwdDesc2')}<strong>{employee.email}</strong>.
                    </p>
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)', marginTop: 'var(--space-4)' }}>
                        <Button variant="outline" onClick={() => setIsResetPasswordOpen(false)}>{t('empProfile.btnCancel')}</Button>
                        <Button onClick={() => { setIsResetPasswordOpen(false); addToast('success', t('empProfile.toastPwdSec')); }}>{t('empProfile.btnConfirmReset')}</Button>
                    </div>
                </div>
            </Modal>

            {/* Suspend Account Modal */}
            <Modal open={isSuspendOpen} onClose={() => setIsSuspendOpen(false)} title={t('empProfile.suspTitle')}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <p style={{ color: 'var(--text-secondary)', fontSize: 'var(--text-sm)' }}>
                        {t('empProfile.suspDesc1')}<strong>{employee.name}</strong>{t('empProfile.suspDesc2')}
                    </p>
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)', marginTop: 'var(--space-4)' }}>
                        <Button variant="outline" onClick={() => setIsSuspendOpen(false)}>{t('empProfile.btnCancel')}</Button>
                        <Button variant="destructive" onClick={() => { setIsSuspendOpen(false); addToast('error', t('empProfile.toastSuspSec')); }}>{t('empProfile.suspendBtn')}</Button>
                    </div>
                </div>
            </Modal>

            {/* Delete Employee Modal */}
            <Modal open={isDeleteOpen} onClose={() => setIsDeleteOpen(false)} title={t('empProfile.delTitleModal')}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <p style={{ color: 'var(--text-secondary)', fontSize: 'var(--text-sm)' }}>
                        {t('empProfile.delDesc1')}<strong>{employee.name}</strong>{t('empProfile.delDesc2')}
                    </p>
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)', marginTop: 'var(--space-4)' }}>
                        <Button variant="outline" onClick={() => setIsDeleteOpen(false)}>{t('empProfile.btnCancel')}</Button>
                        <Button variant="destructive" onClick={() => { setIsDeleteOpen(false); addToast('error', t('empProfile.toastDelSec')); }}>{t('empProfile.btnDelPerm')}</Button>
                    </div>
                </div>
            </Modal>

            {/* Edit Assigned Services Modal */}
            <Modal open={isEditServicesOpen} onClose={() => setIsEditServicesOpen(false)} title={t('empProfile.editServTitle')}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <p style={{ color: 'var(--text-secondary)', fontSize: 'var(--text-sm)' }}>
                        {t('empProfile.servDesc')}
                    </p>

                    {/* Add New Service Row */}
                    <div style={{ display: 'flex', gap: 'var(--space-2)', alignItems: 'center', background: 'var(--bg-secondary)', padding: 'var(--space-3)', borderRadius: 'var(--radius-lg)', marginBottom: 'var(--space-4)' }}>
                        <div style={{ flex: 1 }}>
                            <Select
                                options={availableServices}
                                value={newServiceSelection}
                                onChange={(e) => setNewServiceSelection(e.target.value)}
                            />
                        </div>
                        <Button
                            disabled={newServiceSelection === 'none'}
                            onClick={() => {
                                if (newServiceSelection !== 'none') {
                                    setEmpServices([...empServices, { name: newServiceSelection, commission: '10%' }]);
                                    setNewServiceSelection('none');
                                    addToast('success', `${newServiceSelection}${t('empProfile.toastAssignedPart')}`);
                                }
                            }}
                        >
                            <Plus size={16} className={lang === 'ar' ? 'ml-2' : 'mr-2'} /> {t('empProfile.btnAdd')}
                        </Button>
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-3)', maxHeight: '50vh', overflowY: 'auto', ...(lang === 'ar' ? { paddingLeft: 'var(--space-1)', marginLeft: '-var(--space-1)' } : { paddingRight: 'var(--space-1)', marginRight: '-var(--space-1)' }) }}>
                        {empServices.map((s, idx) => (
                            <div key={idx} style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-3)', padding: 'var(--space-3)', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-md)' }}>
                                <div style={{ flex: 1, fontWeight: 'var(--font-medium)', fontSize: 'var(--text-sm)' }}>
                                    {s.name}
                                </div>
                                <div style={{ position: 'relative', width: '80px' }}>
                                    <Input
                                        defaultValue={s.commission.replace('%', '')}
                                        style={lang === 'ar' ? { textAlign: 'left', paddingLeft: '22px' } : { textAlign: 'right', paddingRight: '22px' }}
                                    />
                                    <span style={{ position: 'absolute', ...(lang === 'ar' ? { left: '10px' } : { right: '10px' }), top: '50%', transform: 'translateY(-50%)', color: 'var(--text-tertiary)', fontSize: 'var(--text-sm)', pointerEvents: 'none' }}>%</span>
                                </div>
                                <Button
                                    variant="ghost"
                                    iconOnly
                                    style={{ color: 'var(--color-error)' }}
                                    onClick={() => setEmpServices(empServices.filter((_, i) => i !== idx))}
                                >
                                    <Trash2 size={16} />
                                </Button>
                            </div>
                        ))}
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)', marginTop: 'var(--space-4)' }}>
                        <Button variant="outline" onClick={() => setIsEditServicesOpen(false)}>{t('empProfile.btnCancel')}</Button>
                        <Button onClick={() => { setIsEditServicesOpen(false); addToast('success', t('empProfile.toastServSec')); }}>{t('empProfile.btnSaveServ')}</Button>
                    </div>
                </div>
            </Modal>

            {/* Edit Schedule Modal */}
            <Modal open={isScheduleEditOpen} onClose={() => setIsScheduleEditOpen(false)} title={t('empProfile.editSchedTitle')}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <p style={{ color: 'var(--text-secondary)', fontSize: 'var(--text-sm)' }}>
                        {t('empProfile.schedDesc')}
                    </p>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-3)', maxHeight: '50vh', overflowY: 'auto' }}>
                        {editableSchedule.map((day, i) => (
                            <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-3)', padding: 'var(--space-3)', background: day.off ? 'var(--color-gray-50)' : 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)', border: '1px solid var(--border-color)' }}>
                                <div style={{ width: 90, fontWeight: 'var(--font-semibold)', fontSize: 'var(--text-sm)', color: day.off ? 'var(--text-tertiary)' : 'var(--text-primary)' }}>{day.day}</div>
                                <div style={{ flex: 1, display: 'flex', flexDirection: 'column', gap: 'var(--space-2)', opacity: day.off ? 0.4 : 1 }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-2)' }}>
                                        <span style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)', width: 40 }}>{t('empProfile.lblShift')}</span>
                                        <Input
                                            type="time"
                                            value={day.off ? '' : day.start.replace(/ AM| PM/g, '')}
                                            disabled={day.off}
                                            onChange={(e) => {
                                                const updated = [...editableSchedule];
                                                updated[i] = { ...updated[i], start: e.target.value };
                                                setEditableSchedule(updated);
                                            }}
                                            style={{ flex: 1 }}
                                        />
                                        <span style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{t('empProfile.to')}</span>
                                        <Input
                                            type="time"
                                            value={day.off ? '' : day.end.replace(/ AM| PM/g, '')}
                                            disabled={day.off}
                                            onChange={(e) => {
                                                const updated = [...editableSchedule];
                                                updated[i] = { ...updated[i], end: e.target.value };
                                                setEditableSchedule(updated);
                                            }}
                                            style={{ flex: 1 }}
                                        />
                                    </div>
                                    {!day.off && (
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-2)' }}>
                                            <span style={{ fontSize: 'var(--text-xs)', color: 'var(--color-warning)', width: 40, fontWeight: 'var(--font-medium)' }}>{t('empProfile.break').replace(':', '')}</span>
                                            <Input
                                                type="time"
                                                value={day.breakStart?.replace(/ AM| PM/g, '') || ''}
                                                placeholder="—"
                                                onChange={(e) => {
                                                    const updated = [...editableSchedule];
                                                    updated[i] = { ...updated[i], breakStart: e.target.value };
                                                    setEditableSchedule(updated);
                                                }}
                                                style={{ flex: 1 }}
                                            />
                                            <span style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{t('empProfile.to')}</span>
                                            <Input
                                                type="time"
                                                value={day.breakEnd?.replace(/ AM| PM/g, '') || ''}
                                                placeholder="—"
                                                onChange={(e) => {
                                                    const updated = [...editableSchedule];
                                                    updated[i] = { ...updated[i], breakEnd: e.target.value };
                                                    setEditableSchedule(updated);
                                                }}
                                                style={{ flex: 1 }}
                                            />
                                        </div>
                                    )}
                                </div>
                                <label style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-1)', fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)', cursor: 'pointer', whiteSpace: 'nowrap' }}>
                                    <input
                                        type="checkbox"
                                        checked={day.off}
                                        onChange={(e) => {
                                            const updated = [...editableSchedule];
                                            updated[i] = { ...updated[i], off: e.target.checked, start: e.target.checked ? '-' : '10:00 AM', end: e.target.checked ? '-' : '08:00 PM', breakStart: '', breakEnd: '' };
                                            setEditableSchedule(updated);
                                        }}
                                    />
                                    {t('empProfile.lblDayOff')}
                                </label>
                            </div>
                        ))}
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)', marginTop: 'var(--space-4)' }}>
                        <Button variant="outline" onClick={() => setIsScheduleEditOpen(false)}>{t('empProfile.btnCancel')}</Button>
                        <Button onClick={() => { setIsScheduleEditOpen(false); addToast('success', t('empProfile.toastSchedSec')); }}>{t('empProfile.btnSaveSched')}</Button>
                    </div>
                </div>
            </Modal>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { Save } from 'lucide-react';
import { Switch, Input, Select, Button, useToast } from '@/components/ui';
import { useTranslation } from '@/hooks/useTranslation';

const s: Record<string, React.CSSProperties> = {
    page: { display: 'flex', flexDirection: 'column', gap: 'var(--space-6)', paddingBottom: 'var(--space-8)' },
    title: { fontSize: 'var(--text-3xl)', fontWeight: 'var(--font-bold)', display: 'flex', alignItems: 'center', gap: 'var(--space-3)' },
    card: { background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-xl)', padding: 'var(--space-6)' },
    section: { marginBottom: 'var(--space-8)' },
    sectionTitle: { fontSize: 'var(--text-lg)', fontWeight: 'var(--font-semibold)', marginBottom: 'var(--space-4)', paddingBottom: 'var(--space-3)', borderBottom: '1px solid var(--border-color)', color: 'var(--text-primary)' },
    row: { display: 'flex', alignItems: 'flex-start', padding: 'var(--space-4) 0', borderBottom: '1px dashed var(--border-color)' },
    rowContent: { flex: '0 0 320px', paddingRight: 'var(--space-6)' },
    rowAction: { display: 'flex', flex: 1, alignItems: 'center', gap: 'var(--space-3)', justifyContent: 'flex-start' },
    label: { fontSize: 'var(--text-base)', fontWeight: 'var(--font-medium)', color: 'var(--text-primary)', marginBottom: 4 },
    hint: { fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)', lineHeight: 1.4 },
    inputGroup: { display: 'flex', alignItems: 'center', gap: 'var(--space-2)' },
    deductionBox: { background: 'var(--bg-secondary)', padding: 'var(--space-4)', borderRadius: 'var(--radius-lg)', marginTop: 'var(--space-3)', display: 'flex', flexDirection: 'column', gap: 'var(--space-4)', border: '1px solid var(--border-color)' }
};

export default function AttendanceSettingsPage() {
    const { t, lang } = useTranslation();
    const { addToast } = useToast();
    const [isSaving, setIsSaving] = useState(false);

    // Form State
    const [config, setConfig] = useState({
        standardHours: '9',
        shiftStart: '09:00',
        shiftEnd: '18:00',
        lateGrace: '5',
        earlyGrace: '10',
        overtimeThreshold: '15',
        maxOvertime: '3',
        autoDeduct: true,
        deductionType: 'percentage', // 'percentage' | 'fixed'
        deductionValue: '5',
        notifyManager: false
    });

    const handleChange = (key: keyof typeof config, value: any) => {
        setConfig(prev => ({ ...prev, [key]: value }));
    };

    const handleSave = () => {
        setIsSaving(true);
        // Simulate API call
        setTimeout(() => {
            setIsSaving(false);
            addToast('success', t('attendanceSettings.toastSaved'));
        }, 600);
    };

    return (
        <div style={s.page}>
            <div style={s.title}>{t('attendanceSettings.title')}</div>

            <div style={s.card}>
                <div style={s.section}>
                    <div style={s.sectionTitle}>{t('attendanceSettings.secWorkHours')}</div>
                    <div style={{ ...s.row, flexDirection: lang === 'ar' ? 'row-reverse' : 'row' }}>
                        <div style={{ ...s.rowContent as React.CSSProperties, paddingRight: lang === 'ar' ? 0 : 'var(--space-6)', paddingLeft: lang === 'ar' ? 'var(--space-6)' : 0, textAlign: lang === 'ar' ? 'right' : 'left' }}>
                            <div style={s.label}>{t('attendanceSettings.stdHours')}</div>
                            <div style={s.hint}>{t('attendanceSettings.stdHoursHint')}</div>
                        </div>
                        <div style={{ ...s.rowAction as React.CSSProperties, justifyContent: lang === 'ar' ? 'flex-end' : 'flex-start' }}>
                            <div style={{ ...s.inputGroup as React.CSSProperties, flexDirection: lang === 'ar' ? 'row-reverse' : 'row' }}>
                                <Input type="number" value={config.standardHours} onChange={(e) => handleChange('standardHours', e.target.value)} style={{ width: 80, textAlign: 'center', margin: 0 }} />
                                <span style={{ color: 'var(--text-tertiary)', fontSize: 'var(--text-sm)' }}>{t('attendanceSettings.hrs')}</span>
                            </div>
                        </div>
                    </div>

                    <div style={{ ...s.row, flexDirection: lang === 'ar' ? 'row-reverse' : 'row' }}>
                        <div style={{ ...s.rowContent as React.CSSProperties, paddingRight: lang === 'ar' ? 0 : 'var(--space-6)', paddingLeft: lang === 'ar' ? 'var(--space-6)' : 0, textAlign: lang === 'ar' ? 'right' : 'left' }}>
                            <div style={s.label}>{t('attendanceSettings.shiftDetails')}</div>
                            <div style={s.hint}>{t('attendanceSettings.shiftDetailsHint')}</div>
                        </div>
                        <div style={{ ...s.rowAction as React.CSSProperties, flexDirection: lang === 'ar' ? 'row-reverse' : 'row', justifyContent: lang === 'ar' ? 'flex-end' : 'flex-start' }}>
                            <Input type="time" value={config.shiftStart} onChange={(e) => handleChange('shiftStart', e.target.value)} style={{ width: 110, margin: 0 }} />
                            <span style={{ color: 'var(--text-tertiary)' }}>{t('attendanceSettings.to')}</span>
                            <Input type="time" value={config.shiftEnd} onChange={(e) => handleChange('shiftEnd', e.target.value)} style={{ width: 110, margin: 0 }} />
                        </div>
                    </div>
                </div>

                <div style={s.section}>
                    <div style={s.sectionTitle}>{t('attendanceSettings.secGrace')}</div>
                    <div style={{ ...s.row, flexDirection: lang === 'ar' ? 'row-reverse' : 'row' }}>
                        <div style={{ ...s.rowContent as React.CSSProperties, paddingRight: lang === 'ar' ? 0 : 'var(--space-6)', paddingLeft: lang === 'ar' ? 'var(--space-6)' : 0, textAlign: lang === 'ar' ? 'right' : 'left' }}>
                            <div style={s.label}>{t('attendanceSettings.lateGrace')}</div>
                            <div style={s.hint}>{t('attendanceSettings.lateGraceHint')}</div>
                        </div>
                        <div style={{ ...s.rowAction as React.CSSProperties, justifyContent: lang === 'ar' ? 'flex-end' : 'flex-start' }}>
                            <div style={{ ...s.inputGroup as React.CSSProperties, flexDirection: lang === 'ar' ? 'row-reverse' : 'row' }}>
                                <Input type="number" value={config.lateGrace} onChange={(e) => handleChange('lateGrace', e.target.value)} style={{ width: 80, textAlign: 'center', margin: 0 }} />
                                <span style={{ color: 'var(--text-tertiary)', fontSize: 'var(--text-sm)' }}>{t('attendanceSettings.min')}</span>
                            </div>
                        </div>
                    </div>

                    <div style={{ ...s.row, flexDirection: lang === 'ar' ? 'row-reverse' : 'row' }}>
                        <div style={{ ...s.rowContent as React.CSSProperties, paddingRight: lang === 'ar' ? 0 : 'var(--space-6)', paddingLeft: lang === 'ar' ? 'var(--space-6)' : 0, textAlign: lang === 'ar' ? 'right' : 'left' }}>
                            <div style={s.label}>{t('attendanceSettings.earlyGrace')}</div>
                            <div style={s.hint}>{t('attendanceSettings.earlyGraceHint')}</div>
                        </div>
                        <div style={{ ...s.rowAction as React.CSSProperties, justifyContent: lang === 'ar' ? 'flex-end' : 'flex-start' }}>
                            <div style={{ ...s.inputGroup as React.CSSProperties, flexDirection: lang === 'ar' ? 'row-reverse' : 'row' }}>
                                <Input type="number" value={config.earlyGrace} onChange={(e) => handleChange('earlyGrace', e.target.value)} style={{ width: 80, textAlign: 'center', margin: 0 }} />
                                <span style={{ color: 'var(--text-tertiary)', fontSize: 'var(--text-sm)' }}>{t('attendanceSettings.min')}</span>
                            </div>
                        </div>
                    </div>
                </div>

                <div style={s.section}>
                    <div style={{ ...s.sectionTitle as React.CSSProperties, textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('attendanceSettings.secPenalties')}</div>

                    <div style={{ ...s.row, borderBottom: config.autoDeduct ? 'none' : '1px dashed var(--border-color)', paddingBottom: config.autoDeduct ? 0 : 'var(--space-4)', flexDirection: lang === 'ar' ? 'row-reverse' : 'row' }}>
                        <div style={{ ...s.rowContent as React.CSSProperties, paddingRight: lang === 'ar' ? 0 : 'var(--space-6)', paddingLeft: lang === 'ar' ? 'var(--space-6)' : 0, textAlign: lang === 'ar' ? 'right' : 'left' }}>
                            <div style={s.label}>{t('attendanceSettings.autoDeduct')}</div>
                            <div style={s.hint}>{t('attendanceSettings.autoDeductHint')}</div>
                        </div>
                        <div style={{ ...s.rowAction as React.CSSProperties, justifyContent: lang === 'ar' ? 'flex-end' : 'flex-start' }}>
                            <Switch checked={config.autoDeduct} onChange={(val) => handleChange('autoDeduct', val)} />
                        </div>
                    </div>

                    {config.autoDeduct && (
                        <div style={{ ...s.deductionBox as React.CSSProperties, textAlign: lang === 'ar' ? 'right' : 'left' }}>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-4)', direction: lang === 'ar' ? 'rtl' : 'ltr' }}>
                                <Select
                                    label={t('attendanceSettings.deductType')}
                                    value={config.deductionType}
                                    onChange={(e) => handleChange('deductionType', e.target.value)}
                                    options={[
                                        { label: t('attendanceSettings.typePercentage'), value: 'percentage' },
                                        { label: t('attendanceSettings.typeFixed'), value: 'fixed' }
                                    ]}
                                />
                                <Input
                                    label={t('attendanceSettings.deductValue')}
                                    type="number"
                                    value={config.deductionValue}
                                    onChange={(e) => handleChange('deductionValue', e.target.value)}
                                    hint={config.deductionType === 'percentage' ? t('attendanceSettings.valueHintPct') : t('attendanceSettings.valueHintFixed')}
                                />
                            </div>
                        </div>
                    )}

                    <div style={{ ...s.row, borderBottom: 'none', paddingTop: config.autoDeduct ? 'var(--space-6)' : 'var(--space-4)', flexDirection: lang === 'ar' ? 'row-reverse' : 'row' }}>
                        <div style={{ ...s.rowContent as React.CSSProperties, paddingRight: lang === 'ar' ? 0 : 'var(--space-6)', paddingLeft: lang === 'ar' ? 'var(--space-6)' : 0, textAlign: lang === 'ar' ? 'right' : 'left' }}>
                            <div style={s.label}>{t('attendanceSettings.notifyAbsence')}</div>
                            <div style={s.hint}>{t('attendanceSettings.notifyAbsenceHint')}</div>
                        </div>
                        <div style={{ ...s.rowAction as React.CSSProperties, justifyContent: lang === 'ar' ? 'flex-end' : 'flex-start' }}>
                            <Switch checked={config.notifyManager} onChange={(val) => handleChange('notifyManager', val)} />
                        </div>
                    </div>
                </div>

                <div style={{ display: 'flex', justifyContent: lang === 'ar' ? 'flex-start' : 'flex-end', borderTop: '1px solid var(--border-color)', paddingTop: 'var(--space-6)', marginTop: 'var(--space-6)' }}>
                    <Button onClick={handleSave} disabled={isSaving}>
                        <Save size={16} className={lang === 'ar' ? 'ml-2' : 'mr-2'} />
                        {isSaving ? t('attendanceSettings.saving') : t('attendanceSettings.saveSettings')}
                    </Button>
                </div>
            </div>
        </div>
    );
}

﻿'use client';

import React, { useState } from 'react';
import { Search, Download, Clock, Plus, Edit, Trash2 } from 'lucide-react';
import { SlideOver, Modal, Input, Select, Button, useToast, EmptyState } from '@/components/ui';
import { useTranslation } from '@/hooks/useTranslation';

const initialData = [
    { id: 'AT-001', employee: 'Sara Ahmed', date: '2026-02-17', checkIn: '08:55', checkOut: '18:05', hours: '9h 10m', late: false, overtime: '10m', status: 'present' },
    { id: 'AT-002', employee: 'Nora Ali', date: '2026-02-17', checkIn: '09:10', checkOut: '18:00', hours: '8h 50m', late: true, overtime: '0m', status: 'late' },
    { id: 'AT-003', employee: 'Layla Hassan', date: '2026-02-17', checkIn: '08:50', checkOut: '18:30', hours: '9h 40m', late: false, overtime: '40m', status: 'present' },
    { id: 'AT-004', employee: 'Hana Youssef', date: '2026-02-17', checkIn: '09:00', checkOut: '18:00', hours: '9h 0m', late: false, overtime: '0m', status: 'present' },
    { id: 'AT-005', employee: 'Reem Mohamed', date: '2026-02-17', checkIn: '-', checkOut: '-', hours: '-', late: false, overtime: '-', status: 'absent' },
    { id: 'AT-006', employee: 'Dina Nabil', date: '2026-02-17', checkIn: '08:45', checkOut: '17:00', hours: '8h 15m', late: false, overtime: '0m', status: 'early_leave' },
    { id: 'AT-007', employee: 'Sara Ahmed', date: '2026-02-16', checkIn: '09:00', checkOut: '18:00', hours: '9h 0m', late: false, overtime: '0m', status: 'present' },
    { id: 'AT-008', employee: 'Nora Ali', date: '2026-02-16', checkIn: '08:58', checkOut: '18:15', hours: '9h 17m', late: false, overtime: '17m', status: 'present' },
];

const statusMap: Record<string, { label: string; bg: string; color: string }> = {
    present: { label: ' Present', bg: 'var(--color-success-light)', color: 'var(--color-success)' },
    late: { label: ' Late', bg: 'var(--color-warning-light)', color: 'var(--color-warning)' },
    absent: { label: ' Absent', bg: 'var(--color-error-light)', color: 'var(--color-error)' },
    early_leave: { label: ' Early Leave', bg: 'var(--color-info-light)', color: 'var(--color-info)' },
};

const s: Record<string, React.CSSProperties> = {
    page: { display: 'flex', flexDirection: 'column', gap: 'var(--space-5)' },
    kpis: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: 'var(--space-4)' },
    kpi: { background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-xl)', padding: 'var(--space-4)', display: 'flex', flexDirection: 'column', justifyContent: 'center' },
    kpiVal: { fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)', color: 'var(--text-primary)' },
    kpiLbl: { fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)', marginTop: 2 },
    toolbar: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 'var(--space-3)', flexWrap: 'wrap' },
    filterGroup: { display: 'flex', alignItems: 'center', gap: 'var(--space-3)', flex: 1 },
    searchBox: { position: 'relative', width: '100%', maxWidth: 320 },
    searchIcon: { position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-tertiary)' },
    searchInput: { width: '100%', height: 40, paddingLeft: 40, border: '1px solid var(--border-color)', borderRadius: 'var(--radius-lg)', background: 'var(--bg-primary)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)' },
    table: { width: '100%', background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-xl)', overflow: 'hidden' },
    th: { padding: 'var(--space-3) var(--space-4)', textAlign: 'left', fontSize: 'var(--text-xs)', fontWeight: 'var(--font-semibold)', color: 'var(--text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', background: 'var(--bg-secondary)', borderBottom: '1px solid var(--border-color)' },
    td: { padding: 'var(--space-3) var(--space-4)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)', borderBottom: '1px solid var(--border-color)' },
    badge: { display: 'inline-flex', padding: '2px 8px', borderRadius: 'var(--radius-full)', fontSize: 11, fontWeight: 'var(--font-semibold)' },
    actions: { display: 'flex', gap: 'var(--space-2)' },
    btnIcon: { display: 'flex', alignItems: 'center', justifyContent: 'center', width: 30, height: 30, borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)', background: 'var(--bg-primary)', cursor: 'pointer', color: 'var(--text-secondary)' },
};

export default function AttendancePage() {
    const { t, lang } = useTranslation();
    const [records, setRecords] = useState(initialData);
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState('All');
    const [dateFilter, setDateFilter] = useState(''); // Default to empty so all show
    const { addToast } = useToast();

    const getTranslatedStatus = (status: string) => {
        if (status === 'present') return t('attendance.kpiPresent');
        if (status === 'late') return t('attendance.kpiLate');
        if (status === 'absent') return t('attendance.kpiAbsent');
        if (status === 'early_leave') return t('attendance.kpiEarlyLeave');
        return status;
    };

    // Modals
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [selectedRecord, setSelectedRecord] = useState<any>(null);

    const getTodayStr = () => {
        const d = new Date();
        d.setMinutes(d.getMinutes() - d.getTimezoneOffset());
        return d.toISOString().split('T')[0];
    };

    // Form
    const [formData, setFormData] = useState({
        employee: '', date: getTodayStr(), checkIn: '09:00', checkOut: '18:00', status: 'present'
    });

    const filtered = records.filter(r => {
        const matchesSearch = r.employee.toLowerCase().includes(search.toLowerCase());
        const matchesStatus = statusFilter === 'All' || r.status === statusFilter;
        const matchesDate = !dateFilter || r.date === dateFilter;
        return matchesSearch && matchesStatus && matchesDate;
    });

    // KPIs based on current date filter (or all if no date selected)
    const kpiData = records.filter(r => !dateFilter || r.date === dateFilter);

    // Helper to calculate hours and overtime
    const calculateTime = (inTime: string, outTime: string) => {
        if (!inTime || !outTime || inTime === '-' || outTime === '-') return { hours: '-', overtime: '-' };

        const [inH, inM] = inTime.split(':').map(Number);
        const [outH, outM] = outTime.split(':').map(Number);

        let diffMins = (outH * 60 + outM) - (inH * 60 + inM);
        if (diffMins < 0) diffMins += 24 * 60; // Handle cross-midnight (unlikely but safe)

        const h = Math.floor(diffMins / 60);
        const m = diffMins % 60;

        // Assume 9 hours is standard shift
        const standardMins = 9 * 60;
        let ot = '0m';
        if (diffMins > standardMins) {
            const otDiff = diffMins - standardMins;
            const oth = Math.floor(otDiff / 60);
            const otm = otDiff % 60;
            ot = oth > 0 ? `${oth}h ${otm}m` : `${otm}m`;
        }

        return { hours: `${h}h ${m}m`, overtime: ot };
    };

    const handleSaveAdd = () => {
        if (!formData.employee) return addToast('error', t('attendance.toastAddReqEmp'));
        if (!formData.date) return addToast('error', t('attendance.toastAddReqDate'));

        let calculated = { hours: '-', overtime: '-' };
        if (formData.status !== 'absent') {
            calculated = calculateTime(formData.checkIn, formData.checkOut);
        }

        const newRecord = {
            id: `AT-${Date.now().toString().slice(-4)}`,
            employee: formData.employee,
            date: formData.date,
            checkIn: formData.status === 'absent' ? '-' : formData.checkIn,
            checkOut: formData.status === 'absent' ? '-' : formData.checkOut,
            hours: calculated.hours,
            late: formData.status === 'late',
            overtime: calculated.overtime,
            status: formData.status
        };

        setRecords([newRecord, ...records]);
        setIsAddOpen(false);
        setFormData({ employee: '', date: getTodayStr(), checkIn: '09:00', checkOut: '18:00', status: 'present' });
        addToast('success', t('attendance.toastAddSuccess'));
    };

    const handleSaveEdit = () => {
        if (!formData.employee) return addToast('error', t('attendance.toastAddReqEmp'));

        let calculated = { hours: '-', overtime: '-' };
        if (formData.status !== 'absent') {
            calculated = calculateTime(formData.checkIn, formData.checkOut);
        }

        setRecords(records.map(r => r.id === selectedRecord.id ? {
            ...r,
            employee: formData.employee,
            date: formData.date,
            checkIn: formData.status === 'absent' ? '-' : formData.checkIn,
            checkOut: formData.status === 'absent' ? '-' : formData.checkOut,
            hours: calculated.hours,
            late: formData.status === 'late',
            overtime: calculated.overtime,
            status: formData.status
        } : r));

        setIsEditOpen(false);
        setSelectedRecord(null);
        addToast('success', t('attendance.toastUpdateSuccess'));
    };

    const handleDelete = () => {
        setRecords(records.filter(r => r.id !== selectedRecord.id));
        setIsDeleteOpen(false);
        setSelectedRecord(null);
        addToast('success', t('attendance.toastDeleteSuccess'));
    };

    const openEdit = (r: any) => {
        setSelectedRecord(r);
        setFormData({
            employee: r.employee,
            date: r.date,
            checkIn: r.checkIn === '-' ? '09:00' : r.checkIn,
            checkOut: r.checkOut === '-' ? '18:00' : r.checkOut,
            status: r.status
        });
        setIsEditOpen(true);
    };

    return (
        <div style={{ ...s.page, direction: lang === 'ar' ? 'rtl' : 'ltr' }}>
            <div style={{ fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)' }}>{t('attendance.title')}</div>

            <div style={s.kpis}>
                <div style={s.kpi}><div style={{ ...s.kpiVal, color: 'var(--color-success)' }}>{kpiData.filter(d => d.status === 'present').length}</div><div style={s.kpiLbl}>{t('attendance.kpiPresent')}</div></div>
                <div style={s.kpi}><div style={{ ...s.kpiVal, color: 'var(--color-warning)' }}>{kpiData.filter(d => d.status === 'late').length}</div><div style={s.kpiLbl}>{t('attendance.kpiLate')}</div></div>
                <div style={s.kpi}><div style={{ ...s.kpiVal, color: 'var(--color-error)' }}>{kpiData.filter(d => d.status === 'absent').length}</div><div style={s.kpiLbl}>{t('attendance.kpiAbsent')}</div></div>
                <div style={s.kpi}><div style={{ ...s.kpiVal, color: 'var(--color-info)' }}>{kpiData.filter(d => d.status === 'early_leave').length}</div><div style={s.kpiLbl}>{t('attendance.kpiEarlyLeave')}</div></div>
            </div>

            <div style={s.toolbar}>
                <div style={s.filterGroup as React.CSSProperties}>
                    <div style={s.searchBox as React.CSSProperties}>
                        <Search size={16} style={{ ...s.searchIcon as React.CSSProperties, left: lang === 'ar' ? 'auto' : 12, right: lang === 'ar' ? 12 : 'auto' }} />
                        <input style={{ ...s.searchInput, paddingLeft: lang === 'ar' ? 16 : 40, paddingRight: lang === 'ar' ? 40 : 16 }} placeholder={t('attendance.searchEmp')} value={search} onChange={e => setSearch(e.target.value)} />
                    </div>
                    <Input type="date" value={dateFilter} onChange={e => setDateFilter(e.target.value)} style={{ height: 40, margin: 0 }} />
                    <Select
                        value={statusFilter}
                        onChange={e => setStatusFilter(e.target.value)}
                        options={[
                            { label: t('attendance.filterAll'), value: 'All' },
                            { label: t('attendance.kpiPresent'), value: 'present' },
                            { label: t('attendance.kpiLate'), value: 'late' },
                            { label: t('attendance.kpiAbsent'), value: 'absent' },
                            { label: t('attendance.kpiEarlyLeave'), value: 'early_leave' },
                        ]}
                        style={{ width: 140 }}
                    />
                </div>
                <div style={{ display: 'flex', gap: 'var(--space-3)' }}>
                    <Button variant="outline" onClick={() => addToast('info', t('attendance.toastExporting'))}>
                        <Download size={16} className={lang === 'ar' ? 'ml-2' : 'mr-2'} /> {t('attendance.export')}
                    </Button>
                    <Button onClick={() => setIsAddOpen(true)}>
                        <Plus size={16} className={lang === 'ar' ? 'ml-2' : 'mr-2'} /> {t('attendance.addRecord')}
                    </Button>
                </div>
            </div>

            {filtered.length > 0 ? (
                <table style={s.table}>
                    <thead>
                        <tr>
                            {[t('attendance.colEmp'), t('attendance.colDate'), t('attendance.colCheckIn'), t('attendance.colCheckOut'), t('attendance.colHours'), t('attendance.colOvertime'), t('attendance.colStatus'), t('attendance.colActions')].map(h =>
                                <th key={h} style={{ ...s.th as React.CSSProperties, textAlign: lang === 'ar' ? 'right' : 'left' }}>{h}</th>
                            )}
                        </tr>
                    </thead>
                    <tbody>
                        {filtered.map((row) => {
                            const st = statusMap[row.status];
                            return (
                                <tr key={row.id} className="hoverRow">
                                    <td style={{ ...s.td, fontWeight: 'var(--font-medium)', textAlign: lang === 'ar' ? 'right' : 'left' } as React.CSSProperties}>{row.employee}</td>
                                    <td style={{ ...s.td, textAlign: lang === 'ar' ? 'right' : 'left' }}>{row.date}</td>
                                    <td style={{ ...s.td, textAlign: lang === 'ar' ? 'right' : 'left' }}>{row.checkIn}</td>
                                    <td style={{ ...s.td, textAlign: lang === 'ar' ? 'right' : 'left' }}>{row.checkOut}</td>
                                    <td style={{ ...s.td, textAlign: lang === 'ar' ? 'right' : 'left' }}>{row.hours}</td>
                                    <td style={{ ...s.td, color: row.overtime !== '0m' && row.overtime !== '-' ? 'var(--color-primary-600)' : 'var(--text-tertiary)', textAlign: lang === 'ar' ? 'right' : 'left' } as React.CSSProperties}>{row.overtime}</td>
                                    <td style={{ ...s.td, textAlign: lang === 'ar' ? 'right' : 'left' }}><span style={{ ...s.badge, background: st.bg, color: st.color }}>{getTranslatedStatus(row.status)}</span></td>
                                    <td style={{ ...s.td, textAlign: lang === 'ar' ? 'right' : 'left' }}>
                                        <div style={s.actions}>
                                            <button style={s.btnIcon} onClick={() => openEdit(row)} title="Edit Record">
                                                <Edit size={14} />
                                            </button>
                                            <button style={{ ...s.btnIcon, color: 'var(--color-error)' }} onClick={() => { setSelectedRecord(row); setIsDeleteOpen(true); }} title="Delete Record">
                                                <Trash2 size={14} />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            ) : (
                <EmptyState icon={<Clock size={32} color="var(--text-tertiary)" />} title={t('attendance.emptyTitle')} description={t('attendance.emptyDesc')} />
            )}

            <style>{`
                .hoverRow:hover { background-color: var(--bg-secondary); }
                .hoverRow:last-child td { border-bottom: none !important; }
            `}</style>

            {/* Add SlideOver */}
            <SlideOver
                open={isAddOpen}
                onClose={() => setIsAddOpen(false)}
                title={t('attendance.addModalTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('attendance.cancel')}</Button>
                        <Button onClick={handleSaveAdd}>{t('attendance.saveRecord')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('attendance.empNameLabel')} placeholder={t('attendance.empNamePlaceholder')} value={formData.employee} onChange={e => setFormData({ ...formData, employee: e.target.value })} />
                    <Input type="date" label={t('attendance.dateLabel')} value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                    <Select label={t('attendance.statusLabel')} value={formData.status} onChange={e => setFormData({ ...formData, status: e.target.value })} options={[
                        { label: t('attendance.kpiPresent'), value: 'present' },
                        { label: t('attendance.kpiLate'), value: 'late' },
                        { label: t('attendance.kpiAbsent'), value: 'absent' },
                        { label: t('attendance.kpiEarlyLeave'), value: 'early_leave' },
                    ]} />

                    {formData.status !== 'absent' && (
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-3)' }}>
                            <Input type="time" label={t('attendance.checkInLabel')} value={formData.checkIn} onChange={e => setFormData({ ...formData, checkIn: e.target.value })} />
                            <Input type="time" label={t('attendance.checkOutLabel')} value={formData.checkOut} onChange={e => setFormData({ ...formData, checkOut: e.target.value })} />
                        </div>
                    )}
                </div>
            </SlideOver>

            {/* Edit SlideOver */}
            <SlideOver
                open={isEditOpen}
                onClose={() => { setIsEditOpen(false); setSelectedRecord(null); }}
                title={t('attendance.editModalTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('attendance.cancel')}</Button>
                        <Button onClick={handleSaveEdit}>{t('attendance.saveChanges')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('attendance.empNameLabel')} value={formData.employee} onChange={e => setFormData({ ...formData, employee: e.target.value })} />
                    <Input type="date" label={t('attendance.dateLabel')} value={formData.date} onChange={e => setFormData({ ...formData, date: e.target.value })} />
                    <Select label={t('attendance.statusLabel')} value={formData.status} onChange={e => setFormData({ ...formData, status: e.target.value })} options={[
                        { label: t('attendance.kpiPresent'), value: 'present' },
                        { label: t('attendance.kpiLate'), value: 'late' },
                        { label: t('attendance.kpiAbsent'), value: 'absent' },
                        { label: t('attendance.kpiEarlyLeave'), value: 'early_leave' },
                    ]} />

                    {formData.status !== 'absent' && (
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-3)' }}>
                            <Input type="time" label={t('attendance.checkInLabel')} value={formData.checkIn} onChange={e => setFormData({ ...formData, checkIn: e.target.value })} />
                            <Input type="time" label={t('attendance.checkOutLabel')} value={formData.checkOut} onChange={e => setFormData({ ...formData, checkOut: e.target.value })} />
                        </div>
                    )}
                </div>
            </SlideOver>

            {/* Delete Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedRecord(null); }}
                title={t('attendance.deleteModalTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('attendance.cancel')}</Button>
                        <Button variant="destructive" onClick={handleDelete}>{t('attendance.deleteConfirmBtn')}</Button>
                    </div>
                }
            >
                <p style={{ color: 'var(--text-secondary)' }}>
                    {t('attendance.deleteConfirmMsg1')}<strong>{selectedRecord?.employee}</strong>{t('attendance.deleteConfirmMsg2')}{selectedRecord?.date}{t('attendance.deleteConfirmMsg3')}
                </p>
            </Modal>
        </div>
    );
}

'use client';

