};

// ─── Component ──────────────────────────────────────────────────────
export default function CommissionSettingsPage() {
    const { addToast } = useToast();
    const { t, lang } = useTranslation();
    const isRtl = lang === 'ar';

    const [activeTab, setActiveTab] = useState('service');

    const tabs = [
        { key: 'service', label: t('commSettings.tabService'), icon: <Settings2 size={15} /> },
        { key: 'target', label: t('commSettings.tabTarget'), icon: <Target size={15} /> },
        { key: 'segment', label: t('commSettings.tabSegment'), icon: <PieChart size={15} /> },
        { key: 'extraction', label: t('commSettings.tabExtraction'), icon: <FlaskConical size={15} /> },
    ];

    // State for each tab
    const [serviceRates, setServiceRates] = useState(initialServiceRates);
    const [targetRules, setTargetRules] = useState(initialTargetRules);
    const [segmentRates, setSegmentRates] = useState(initialSegmentRates);
    const [extractionRules, setExtractionRules] = useState(initialExtractionRules);

    // Modal state
    const [modalOpen, setModalOpen] = useState(false);
    const [modalMode, setModalMode] = useState<'add' | 'edit'>('add');
    const [editId, setEditId] = useState<number | null>(null);

    // Form fields (shared across modals, tab-specific)
    const [form, setForm] = useState<Record<string, string>>({});

    const openAdd = () => {
        setModalMode('add');
        setEditId(null);
        setForm({});
        setModalOpen(true);
    };

    const openEdit = (id: number, data: Record<string, any>) => {
        setModalMode('edit');
        setEditId(id);
        const strData: Record<string, string> = {};
        Object.entries(data).forEach(([k, v]) => { strData[k] = String(v); });
        setForm(strData);
        setModalOpen(true);
    };

    const handleDelete = (id: number) => {
        if (activeTab === 'service') setServiceRates(prev => prev.filter(r => r.id !== id));
        if (activeTab === 'target') setTargetRules(prev => prev.filter(r => r.id !== id));
        if (activeTab === 'segment') setSegmentRates(prev => prev.filter(r => r.id !== id));
        if (activeTab === 'extraction') setExtractionRules(prev => prev.filter(r => r.id !== id));
        addToast('success', t('commSettings.toastDel'));
    };

    const handleSaveModal = () => {
        const newId = Date.now();

        if (activeTab === 'service') {
            const entry = { id: editId ?? newId, service: form.service || '', category: form.category || '', rate: parseFloat(form.rate) || 0 };
            if (modalMode === 'add') setServiceRates(prev => [...prev, entry]);
            else setServiceRates(prev => prev.map(r => r.id === editId ? entry : r));
        }
        if (activeTab === 'target') {
            const entry = { id: editId ?? newId, employee: form.employee || '', targetRev: parseFloat(form.targetRev) || 0, baseBonus: parseFloat(form.baseBonus) || 0, mult120: parseFloat(form.mult120) || 1.5, mult150: parseFloat(form.mult150) || 2.0 };
            if (modalMode === 'add') setTargetRules(prev => [...prev, entry]);
            else setTargetRules(prev => prev.map(r => r.id === editId ? entry : r));
        }
        if (activeTab === 'segment') {
            const entry = { id: editId ?? newId, segment: form.segment || '', rate: parseFloat(form.rate) || 0, description: form.description || '' };
            if (modalMode === 'add') setSegmentRates(prev => [...prev, entry]);
            else setSegmentRates(prev => prev.map(r => r.id === editId ? entry : r));
        }
        if (activeTab === 'extraction') {
            const entry = { id: editId ?? newId, service: form.service || '', extractionRate: parseFloat(form.extractionRate) || 0, applyTo: form.applyTo || 'All Employees' };
            if (modalMode === 'add') setExtractionRules(prev => [...prev, entry]);
            else setExtractionRules(prev => prev.map(r => r.id === editId ? entry : r));
        }

        setModalOpen(false);
        addToast('success', modalMode === 'add' ? t('commSettings.toastAdded') : t('commSettings.toastUpdated'));
    };

    const handleSaveAll = () => {
        addToast('success', t('commSettings.toastSavedAll'));
    };

    const updateForm = (key: string, value: string) => setForm(prev => ({ ...prev, [key]: value }));

    // ─── Tab Labels ─────────────────
    const tabLabels: Record<string, string> = {
        service: t('commSettings.lblService'),
        target: t('commSettings.lblTarget'),
        segment: t('commSettings.lblSegment'),
        extraction: t('commSettings.lblExtraction'),
    };

    // ─── Modal Fields per Tab ───────
    const renderModalFields = () => {
        if (activeTab === 'service') return (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                <Input label={t('commSettings.fldServiceName')} value={form.service || ''} onChange={e => updateForm('service', e.target.value)} placeholder={t('commSettings.phService')} />
                <Select label={t('commSettings.fldCategory')} value={form.category || ''} onChange={e => updateForm('category', e.target.value)} options={[
                    { label: t('commSettings.selCategory'), value: '' },
                    { label: 'Hair Care', value: 'Hair Care' },
                    { label: 'Skincare', value: 'Skincare' },
                    { label: 'Spa', value: 'Spa' },
                    { label: 'Nail Care', value: 'Nail Care' },
                ]} />
                <Input label={t('commSettings.fldRate')} type="number" value={form.rate || ''} onChange={e => updateForm('rate', e.target.value)} placeholder={t('commSettings.phRate')} />
            </div>
        );
        if (activeTab === 'target') return (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                <Select label={t('commSettings.fldEmployee')} value={form.employee || ''} onChange={e => updateForm('employee', e.target.value)} options={[
                    { label: t('commSettings.selEmployee'), value: '' },
                    { label: 'Sara Ahmed', value: 'Sara Ahmed' },
                    { label: 'Nora Ali', value: 'Nora Ali' },
                    { label: 'Layla Hassan', value: 'Layla Hassan' },
                    { label: 'Hana Youssef', value: 'Hana Youssef' },
                    { label: 'Reem Mohamed', value: 'Reem Mohamed' },
                ]} />
                <Input label={`${t('commSettings.fldTargetRev')} (${t('payroll.egp').trim()})`} type="number" value={form.targetRev || ''} onChange={e => updateForm('targetRev', e.target.value)} placeholder={t('commSettings.phTargetRev')} />
                <Input label={`${t('commSettings.fldBaseBonus')} (${t('payroll.egp').trim()})`} type="number" value={form.baseBonus || ''} onChange={e => updateForm('baseBonus', e.target.value)} placeholder={t('commSettings.phBaseBonus')} />
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-4)' }}>
                    <Input label={t('commSettings.fldMult120')} type="number" value={form.mult120 || ''} onChange={e => updateForm('mult120', e.target.value)} placeholder="1.5" hint={t('commSettings.hintMult120')} />
                    <Input label={t('commSettings.fldMult150')} type="number" value={form.mult150 || ''} onChange={e => updateForm('mult150', e.target.value)} placeholder="2.0" hint={t('commSettings.hintMult150')} />
                </div>
            </div>
        );
        if (activeTab === 'segment') return (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                <Input label={t('commSettings.fldSegName')} value={form.segment || ''} onChange={e => updateForm('segment', e.target.value)} placeholder={t('commSettings.phSegName')} />
                <Input label={t('commSettings.fldRate')} type="number" value={form.rate || ''} onChange={e => updateForm('rate', e.target.value)} placeholder={t('commSettings.phRate')} />
                <Input label={t('commSettings.fldDesc')} value={form.description || ''} onChange={e => updateForm('description', e.target.value)} placeholder={t('commSettings.phDesc')} />
            </div>
        );
        if (activeTab === 'extraction') return (
            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                <Input label={t('commSettings.fldServiceName')} value={form.service || ''} onChange={e => updateForm('service', e.target.value)} placeholder={t('commSettings.phService')} />
                <Input label={t('commSettings.fldExtRate')} type="number" value={form.extractionRate || ''} onChange={e => updateForm('extractionRate', e.target.value)} placeholder="15" hint={t('commSettings.hintExtRate')} />
                <Select label={t('commSettings.fldApplyTo')} value={form.applyTo || 'All Employees'} onChange={e => updateForm('applyTo', e.target.value)} options={[
                    { label: t('commissions.allEmp'), value: 'All Employees' },
                    { label: 'Sara Ahmed', value: 'Sara Ahmed' },
                    { label: 'Nora Ali', value: 'Nora Ali' },
                    { label: 'Layla Hassan', value: 'Layla Hassan' },
                    { label: 'Hana Youssef', value: 'Hana Youssef' },
                    { label: 'Reem Mohamed', value: 'Reem Mohamed' },
                ]} />
            </div>
        );
        return null;
    };

    // ─── Table Renderers ────────────
    const renderServiceTable = () => (
        <table style={s.table}>
            <thead><tr>{[t('commSettings.fldServiceName'), t('commSettings.fldCategory'), t('commSettings.fldRate'), t('commSettings.colActions')].map(h => <th key={h} style={{ ...s.th, textAlign: isRtl ? 'right' : 'left' } as React.CSSProperties}>{h}</th>)}</tr></thead>
            <tbody>
                {serviceRates.length === 0 ? (
                    <tr><td colSpan={4} style={s.emptyRow as React.CSSProperties}>{t('commSettings.emptyService')}</td></tr>
                ) : serviceRates.map(r => (
                    <tr key={r.id} className="hoverRow">
                        <td style={{ ...s.td, fontWeight: 'var(--font-medium)' }}>{r.service}</td>
                        <td style={s.td}><Badge color="neutral" size="sm">{t(`commSettings.cat${r.category.replace(/\s+/g, '')}`) || r.category}</Badge></td>
                        <td style={{ ...s.td, fontWeight: 'var(--font-semibold)', color: 'var(--color-primary-600)' }}>{r.rate}%</td>
                        <td style={s.td}>
                            <div style={s.actions}>
                                <button style={s.btnIcon} onClick={() => openEdit(r.id, r)}><Edit size={14} /></button>
                                <button style={{ ...s.btnIcon, color: 'var(--color-error)' }} onClick={() => handleDelete(r.id)}><Trash2 size={14} /></button>
                            </div>
                        </td>
                    </tr>
                ))}
            </tbody>
        </table>
    );

    const renderTargetTable = () => (
        <table style={s.table}>
            <thead><tr>{[t('commSettings.fldEmployee'), t('commSettings.fldTargetRev'), t('commSettings.fldBaseBonus'), t('commSettings.fldMult120'), t('commSettings.fldMult150'), t('commSettings.colActions')].map(h => <th key={h} style={{ ...s.th, textAlign: isRtl ? 'right' : 'left' } as React.CSSProperties}>{h}</th>)}</tr></thead>
            <tbody>
                {targetRules.length === 0 ? (
                    <tr><td colSpan={6} style={s.emptyRow as React.CSSProperties}>{t('commSettings.emptyTarget')}</td></tr>
                ) : targetRules.map(r => (
                    <tr key={r.id} className="hoverRow">
                        <td style={{ ...s.td, fontWeight: 'var(--font-medium)' }}>{r.employee}</td>
                        <td style={s.td}>{r.targetRev.toLocaleString()}{t('payroll.egp')}</td>
                        <td style={{ ...s.td, fontWeight: 'var(--font-semibold)', color: 'var(--color-primary-600)' }}>{r.baseBonus.toLocaleString()}{t('payroll.egp')}</td>
                        <td style={s.td}><Badge color="info" size="sm">×{r.mult120}</Badge></td>
                        <td style={s.td}><Badge color="success" size="sm">×{r.mult150}</Badge></td>
                        <td style={s.td}>
                            <div style={s.actions}>
                                <button style={s.btnIcon} onClick={() => openEdit(r.id, r)}><Edit size={14} /></button>
                                <button style={{ ...s.btnIcon, color: 'var(--color-error)' }} onClick={() => handleDelete(r.id)}><Trash2 size={14} /></button>
                            </div>
                        </td>
                    </tr>
                ))}
            </tbody>
        </table>
    );

    const renderSegmentTable = () => (
        <table style={s.table}>
            <thead><tr>{[t('commSettings.fldSegName'), t('commSettings.fldRate'), t('commSettings.fldDesc'), t('commSettings.colActions')].map(h => <th key={h} style={{ ...s.th, textAlign: isRtl ? 'right' : 'left' } as React.CSSProperties}>{h}</th>)}</tr></thead>
            <tbody>
                {segmentRates.length === 0 ? (
                    <tr><td colSpan={4} style={s.emptyRow as React.CSSProperties}>{t('commSettings.emptySegment')}</td></tr>
                ) : segmentRates.map(r => (
                    <tr key={r.id} className="hoverRow">
                        <td style={{ ...s.td, fontWeight: 'var(--font-medium)' }}>{r.segment}</td>
                        <td style={{ ...s.td, fontWeight: 'var(--font-semibold)', color: 'var(--color-primary-600)' }}>{r.rate}%</td>
                        <td style={{ ...s.td, color: 'var(--text-secondary)' }}>{r.description}</td>
                        <td style={s.td}>
                            <div style={s.actions}>
                                <button style={s.btnIcon} onClick={() => openEdit(r.id, r)}><Edit size={14} /></button>
                                <button style={{ ...s.btnIcon, color: 'var(--color-error)' }} onClick={() => handleDelete(r.id)}><Trash2 size={14} /></button>
                            </div>
                        </td>
                    </tr>
                ))}
            </tbody>
        </table>
    );

    const renderExtractionTable = () => (
        <table style={s.table}>
            <thead><tr>{[t('commSettings.fldServiceName'), t('commSettings.fldExtRate'), t('commSettings.fldApplyTo'), t('commSettings.colActions')].map(h => <th key={h} style={{ ...s.th, textAlign: isRtl ? 'right' : 'left' } as React.CSSProperties}>{h}</th>)}</tr></thead>
            <tbody>
                {extractionRules.length === 0 ? (
                    <tr><td colSpan={4} style={s.emptyRow as React.CSSProperties}>{t('commSettings.emptyExtraction')}</td></tr>
                ) : extractionRules.map(r => (
                    <tr key={r.id} className="hoverRow">
                        <td style={{ ...s.td, fontWeight: 'var(--font-medium)' }}>{r.service}</td>
                        <td style={{ ...s.td, fontWeight: 'var(--font-semibold)', color: '#ef4444' }}>{r.extractionRate}%</td>
                        <td style={s.td}><Badge color="neutral" size="sm">{r.applyTo === 'All Employees' ? t('commissions.allEmp') : r.applyTo}</Badge></td>
                        <td style={s.td}>
                            <div style={s.actions}>
                                <button style={s.btnIcon} onClick={() => openEdit(r.id, r)}><Edit size={14} /></button>
                                <button style={{ ...s.btnIcon, color: 'var(--color-error)' }} onClick={() => handleDelete(r.id)}><Trash2 size={14} /></button>
                            </div>
                        </td>
                    </tr>
                ))}
            </tbody>
        </table>
    );

    const renderActiveTable = () => {
        if (activeTab === 'service') return renderServiceTable();
        if (activeTab === 'target') return renderTargetTable();
        if (activeTab === 'segment') return renderSegmentTable();
        if (activeTab === 'extraction') return renderExtractionTable();
        return null;
    };

    return (
        <div style={{ ...s.page, direction: isRtl ? 'rtl' : 'ltr' }}>
            <div style={s.header}>
                <div>
                    <div style={{ fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)' }}>{t('commSettings.title')}</div>
                    <div style={{ fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)', marginTop: 'var(--space-1)' }}>{t('commSettings.desc')}</div>
                </div>
                <Button onClick={handleSaveAll}><Save size={16} className={isRtl ? 'ml-2' : 'mr-2'} /> {t('commSettings.saveAll')}</Button>
            </div>

            <div style={s.tabBar}>
                {tabs.map(tTab => (
                    <button
                        key={tTab.key}
                        style={{ ...s.tab, ...(tTab.key === activeTab ? s.tabActive : {}) }}
                        onClick={() => setActiveTab(tTab.key)}
                    >
                        {tTab.icon} {tTab.label}
                    </button>
                ))}
            </div>

            <div style={s.card}>
                <div style={s.cardHeader}>
                    <span>{tabLabels[activeTab]}</span>
                    <Button size="sm" onClick={openAdd}><Plus size={14} className={isRtl ? 'ml-2' : 'mr-2'} /> {t('commSettings.addRule')}</Button>
                </div>
                <div style={{ overflowX: 'auto' }}>
                    {renderActiveTable()}
                </div>
            </div>

            <div style={s.footer}>
                <Button onClick={handleSaveAll}><Save size={16} className={isRtl ? 'ml-2' : 'mr-2'} /> {t('commSettings.saveAll')}</Button>
            </div>

            {/* Add / Edit Modal */}
            <Modal
                open={modalOpen}
                onClose={() => setModalOpen(false)}
                title={modalMode === 'add' ? t('commSettings.addRule') : t('commSettings.editRule')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setModalOpen(false)}><X size={14} className={isRtl ? 'ml-2' : 'mr-2'} /> {t('commSettings.cancel')}</Button>
                        <Button onClick={handleSaveModal}><Check size={14} className={isRtl ? 'ml-2' : 'mr-2'} /> {modalMode === 'add' ? t('commSettings.addRule') : t('commSettings.saveChanges')}</Button>
                    </div>
                }
            >
                {renderModalFields()}
            </Modal>

            <style>{`
                .hoverRow:hover { background-color: var(--bg-secondary); }
                .hoverRow:last-child td { border-bottom: none !important; }
            `}</style>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { Plus, Search, Edit, Trash2, Users, MoreVertical, Eye, Briefcase } from 'lucide-react';
import { SlideOver, Modal, Input, Select, Button, useToast, DropdownMenu, EmptyState } from '@/components/ui';
import { useTranslation } from '@/hooks/useTranslation';

const initialDepartments = [
    { id: 1, name: 'Hair Styling', manager: 'Sara Ahmed', employees: 4, color: '#F59E0B', status: 'available' },
    { id: 2, name: 'Skin Care', manager: 'Nora Ali', employees: 3, color: '#EC4899', status: 'available' },
    { id: 3, name: 'Massage & Body', manager: 'Layla Hassan', employees: 2, color: '#10B981', status: 'available' },
    { id: 4, name: 'Nails', manager: 'Hana Youssef', employees: 2, color: '#3B82F6', status: 'available' },
    { id: 5, name: 'Reception', manager: 'Dina Nabil', employees: 2, color: '#8B5CF6', status: 'available' },
    { id: 6, name: 'Administration', manager: 'Sara Ahmed', employees: 1, color: '#6B7280', status: 'available' },
];

export default function DepartmentsPage() {
    const { t, lang } = useTranslation();
    const [departments, setDepartments] = useState(initialDepartments);
    const [search, setSearch] = useState('');
    const { addToast } = useToast();

    // Modals state
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [isViewOpen, setIsViewOpen] = useState(false);
    const [isAddStaffOpen, setIsAddStaffOpen] = useState(false);
    const [selectedDept, setSelectedDept] = useState<any>(null);

    // Mock staff data for details view
    const [staffList, setStaffList] = useState([
        { id: 1, name: 'Sara Ahmed', role: 'Senior Stylist', avatar: 'SA' },
        { id: 2, name: 'Nora Ali', role: 'Stylist', avatar: 'NA' },
        { id: 3, name: 'Layla Hassan', role: 'Junior Stylist', avatar: 'LH' }
    ]);

    // Form state
    const [formData, setFormData] = useState({ name: '', manager: '', employees: '', color: '#3B82F6' });
    const [newStaffSelection, setNewStaffSelection] = useState<string>('');
    const [newDeptStaff, setNewDeptStaff] = useState<any[]>([]);

    const availableStaffOptions = [
        { label: 'Farida Sayed (Stylist)', value: 'Farida Sayed' },
        { label: 'Kareem Tarek (Barber)', value: 'Kareem Tarek' },
        { label: 'Yasmin Omar (Therapist)', value: 'Yasmin Omar' },
        { label: 'Omar Khaled (Junior Stylist)', value: 'Omar Khaled' }
    ];

    const filtered = departments.filter(d => d.name.toLowerCase().includes(search.toLowerCase()));

    const handleSaveAdd = () => {
        if (!formData.name) return addToast('error', t('departments.toastReqName'));

        const newD = {
            id: departments.length + 1,
            name: formData.name,
            manager: formData.manager || t('departments.unassigned'),
            employees: newDeptStaff.length > 0 ? newDeptStaff.length : parseInt(formData.employees) || 0,
            color: formData.color,
            status: 'available'
        };

        setDepartments([...departments, newD]);
        setIsAddOpen(false);
        setFormData({ name: '', manager: '', employees: '', color: '#3B82F6' });
        setNewDeptStaff([]);
        addToast('success', t('departments.toastAddSuccess'));
    };

    const handleSaveEdit = () => {
        if (!formData.name) return addToast('error', t('departments.toastReqName'));

        setDepartments(departments.map(d => d.id === selectedDept.id ? {
            ...d,
            name: formData.name,
            manager: formData.manager,
            color: formData.color
        } : d));

        setIsEditOpen(false);
        setSelectedDept(null);
        addToast('success', t('departments.toastUpdateSuccess'));
    };

    const handleDelete = () => {
        setDepartments(departments.filter(d => d.id !== selectedDept.id));
        setIsDeleteOpen(false);
        setSelectedDept(null);
        addToast('success', t('departments.toastRemTitle'));
    };

    const handleRemoveStaff = (id: number) => {
        setStaffList(staffList.filter(s => s.id !== id));
        addToast('success', t('departments.toastStaffRem'));
    };

    const handleAddStaff = () => {
        if (!newStaffSelection) return addToast('error', t('departments.toastSelToAdd'));

        // Find existing to avoid duplicates in this mock
        if (staffList.find(s => s.name === newStaffSelection)) {
            return addToast('error', t('departments.toastAlreadyAssigned'));
        }

        const roleExtracted = availableStaffOptions.find(o => o.value === newStaffSelection)?.label.split('(')[1].replace(')', '') || 'Employee';
        const initials = newStaffSelection.split(' ').map(n => n[0]).join('').toUpperCase();

        const newStaffMember = {
            id: Date.now(), // timestamp mock ID
            name: newStaffSelection,
            role: roleExtracted,
            avatar: initials
        };

        setStaffList([...staffList, newStaffMember]);
        setNewStaffSelection('');
        setIsAddStaffOpen(false);
        addToast('success', `${t('departments.toastAssignedPart1')}${newStaffSelection}${t('departments.toastAssignedPart2')}${selectedDept?.name}`);
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-5)', direction: lang === 'ar' ? 'rtl' : 'ltr' }}>
            <div style={{ fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)' }}>{t('departments.title')}</div>

            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 'var(--space-3)', flexWrap: 'wrap' }}>
                <div style={{ position: 'relative', flex: 1, maxWidth: 320 }}>
                    <Search size={16} style={{ position: 'absolute', ...(lang === 'ar' ? { right: 12 } : { left: 12 }), top: '50%', transform: 'translateY(-50%)', color: 'var(--text-tertiary)' }} />
                    <input
                        style={{ width: '100%', height: 40, ...(lang === 'ar' ? { paddingRight: 40, paddingLeft: 12 } : { paddingLeft: 40, paddingRight: 12 }), border: '1px solid var(--border-color)', borderRadius: 'var(--radius-lg)', background: 'var(--bg-primary)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)' }}
                        placeholder={t('departments.search')}
                        value={search}
                        onChange={e => setSearch(e.target.value)}
                    />
                </div>
                <Button onClick={() => setIsAddOpen(true)}>
                    <Plus size={16} className={lang === 'ar' ? 'ml-2' : 'mr-2'} /> {t('departments.newDept')}
                </Button>
            </div>

            {filtered.length > 0 ? (
                <div style={{ background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-xl)', overflow: 'hidden' }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead>
                            <tr>
                                {[{ label: t('departments.colDept'), key: 'dept' }, { label: t('departments.colManager'), key: 'manager' }, { label: t('departments.colStaffCount'), key: 'count' }, { label: t('departments.colStatus'), key: 'status' }, { label: t('departments.colActions'), key: 'actions' }].map(h =>
                                    <th key={h.key} style={{ padding: 'var(--space-3) var(--space-4)', fontSize: 'var(--text-xs)', fontWeight: 'var(--font-semibold)', color: 'var(--text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', background: 'var(--bg-secondary)', borderBottom: '1px solid var(--border-color)', textAlign: lang === 'ar' ? 'right' : 'left' }}>{h.label}</th>
                                )}
                            </tr>
                        </thead>
                        <tbody>
                            {filtered.map(d => (
                                <tr key={d.id} className="hoverRow">
                                    <td style={{ padding: 'var(--space-4)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)', borderBottom: '1px solid var(--border-color)', fontWeight: 'var(--font-medium)' }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-2)' }}>
                                            <span style={{ width: 10, height: 10, borderRadius: '50%', display: 'inline-block', background: d.color }} />
                                            {d.name}
                                        </div>
                                    </td>
                                    <td style={{ padding: 'var(--space-4)', fontSize: 'var(--text-sm)', color: 'var(--text-secondary)', borderBottom: '1px solid var(--border-color)' }}>{d.manager}</td>
                                    <td style={{ padding: 'var(--space-4)', fontSize: 'var(--text-sm)', color: 'var(--text-secondary)', borderBottom: '1px solid var(--border-color)' }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}><Users size={14} /> {d.employees} {t('departments.users')}</div>
                                    </td>
                                    <td style={{ padding: 'var(--space-4)', fontSize: 'var(--text-sm)', borderBottom: '1px solid var(--border-color)' }}>
                                        <span style={{ display: 'inline-flex', padding: '2px 8px', borderRadius: 'var(--radius-full)', fontSize: 11, fontWeight: 'var(--font-semibold)', background: 'var(--color-success-light)', color: 'var(--color-success)' }}>{t('departments.active')}</span>
                                    </td>
                                    <td style={{ padding: 'var(--space-4)', fontSize: 'var(--text-sm)', borderBottom: '1px solid var(--border-color)' }}>
                                        <DropdownMenu
                                            trigger={
                                                <button style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', width: 32, height: 32, borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)', background: 'transparent', cursor: 'pointer', color: 'var(--text-secondary)' }}>
                                                    <MoreVertical size={16} />
                                                </button>
                                            }
                                            items={[
                                                { label: t('departments.actionView'), icon: <Eye size={14} />, onClick: () => { setSelectedDept(d); setIsViewOpen(true); } },
                                                { label: t('departments.actionEdit'), icon: <Edit size={14} />, onClick: () => { setSelectedDept(d); setFormData({ name: d.name, manager: d.manager, employees: d.employees.toString(), color: d.color }); setIsEditOpen(true); } },
                                                { label: t('departments.actionDelete'), destructive: true, icon: <Trash2 size={14} />, onClick: () => { setSelectedDept(d); setIsDeleteOpen(true); } }
                                            ]}
                                        />
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                    <style>{`
                        .hoverRow:hover { background-color: var(--bg-secondary); }
                        .hoverRow:last-child td { border-bottom: none !important; }
                    `}</style>
                </div>
            ) : (
                <EmptyState icon={<Briefcase size={32} color="var(--text-tertiary)" />} title={t('departments.emptyTitle')} description={t('departments.emptyDesc')} />
            )}

            {/* Add SlideOver */}
            <SlideOver
                open={isAddOpen}
                onClose={() => setIsAddOpen(false)}
                title={t('departments.addTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => { setIsAddOpen(false); setNewDeptStaff([]); }}>{t('departments.btnCancel')}</Button>
                        <Button onClick={handleSaveAdd}>{t('departments.btnCreate')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('departments.lblName')} placeholder={t('departments.phName')} value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
                    <Select
                        label={t('departments.lblManager')}
                        value={formData.manager}
                        onChange={e => setFormData({ ...formData, manager: e.target.value })}
                        options={[{ label: t('departments.unassigned'), value: '' }, ...availableStaffOptions]}
                    />
                    <Select label={t('departments.lblColor')} value={formData.color} onChange={e => setFormData({ ...formData, color: e.target.value })} options={[
                        { label: t('departments.colorAmber'), value: '#F59E0B' },
                        { label: t('departments.colorPink'), value: '#EC4899' },
                        { label: t('departments.colorEmerald'), value: '#10B981' },
                        { label: t('departments.colorBlue'), value: '#3B82F6' },
                        { label: t('departments.colorPurple'), value: '#8B5CF6' }
                    ]} />

                    <div style={{ borderTop: '1px solid var(--border-color)', margin: 'var(--space-2) 0' }} />

                    <div>
                        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 'var(--space-2)' }}>
                            <h3 style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)' }}>{t('departments.assignStaff')}</h3>
                        </div>
                        <div style={{ display: 'flex', gap: 'var(--space-2)', alignItems: 'flex-end' }}>
                            <div style={{ flex: 1 }}>
                                <Select
                                    label=""
                                    value={newStaffSelection}
                                    onChange={e => setNewStaffSelection(e.target.value)}
                                    options={[{ label: t('departments.phEmployee'), value: '' }, ...availableStaffOptions]}
                                />
                            </div>
                            <Button variant="secondary" onClick={() => {
                                if (!newStaffSelection) return;
                                if (newDeptStaff.find(s => s.name === newStaffSelection)) return;
                                const roleExtracted = availableStaffOptions.find(o => o.value === newStaffSelection)?.label?.split('(')[1]?.replace(')', '') || 'Employee';
                                const initials = newStaffSelection.split(' ').map(n => n[0]).join('').toUpperCase();
                                setNewDeptStaff([...newDeptStaff, { id: Date.now(), name: newStaffSelection, role: roleExtracted, avatar: initials }]);
                                setNewStaffSelection('');
                            }}>{t('departments.btnAdd')}</Button>
                        </div>

                        {newDeptStaff.length > 0 && (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-2)', marginTop: 'var(--space-3)' }}>
                                {newDeptStaff.map(staff => (
                                    <div key={staff.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: 'var(--space-2) var(--space-3)', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)' }}>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-3)' }}>
                                            <div style={{ width: 28, height: 28, borderRadius: '50%', background: 'var(--color-primary-100)', color: 'var(--color-primary-600)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '10px', fontWeight: 'var(--font-bold)' }}>
                                                {staff.avatar}
                                            </div>
                                            <div style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)' }}>{staff.name}</div>
                                        </div>
                                        <Trash2 size={14} style={{ cursor: 'pointer', color: 'var(--color-error)' }} onClick={() => setNewDeptStaff(newDeptStaff.filter(s => s.id !== staff.id))} />
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            </SlideOver>

            {/* Edit SlideOver */}
            <SlideOver
                open={isEditOpen}
                onClose={() => { setIsEditOpen(false); setSelectedDept(null); }}
                title={t('departments.editTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('departments.btnCancel')}</Button>
                        <Button onClick={handleSaveEdit}>{t('departments.btnSave')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('departments.lblName')} value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} />
                    <Select
                        label={t('departments.lblManager')}
                        value={formData.manager}
                        onChange={e => setFormData({ ...formData, manager: e.target.value })}
                        options={[{ label: t('departments.unassigned'), value: '' }, ...availableStaffOptions]}
                    />
                    <Select label={t('departments.lblColor')} value={formData.color} onChange={e => setFormData({ ...formData, color: e.target.value })} options={[
                        { label: t('departments.colorAmber'), value: '#F59E0B' },
                        { label: t('departments.colorPink'), value: '#EC4899' },
                        { label: t('departments.colorEmerald'), value: '#10B981' },
                        { label: t('departments.colorBlue'), value: '#3B82F6' },
                        { label: t('departments.colorPurple'), value: '#8B5CF6' }
                    ]} />
                </div>
            </SlideOver>

            {/* View SlideOver */}
            <SlideOver
                open={isViewOpen}
                onClose={() => { setIsViewOpen(false); setSelectedDept(null); }}
                title={t('departments.viewTitle')}
            >
                {selectedDept && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-6)' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-4)' }}>
                            <div style={{ width: 48, height: 48, borderRadius: 'var(--radius-lg)', background: selectedDept.color, opacity: 0.1, position: 'relative' }}>
                                <Briefcase size={20} style={{ position: 'absolute', top: '50%', left: '50%', transform: 'translate(-50%, -50%)', color: selectedDept.color }} />
                            </div>
                            <div>
                                <h2 style={{ fontSize: 'var(--text-lg)', fontWeight: 'var(--font-bold)', color: 'var(--text-primary)' }}>{selectedDept.name}</h2>
                                <p style={{ fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)' }}>{selectedDept.employees} {t('departments.activeStaff')}</p>
                            </div>
                        </div>

                        <div style={{ borderTop: '1px solid var(--border-color)' }} />

                        <div>
                            <h3 style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)', color: 'var(--text-primary)', marginBottom: 'var(--space-3)' }}>{t('departments.mgtInfo')}</h3>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-3)' }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                                    <span style={{ color: 'var(--text-tertiary)', fontSize: 'var(--text-sm)' }}>{t('departments.colManager')}</span>
                                    <span style={{ fontWeight: 'var(--font-medium)', fontSize: 'var(--text-sm)' }}>{selectedDept.manager}</span>
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                                    <span style={{ color: 'var(--text-tertiary)', fontSize: 'var(--text-sm)' }}>{t('departments.colStatus')}</span>
                                    <span style={{ color: 'var(--color-success)', fontWeight: 'var(--font-medium)', fontSize: 'var(--text-sm)' }}>{t('departments.active')}</span>
                                </div>
                                <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                                    <span style={{ color: 'var(--text-tertiary)', fontSize: 'var(--text-sm)' }}>{t('departments.payrollTag')}</span>
                                    <span style={{ fontWeight: 'var(--font-medium)', fontSize: 'var(--text-sm)' }}>{selectedDept.name.substring(0, 3).toUpperCase()}-XX</span>
                                </div>
                            </div>
                        </div>

                        <div style={{ borderTop: '1px solid var(--border-color)' }} />

                        <div>
                            <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 'var(--space-3)' }}>
                                <h3 style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)', color: 'var(--text-primary)' }}>{t('departments.assignedStaff')} ({staffList.length})</h3>
                                <Button variant="secondary" onClick={() => setIsAddStaffOpen(true)}>
                                    <Plus size={14} style={{ ...(lang === 'ar' ? { marginLeft: 4 } : { marginRight: 4 }) }} /> {t('departments.btnAddStaff')}
                                </Button>
                            </div>

                            {staffList.length > 0 ? (
                                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-2)' }}>
                                    {staffList.map(staff => (
                                        <div key={staff.id} style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: 'var(--space-3)', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)', border: '1px solid var(--border-color)' }}>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-3)' }}>
                                                <div style={{ width: 36, height: 36, borderRadius: '50%', background: 'var(--color-primary-100)', color: 'var(--color-primary-600)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 'var(--text-sm)', fontWeight: 'var(--font-bold)' }}>
                                                    {staff.avatar}
                                                </div>
                                                <div>
                                                    <div style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', color: 'var(--text-primary)' }}>{staff.name}</div>
                                                    <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{staff.role}</div>
                                                </div>
                                            </div>
                                            <button
                                                onClick={() => handleRemoveStaff(staff.id)}
                                                title={t('departments.removeStaffTitle')}
                                                style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', width: 32, height: 32, borderRadius: 'var(--radius-md)', border: 'none', background: 'transparent', cursor: 'pointer', color: 'var(--color-error)' }}
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <EmptyState icon={<Users size={24} color="var(--text-tertiary)" />} title={t('departments.emptyStaffTitle')} description={t('departments.emptyStaffDesc')} />
                            )}
                        </div>
                    </div>
                )}
            </SlideOver>

            {/* Delete Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedDept(null); }}
                title={t('departments.delTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('departments.btnCancel')}</Button>
                        <Button variant="destructive" onClick={handleDelete}>{t('departments.btnRemoveAnyway')}</Button>
                    </div>
                }
            >
                <p style={{ color: 'var(--text-secondary)' }}>
                    {t('departments.delConfirmMsg1')}<strong>{selectedDept?.name}</strong>{t('departments.delConfirmMsg2')}
                </p>
            </Modal>

            {/* Add Staff Modal */}
            <Modal
                open={isAddStaffOpen}
                onClose={() => { setIsAddStaffOpen(false); setNewStaffSelection(''); }}
                title={`${t('departments.addStaffModalTitle')} ${selectedDept?.name || 'Department'}`}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => { setIsAddStaffOpen(false); setNewStaffSelection(''); }}>{t('departments.btnCancel')}</Button>
                        <Button onClick={handleAddStaff}>{t('departments.btnAssignMember')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <p style={{ fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)' }}>
                        {t('departments.addStaffHint')}
                    </p>
                    <Select
                        label={t('departments.lblAvailableEmp')}
                        value={newStaffSelection}
                        onChange={e => setNewStaffSelection(e.target.value)}
                        options={[{ label: t('departments.phEmployee'), value: '' }, ...availableStaffOptions]}
                    />
                </div>
            </Modal>
        </div>
    );
}

﻿'use client';

import React, { useState } from 'react';
import { Fingerprint, Search, RefreshCw, Trash2 } from 'lucide-react';
import { Modal, Select, Button, useToast, EmptyState } from '@/components/ui';

const initialData = [
    { id: 1, employee: 'Sara Ahmed', device: 'BioStation A2', enrollDate: '2026-01-05', fingers: 2, status: 'enrolled' },
    { id: 2, employee: 'Nora Ali', device: 'BioStation A2', enrollDate: '2026-01-05', fingers: 2, status: 'enrolled' },
    { id: 3, employee: 'Layla Hassan', device: 'BioStation A2', enrollDate: '2026-01-10', fingers: 2, status: 'enrolled' },
    { id: 4, employee: 'Hana Youssef', device: 'BioStation A2', enrollDate: '2026-01-10', fingers: 1, status: 'partial' },
    { id: 5, employee: 'Reem Mohamed', device: 'BioStation A2', enrollDate: '-', fingers: 0, status: 'not_enrolled' },
    { id: 6, employee: 'Dina Nabil', device: 'FaceStation F2', enrollDate: '2026-02-01', fingers: 2, status: 'enrolled' },
];

const statusMap: Record<string, { label: string; bg: string; color: string }> = {
    enrolled: { label: ' Enrolled', bg: 'var(--color-success-light)', color: 'var(--color-success)' },
    partial: { label: ' Partial', bg: 'var(--color-warning-light)', color: 'var(--color-warning)' },
    not_enrolled: { label: ' Not Enrolled', bg: 'var(--color-error-light)', color: 'var(--color-error)' },
};

const s: Record<string, React.CSSProperties> = {
    page: { display: 'flex', flexDirection: 'column', gap: 'var(--space-5)' },
    toolbar: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 'var(--space-3)', flexWrap: 'wrap' },
    filterGroup: { display: 'flex', alignItems: 'center', gap: 'var(--space-3)', flex: 1 },
    searchBox: { position: 'relative', width: '100%', maxWidth: 320 },
    searchIcon: { position: 'absolute', left: 12, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-tertiary)' },
    searchInput: { width: '100%', height: 40, paddingLeft: 40, border: '1px solid var(--border-color)', borderRadius: 'var(--radius-lg)', background: 'var(--bg-primary)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)' },
    table: { width: '100%', background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-xl)', overflow: 'hidden' },
    th: { padding: 'var(--space-3) var(--space-4)', textAlign: 'left', fontSize: 'var(--text-xs)', fontWeight: 'var(--font-semibold)', color: 'var(--text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', background: 'var(--bg-secondary)', borderBottom: '1px solid var(--border-color)' },
    td: { padding: 'var(--space-3) var(--space-4)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)', borderBottom: '1px solid var(--border-color)' },
    badge: { display: 'inline-flex', padding: '2px 8px', borderRadius: 'var(--radius-full)', fontSize: 11, fontWeight: 'var(--font-semibold)' },
    actions: { display: 'flex', gap: 'var(--space-2)' },
    btnIcon: { display: 'flex', alignItems: 'center', justifyContent: 'center', width: 30, height: 30, borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)', background: 'var(--bg-primary)', cursor: 'pointer', color: 'var(--text-secondary)' },
    btnHoverText: { display: 'inline-flex', alignItems: 'center', gap: 6, padding: '4px 10px', borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)', background: 'var(--bg-primary)', cursor: 'pointer', fontSize: 12, fontWeight: 'var(--font-medium)' }
};

export default function FingerprintsPage() {
    const [fingerprints, setFingerprints] = useState(initialData);
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState('All');
    const { addToast } = useToast();

    // Modals
    const [isEnrollOpen, setIsEnrollOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [selectedEmployee, setSelectedEmployee] = useState<any>(null);
    const [isScanning, setIsScanning] = useState(false);

    const filtered = fingerprints.filter(f => {
        const matchesSearch = f.employee.toLowerCase().includes(search.toLowerCase()) ||
            f.device.toLowerCase().includes(search.toLowerCase());
        const matchesStatus = statusFilter === 'All' || f.status === statusFilter;
        return matchesSearch && matchesStatus;
    });

    const handleStartScan = () => {
        setIsScanning(true);
        // Simulate scanning delay
        setTimeout(() => {
            setIsScanning(false);
            setFingerprints(fingerprints.map(f => f.id === selectedEmployee.id ? {
                ...f,
                status: 'enrolled',
                fingers: 2,
                enrollDate: new Date().toISOString().split('T')[0]
            } : f));
            setIsEnrollOpen(false);
            setSelectedEmployee(null);
            addToast('success', 'Fingerprint enrolled successfully.');
        }, 2000);
    };

    const handleDelete = () => {
        setFingerprints(fingerprints.map(f => f.id === selectedEmployee.id ? {
            ...f,
            status: 'not_enrolled',
            fingers: 0,
            enrollDate: '-'
        } : f));
        setIsDeleteOpen(false);
        setSelectedEmployee(null);
        addToast('success', 'Fingerprint data cleared.');
    };

    return (
        <div style={s.page}>
            <div style={{ fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)' }}>Fingerprint Management</div>

            <div style={s.toolbar}>
                <div style={s.filterGroup as React.CSSProperties}>
                    <div style={s.searchBox as React.CSSProperties}>
                        <Search size={16} style={s.searchIcon as React.CSSProperties} />
                        <input style={s.searchInput} placeholder="Search employees or devices..." value={search} onChange={e => setSearch(e.target.value)} />
                    </div>
                    <Select
                        value={statusFilter}
                        onChange={e => setStatusFilter(e.target.value)}
                        options={[
                            { label: 'All Statuses', value: 'All' },
                            { label: 'Enrolled', value: 'enrolled' },
                            { label: 'Partial', value: 'partial' },
                            { label: 'Not Enrolled', value: 'not_enrolled' },
                        ]}
                        style={{ width: 160 }}
                    />
                </div>
            </div>

            {filtered.length > 0 ? (
                <table style={s.table}>
                    <thead>
                        <tr>
                            {['Employee', 'Verification Device', 'Enrolled Date', 'Fingers Scanned', 'Status', 'Actions'].map(h =>
                                <th key={h} style={s.th as React.CSSProperties}>{h}</th>
                            )}
                        </tr>
                    </thead>
                    <tbody>
                        {filtered.map(row => {
                            const st = statusMap[row.status];
                            return (
                                <tr key={row.id} className="hoverRow">
                                    <td style={{ ...s.td, fontWeight: 'var(--font-medium)' } as React.CSSProperties}>{row.employee}</td>
                                    <td style={s.td}>{row.device}</td>
                                    <td style={s.td}>{row.enrollDate}</td>
                                    <td style={s.td}>{row.fingers}/2</td>
                                    <td style={s.td}><span style={{ ...s.badge, background: st.bg, color: st.color }}>{st.label}</span></td>
                                    <td style={s.td}>
                                        <div style={s.actions}>
                                            <button
                                                style={{ ...s.btnHoverText, color: 'var(--color-primary-600)' }}
                                                onClick={() => { setSelectedEmployee(row); setIsEnrollOpen(true); }}
                                            >
                                                <RefreshCw size={14} /> {row.status === 'not_enrolled' ? 'Enroll Fingerprint' : 'Re-enroll'}
                                            </button>
                                            {row.status !== 'not_enrolled' && (
                                                <button
                                                    style={{ ...s.btnIcon, color: 'var(--color-error)' }}
                                                    onClick={() => { setSelectedEmployee(row); setIsDeleteOpen(true); }}
                                                    title="Clear Fingerprint Data"
                                                >
                                                    <Trash2 size={14} />
                                                </button>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            ) : (
                <EmptyState icon={<Fingerprint size={32} color="var(--text-tertiary)" />} title="No fingerprint records found" description="Adjust your filters or search query to find what you're looking for." />
            )}

            <style>{`
                .hoverRow:hover { background-color: var(--bg-secondary); }
                .hoverRow:last-child td { border-bottom: none !important; }

                @keyframes pulse {
                    0% { transform: scale(0.95); opacity: 0.5; }
                    50% { transform: scale(1.05); opacity: 1; }
                    100% { transform: scale(0.95); opacity: 0.5; }
                }
                .fingerprint-icon-scanning {
                    animation: pulse 1.5s infinite ease-in-out;
                    color: var(--color-primary-600);
                }
            `}</style>

            {/* Enroll Modal */}
            <Modal
                title="Device Sync & Enrollment"
                open={isEnrollOpen}
                onClose={() => !isScanning && setIsEnrollOpen(false)}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEnrollOpen(false)} disabled={isScanning}>Cancel</Button>
                        <Button onClick={handleStartScan} disabled={isScanning}>
                            {isScanning ? 'Scanning...' : 'Start Scan on Device'}
                        </Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 'var(--space-6)', padding: 'var(--space-4) 0' }}>

                    <div style={{ width: 80, height: 80, borderRadius: '50%', background: 'var(--color-primary-50)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                        <Fingerprint size={40} className={isScanning ? 'fingerprint-icon-scanning' : ''} color={isScanning ? "var(--color-primary-600)" : "var(--text-tertiary)"} />
                    </div>

                    <div style={{ textAlign: 'center' }}>
                        <div style={{ fontWeight: 'var(--font-semibold)', fontSize: 'var(--text-lg)', marginBottom: 4 }}>
                            {isScanning ? 'Scanning in progress...' : 'Ready to Enroll'}
                        </div>
                        <div style={{ color: 'var(--text-secondary)', fontSize: 'var(--text-sm)' }}>
                            {isScanning
                                ? `Please wait while ${selectedEmployee?.employee} scans their fingers on the ${selectedEmployee?.device} device.`
                                : `Instruct ${selectedEmployee?.employee} to step up to the ${selectedEmployee?.device} device and place their finger on the sensor. Click Start Scan below to begin.`
                            }
                        </div>
                    </div>

                    {isScanning && (
                        <div style={{ width: '100%', maxWidth: 240, height: 4, background: 'var(--bg-secondary)', borderRadius: 2, overflow: 'hidden' }}>
                            <div style={{ width: '100%', height: '100%', background: 'var(--color-primary-600)', transformOrigin: 'left', animation: 'progress 2s linear infinite' }} />
                            <style>{`
                                @keyframes progress {
                                    0% { transform: scaleX(0); }
                                    50% { transform: scaleX(1); opacity: 1; }
                                    100% { transform: scaleX(1); opacity: 0; }
                                }
                            `}</style>
                        </div>
                    )}

                </div>
            </Modal>

            {/* Delete/Clear Modal */}
            <Modal
                title="Clear Fingerprint Data"
                open={isDeleteOpen}
                onClose={() => setIsDeleteOpen(false)}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>Cancel</Button>
                        <Button variant="destructive" onClick={handleDelete}>Confirm Clear</Button>
                    </div>
                }
            >
                <p style={{ color: 'var(--text-secondary)' }}>
                    Are you sure you want to permanently clear the enrolled fingerprint data for <strong>{selectedEmployee?.employee}</strong>? They will need to re-enroll on the device to authenticate.
                </p>
            </Modal>
        </div>
    );
}

