export default function NotificationsPage() {
    const { addToast } = useToast();
    const { t } = useTranslation();
    const [notifications, setNotifications] = useState(initialNotifications);
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [isDetailOpen, setIsDetailOpen] = useState(false);
    const [selected, setSelected] = useState<any>(null);
    const [recipientFilter, setRecipientFilter] = useState<'all' | 'opened' | 'not_opened'>('all');
    const [recipientSearch, setRecipientSearch] = useState('');

    const openDetail = (n: any) => { setSelected(n); setIsDetailOpen(true); setRecipientFilter('all'); setRecipientSearch(''); };
    const openEdit = (n: any) => { setSelected(n); setIsDetailOpen(false); setIsEditOpen(true); };
    const openDelete = (n: any) => { setSelected(n); setIsDetailOpen(false); setIsDeleteOpen(true); };

    const handleDelete = () => {
        setNotifications(prev => prev.filter(n => n.id !== selected?.id));
        setIsDeleteOpen(false);
        setSelected(null);
        addToast('success', t('mkt.lblDeleteNotification'));
    };

    const totalSent = notifications.reduce((a, n) => a + n.sent, 0);
    const totalOpened = notifications.reduce((a, n) => a + n.opened, 0);

    const filteredRecipients = useMemo(() => {
        if (!selected) return [];
        const list = recipientData[selected.id] || [];
        let filtered = list;
        if (recipientFilter === 'opened') filtered = list.filter(r => r.opened);
        if (recipientFilter === 'not_opened') filtered = list.filter(r => !r.opened);
        if (recipientSearch) filtered = filtered.filter(r => r.name.toLowerCase().includes(recipientSearch.toLowerCase()));
        return filtered;
    }, [selected, recipientFilter, recipientSearch]);

    const getInitials = (name: string) => name.split(' ').map(n => n[0]).join('').toUpperCase();

    return (
        <div style={s.page}>
            <MarketingTabs />

            <div style={s.kpis}>
                <div style={s.kpi}><div style={s.kpiVal}>{totalSent}</div><div style={s.kpiLbl}>{t('mkt.lblTotalSent')}</div></div>
                <div style={s.kpi}><div style={s.kpiVal}>{totalOpened}</div><div style={s.kpiLbl}>{t('mkt.lblTotalOpened')}</div></div>
                <div style={s.kpi}><div style={s.kpiVal}>{totalSent > 0 ? Math.round(totalOpened / totalSent * 100) : 0}%</div><div style={s.kpiLbl}>{t('mkt.lblOpenRate')}</div></div>
            </div>

            <div style={s.toolbar}><button style={s.addBtn} onClick={() => setIsAddOpen(true)}><Plus size={16} /> {t('mkt.btnCompose')}</button></div>

            <table style={s.table}>
                <thead><tr>{[t('mkt.lblTitle'), t('mkt.lblChannel'), t('mkt.lblAudience'), t('mkt.lblTotalSent'), t('mkt.lblOpened'), t('mkt.lblDate'), t('mkt.lblStatus'), ''].map((h, i) => <th key={i} style={s.th as React.CSSProperties}>{h}</th>)}</tr></thead>
                <tbody>
                    {notifications.map(n => (
                        <tr key={n.id} style={{ cursor: 'pointer' }} className="hoverRow" onClick={() => openDetail(n)}>
                            <td style={{ ...s.td, fontWeight: 'var(--font-medium)' }}>{n.title}</td>
                            <td style={s.td}><Badge color={channelBadge[n.channel]} size="sm">{n.channel}</Badge></td>
                            <td style={s.td}>{n.audience}</td>
                            <td style={s.td}>{n.sent}</td>
                            <td style={{ ...s.td, color: 'var(--color-primary-600)', fontWeight: 'var(--font-medium)' }}>{n.opened}</td>
                            <td style={s.td}>{n.date}</td>
                            <td style={s.td}><Badge color={statusBadge[n.status]} size="sm">{t(`mkt.lbl${n.status.charAt(0).toUpperCase() + n.status.slice(1)}`) || n.status}</Badge></td>
                            <td style={{ ...s.td, textAlign: 'right' }} onClick={e => e.stopPropagation()}>
                                <DropdownMenu
                                    trigger={<button style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-tertiary)' }}><MoreVertical size={16} /></button>}
                                    items={[
                                        { label: t('bk.actionView'), icon: <Eye size={14} />, onClick: () => openDetail(n) },
                                        { label: t('mkt.lblEditNotification'), icon: <Edit size={14} />, onClick: () => openEdit(n) },
                                        { label: t('mkt.lblDeleteNotification'), destructive: true, icon: <Trash2 size={14} />, onClick: () => openDelete(n) }
                                    ]}
                                />
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>

            {/* Detail SlideOver */}
            <SlideOver open={isDetailOpen} onClose={() => { setIsDetailOpen(false); setSelected(null); }} title={t('mkt.lblNotificationDetails')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => openDelete(selected)}><Trash2 size={14} /> {t('mkt.lblDeleteNotification')}</Button>
                        <Button variant="ghost" onClick={() => { addToast('success', 'Notification resent'); setIsDetailOpen(false); }}><RefreshCw size={14} /> {t('mkt.btnResend')}</Button>
                        <Button onClick={() => openEdit(selected)}><Edit size={14} /> {t('bk.btnEdit')}</Button>
                    </div>
                }
            >
                {selected && (
                    <div style={s.detailSection as React.CSSProperties}>
                        <div>
                            <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-2)', marginBottom: 'var(--space-2)' }}>
                                <span style={{ fontSize: 'var(--text-xl)', fontWeight: 'var(--font-bold)' }}>{selected.title}</span>
                                <Badge color={statusBadge[selected.status]}>{t(`mkt.lbl${selected.status.charAt(0).toUpperCase() + selected.status.slice(1)}`) || selected.status}</Badge>
                            </div>
                            <div style={{ display: 'flex', gap: 'var(--space-2)' }}>
                                <Badge color={channelBadge[selected.channel]} size="sm">{channelIcons[selected.channel]} {selected.channel}</Badge>
                                <Badge color="neutral" size="sm">{selected.audience}</Badge>
                            </div>
                        </div>

                        <div style={s.infoGrid as React.CSSProperties}>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblTotalSent')}</div>
                                <div style={{ ...s.infoValue, fontSize: 'var(--text-2xl)' }}>{selected.sent}</div>
                            </div>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblTotalOpened')}</div>
                                <div style={{ ...s.infoValue, fontSize: 'var(--text-2xl)', color: 'var(--color-primary-600)' }}>{selected.opened}</div>
                            </div>
                        </div>

                        {/* Open Rate Progress */}
                        <div>
                            <div style={{ ...s.sectionTitle as React.CSSProperties, marginBottom: 'var(--space-3)' }}>{t('mkt.lblOpenRate')}</div>
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 'var(--space-2)' }}>
                                <span style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)' }}>{selected.opened} / {selected.sent} {t('mkt.lblOpened').toLowerCase()}</span>
                                <span style={{ fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)' }}>{selected.sent > 0 ? Math.round(selected.opened / selected.sent * 100) : 0}%</span>
                            </div>
                            <div style={s.progressContainer}>
                                <div style={{ ...s.progressFill, width: `${selected.sent > 0 ? Math.min(selected.opened / selected.sent * 100, 100) : 0}%`, background: 'var(--color-primary-500)' }} />
                            </div>
                        </div>

                        {/* Recipient List with Filter */}
                        <div>
                            <div style={{ ...s.sectionTitle as React.CSSProperties, marginBottom: 'var(--space-3)' }}>{t('mkt.lblRecipients')}</div>

                            {/* Filter tabs */}
                            <div style={s.filterBar as React.CSSProperties}>
                                {[
                                    { key: 'all' as const, label: t('mkt.lblAll'), count: recipientData[selected.id]?.length || 0 },
                                    { key: 'opened' as const, label: t('mkt.lblOpened'), count: recipientData[selected.id]?.filter(r => r.opened).length || 0 },
                                    { key: 'not_opened' as const, label: t('mkt.lblNotOpened'), count: recipientData[selected.id]?.filter(r => !r.opened).length || 0 },
                                ].map(f => (
                                    <button
                                        key={f.key}
                                        style={{ ...s.filterBtn, ...(recipientFilter === f.key ? s.filterBtnActive : {}) }}
                                        onClick={() => setRecipientFilter(f.key)}
                                    >
                                        {f.label} ({f.count})
                                    </button>
                                ))}
                            </div>

                            {/* Search */}
                            <div style={{ position: 'relative' as const, marginBottom: 'var(--space-3)' }}>
                                <Search size={14} style={{ position: 'absolute' as const, left: 10, top: '50%', transform: 'translateY(-50%)', color: 'var(--text-tertiary)' }} />
                                <input
                                    style={{ width: '100%', height: 36, paddingLeft: 32, border: '1px solid var(--border-color)', borderRadius: 'var(--radius-lg)', background: 'var(--bg-primary)', fontSize: 'var(--text-sm)', color: 'var(--text-primary)' }}
                                    placeholder={t('mkt.phSearchRecipients')}
                                    value={recipientSearch}
                                    onChange={e => setRecipientSearch(e.target.value)}
                                />
                            </div>

                            {/* Recipient list */}
                            <div style={{ border: '1px solid var(--border-color)', borderRadius: 'var(--radius-lg)', overflow: 'hidden', maxHeight: 300, overflowY: 'auto' }}>
                                {filteredRecipients.length === 0 ? (
                                    <div style={{ padding: 'var(--space-4)', textAlign: 'center', color: 'var(--text-tertiary)', fontSize: 'var(--text-sm)' }}>
                                        {recipientData[selected.id] ? t('mkt.msgNoRecipientsMatch') : 'No recipient data available'}
                                    </div>
                                ) : (
                                    filteredRecipients.map((r, i) => (
                                        <div key={i} style={{ ...s.recipientItem, borderTop: i === 0 ? 'none' : '1px solid var(--border-color)' }}>
                                            <div style={s.recipientInfo as React.CSSProperties}>
                                                <div style={{ ...s.recipientAvatar, background: r.opened ? 'var(--color-success)' : 'var(--color-gray-400)' }}>
                                                    {getInitials(r.name)}
                                                </div>
                                                <div>
                                                    <div style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)' }}>{r.name}</div>
                                                    <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{r.phone}</div>
                                                </div>
                                            </div>
                                            <div style={{ textAlign: 'right' }}>
                                                {r.opened ? (
                                                    <>
                                                        <div style={{ display: 'flex', alignItems: 'center', gap: 4, color: 'var(--color-success)', fontSize: 'var(--text-xs)', fontWeight: 'var(--font-semibold)' }}><Check size={12} /> {t('mkt.lblOpened')}</div>
                                                        <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{r.openedAt}</div>
                                                    </>
                                                ) : (
                                                    <div style={{ display: 'flex', alignItems: 'center', gap: 4, color: 'var(--color-gray-400)', fontSize: 'var(--text-xs)', fontWeight: 'var(--font-semibold)' }}><X size={12} /> {t('mkt.lblNotOpened')}</div>
                                                )}
                                            </div>
                                        </div>
                                    ))
                                )}
                            </div>
                        </div>

                        {/* Message Preview */}
                        <div>
                            <div style={{ ...s.sectionTitle as React.CSSProperties, marginBottom: 'var(--space-3)' }}>{t('mkt.lblMessageContent')}</div>
                            <div style={{ padding: 'var(--space-4)', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)', fontSize: 'var(--text-sm)', color: 'var(--text-secondary)', lineHeight: 1.7, whiteSpace: 'pre-wrap' }}>
                                {selected.message}
                            </div>
                        </div>
                    </div>
                )}
            </SlideOver>

            {/* Add Notification SlideOver */}
            <SlideOver open={isAddOpen} onClose={() => setIsAddOpen(false)} title={t('mkt.lblComposeNotification')}
                footer={<div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}><Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('rtn.btnBack')}</Button><Button onClick={() => { setIsAddOpen(false); addToast('success', 'Notification scheduled'); }}>{t('mkt.btnScheduleNotification')}</Button></div>}
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('mkt.lblCampaignTitle')} placeholder="e.g. End of Summer Sale" />
                    <Select label={t('mkt.lblChannel')} options={[{ label: 'SMS', value: 'SMS' }, { label: 'Email', value: 'Email' }, { label: 'Push', value: 'Push' }, { label: 'WhatsApp', value: 'WhatsApp' }]} />
                    <Select label={t('mkt.lblAudience')} options={[{ label: 'All Clients', value: 'All Clients' }, { label: 'VIP Group', value: 'VIP Group' }, { label: 'Inactive > 30 days', value: 'Inactive > 30 days' }]} />
                    <Input label={t('mkt.lblSendDate')} type="date" />
                    <div>
                        <label style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', display: 'block', marginBottom: 'var(--space-2)' }}>{t('mkt.lblMessageContent')}</label>
                        <textarea style={{ width: '100%', minHeight: 120, padding: 'var(--space-3)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-md)', fontSize: 'var(--text-sm)', background: 'var(--bg-primary)', color: 'var(--text-primary)' }} placeholder={t('mkt.phTypeMessage')} />
                    </div>
                </div>
            </SlideOver>

            {/* Edit Notification SlideOver */}
            <SlideOver open={isEditOpen} onClose={() => { setIsEditOpen(false); setSelected(null); }} title={t('mkt.lblEditNotification')}
                footer={<div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}><Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('rtn.btnBack')}</Button><Button onClick={() => { setIsEditOpen(false); addToast('success', 'Notification updated'); }}>{t('settings.saveChanges')}</Button></div>}
            >
                {selected && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        <Input label={t('mkt.lblCampaignTitle')} defaultValue={selected.title} />
                        <Select label={t('mkt.lblChannel')} defaultValue={selected.channel} options={[{ label: 'SMS', value: 'SMS' }, { label: 'Email', value: 'Email' }, { label: 'Push', value: 'Push' }, { label: 'WhatsApp', value: 'WhatsApp' }]} />
                        <Select label={t('mkt.lblAudience')} defaultValue={selected.audience} options={[{ label: 'All Clients', value: 'All Clients' }, { label: 'VIP Group', value: 'VIP Group' }, { label: 'Inactive > 30 days', value: 'Inactive > 30 days' }, { label: 'Booked Clients', value: 'Booked Clients' }, { label: 'Birthday Today', value: 'Birthday Today' }]} />
                        <Input label={t('mkt.lblSendDate')} type="date" defaultValue={selected.date} />
                        <Select label={t('mkt.lblStatus')} defaultValue={selected.status} options={[{ label: t('mkt.lblDraft'), value: 'draft' }, { label: t('mkt.lblScheduled'), value: 'scheduled' }, { label: t('mkt.lblSentAt') /* Using Sent At since we don't have just Sent */, value: 'sent' }]} />
                        <div>
                            <label style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', display: 'block', marginBottom: 'var(--space-2)' }}>{t('mkt.lblMessageContent')}</label>
                            <textarea style={{ width: '100%', minHeight: 120, padding: 'var(--space-3)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-md)', fontSize: 'var(--text-sm)', background: 'var(--bg-primary)', color: 'var(--text-primary)' }} defaultValue={selected.message} />
                        </div>
                    </div>
                )}
            </SlideOver>

            {/* Delete Confirmation Modal */}
            <Modal open={isDeleteOpen} onClose={() => { setIsDeleteOpen(false); setSelected(null); }} title={t('mkt.lblDeleteNotification')}
                footer={<div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}><Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('rtn.btnBack')}</Button><Button variant="destructive" onClick={handleDelete}>{t('mkt.lblDeleteNotification')}</Button></div>}
            >
                <p style={{ color: 'var(--text-secondary)' }}>{t('mkt.msgDeleteNotificationConfirm')} <strong>{selected?.title}</strong></p>
            </Modal>

            <style>{`.hoverRow:hover { background-color: var(--bg-secondary); }`}</style>
        </div >
    );
}

'use client';

import React, { useState } from 'react';
import { Plus, Calendar, Tag, Edit, Trash2, Eye } from 'lucide-react';
import { useToast, SlideOver, Modal, Input, Button, Select, Badge } from '@/components/ui';
import MarketingTabs from '@/components/MarketingTabs';
import { useTranslation } from '@/hooks/useTranslation';

const initialOffers = [
    { id: 1, name: 'Spring Beauty Festival', discount: 30, type: 'percentage', services: ['Hair Coloring', 'HydraFacial', 'Manicure'], startDate: '2026-03-01', endDate: '2026-03-15', status: 'scheduled', color: '#EC4899', uses: 0, limit: 100, description: 'Celebrate spring with our biggest beauty festival! Get 30% off on select services.' },
    { id: 2, name: 'Eid Special Bundle', discount: 25, type: 'percentage', services: ['Full Body Massage', 'Facial', 'Pedicure'], startDate: '2026-02-10', endDate: '2026-02-20', status: 'active', color: '#F59E0B', uses: 34, limit: 50, description: 'Exclusive Eid bundle for our valued clients. Limited availability!' },
    { id: 3, name: 'Valentines Day Offer', discount: 200, type: 'fixed', services: ['Couples Massage', 'Facial x2'], startDate: '2026-02-14', endDate: '2026-02-14', status: 'active', color: '#EF4444', uses: 8, limit: 20, description: 'A romantic spa experience for two. Book now before it sells out.' },
    { id: 4, name: 'New Client Welcome', discount: 50, type: 'fixed', services: ['Any single service'], startDate: '2026-01-01', endDate: '2026-12-31', status: 'active', color: '#10B981', uses: 67, limit: 500, description: 'Welcome offer for first-time clients. Valid on any single service.' },
    { id: 5, name: 'Flash Friday', discount: 40, type: 'percentage', services: ['All Services'], startDate: '2026-02-07', endDate: '2026-02-07', status: 'expired', color: '#8B5CF6', uses: 22, limit: 30, description: 'One-day flash sale every Friday. Up to 40% off on all services.' },
];

const statusBadge: Record<string, 'success' | 'info' | 'neutral'> = { active: 'success', scheduled: 'info', expired: 'neutral' };

const s: Record<string, React.CSSProperties> = {
    page: { display: 'flex', flexDirection: 'column', gap: 'var(--space-5)' },
    tabBar: { display: 'flex', gap: 'var(--space-1)', borderBottom: '2px solid var(--border-color)', overflowX: 'auto' },
    tab: { padding: 'var(--space-3) var(--space-4)', fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', color: 'var(--text-tertiary)', borderBottom: '2px solid transparent', marginBottom: '-2px', whiteSpace: 'nowrap', textDecoration: 'none' },
    tabActive: { color: 'var(--color-primary-500)', borderBottomColor: 'var(--color-primary-500)' },
    toolbar: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 'var(--space-3)' },
    addBtn: { display: 'flex', alignItems: 'center', gap: 'var(--space-2)', padding: 'var(--space-2) var(--space-5)', background: 'var(--color-primary-500)', color: 'white', borderRadius: 'var(--radius-lg)', fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)' },
    grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(340px, 1fr))', gap: 'var(--space-5)' },
    card: { background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-xl)', overflow: 'hidden', cursor: 'pointer', transition: 'all 0.2s' },
    cardHead: { padding: 'var(--space-5)', display: 'flex', alignItems: 'flex-start', gap: 'var(--space-3)' },
    icon: { width: 44, height: 44, borderRadius: 'var(--radius-lg)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', flexShrink: 0 },
    name: { fontSize: 'var(--text-lg)', fontWeight: 'var(--font-semibold)' },
    discount: { fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)', color: 'var(--color-primary-600)' },
    services: { padding: '0 var(--space-5) var(--space-4)', display: 'flex', flexWrap: 'wrap', gap: 6 },
    svcChip: { padding: '2px 10px', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-full)', fontSize: 'var(--text-xs)', color: 'var(--text-secondary)' },
    footer: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: 'var(--space-3) var(--space-5)', borderTop: '1px solid var(--border-color)', background: 'var(--bg-secondary)' },
    stat: { display: 'flex', alignItems: 'center', gap: 4, fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' },
    actions: { display: 'flex', gap: 'var(--space-2)' },
    btnIcon: { display: 'flex', alignItems: 'center', justifyContent: 'center', width: 28, height: 28, borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)', background: 'var(--bg-primary)', cursor: 'pointer', color: 'var(--text-secondary)' },
    // Detail SlideOver styles
    detailSection: { display: 'flex', flexDirection: 'column', gap: 'var(--space-5)' },
    detailHeader: { display: 'flex', alignItems: 'center', gap: 'var(--space-4)' },
    detailIcon: { width: 56, height: 56, borderRadius: 'var(--radius-xl)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', flexShrink: 0 },
    detailName: { fontSize: 'var(--text-xl)', fontWeight: 'var(--font-bold)' },
    detailDiscount: { fontSize: 'var(--text-3xl)', fontWeight: 'var(--font-bold)', color: 'var(--color-primary-600)' },
    infoGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-4)' },
    infoCard: { background: 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)', padding: 'var(--space-4)' },
    infoLabel: { fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 'var(--space-1)' },
    infoValue: { fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)', color: 'var(--text-primary)' },
    progressContainer: { height: 8, background: 'var(--bg-tertiary)', borderRadius: 4, overflow: 'hidden' },
    progressFill: { height: '100%', borderRadius: 4, transition: 'width 0.5s ease' },
    sectionTitle: { fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '0.05em' },
};

export default function OffersPage() {
    const { addToast } = useToast();
    const [offers, setOffers] = useState(initialOffers);
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [isDetailOpen, setIsDetailOpen] = useState(false);
    const [selectedOffer, setSelectedOffer] = useState<any>(null);

    const openDetail = (offer: any) => { setSelectedOffer(offer); setIsDetailOpen(true); };
    const openEdit = (offer: any) => { setSelectedOffer(offer); setIsDetailOpen(false); setIsEditOpen(true); };
    const openDelete = (offer: any) => { setSelectedOffer(offer); setIsDetailOpen(false); setIsDeleteOpen(true); };

    const { t } = useTranslation();

    const handleDelete = () => {
        setOffers(prev => prev.filter(o => o.id !== selectedOffer?.id));
        setIsDeleteOpen(false);
        setSelectedOffer(null);
        addToast('success', t('mkt.lblDeleteOffer'));
    };

    return (
        <div style={s.page}>
            <MarketingTabs />

            <div style={s.toolbar}>
                <div style={{ fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)' }}>{offers.filter(o => o.status === 'active').length} {t('mkt.lblActiveOffers')}</div>
                <button style={s.addBtn} onClick={() => setIsAddOpen(true)}><Plus size={16} /> {t('mkt.btnNewOffer')}</button>
            </div>

            <div style={s.grid}>
                {offers.map(offer => (
                    <div key={offer.id} style={{ ...s.card, opacity: offer.status === 'expired' ? 0.6 : 1 }} onClick={() => openDetail(offer)}>
                        <div style={s.cardHead}>
                            <div style={{ ...s.icon, background: offer.color }}><Tag size={20} /></div>
                            <div style={{ flex: 1 }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-2)' }}>
                                    <div style={s.name}>{offer.name}</div>
                                    <Badge color={statusBadge[offer.status]} size="sm">{t(`mkt.lbl${offer.status.charAt(0).toUpperCase() + offer.status.slice(1)}`)}</Badge>
                                </div>
                                <div style={s.discount}>
                                    {offer.type === 'percentage' ? `${offer.discount}% ${t('mkt.lblOFF')}` : `-${offer.discount} ${t('mkt.lblEGP')}`}
                                </div>
                            </div>
                        </div>
                        <div style={s.services as React.CSSProperties}>
                            {offer.services.map(svc => <span key={svc} style={s.svcChip}>{svc}</span>)}
                        </div>
                        <div style={s.footer}>
                            <div style={s.stat}><Calendar size={12} /> {offer.startDate} → {offer.endDate}</div>
                            <div style={s.stat}>{offer.uses}/{offer.limit} {t('mkt.lblUsed')}</div>
                            <div style={s.actions} onClick={e => e.stopPropagation()}>
                                <button style={{ ...s.btnIcon, color: 'var(--color-primary-500)' }} onClick={() => openDetail(offer)} title={t('mkt.lblOfferDetails')}><Eye size={12} /></button>
                                <button style={s.btnIcon} onClick={() => openEdit(offer)} title={t('mkt.lblEditOffer')}><Edit size={12} /></button>
                                <button style={{ ...s.btnIcon, color: 'var(--color-error)' }} onClick={() => openDelete(offer)} title={t('mkt.lblDeleteOffer')}><Trash2 size={12} /></button>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            {/* Detail SlideOver */}
            <SlideOver
                open={isDetailOpen}
                onClose={() => { setIsDetailOpen(false); setSelectedOffer(null); }}
                title={t('mkt.lblOfferDetails')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => openDelete(selectedOffer)}><Trash2 size={14} /> {t('mkt.lblDeleteOffer')}</Button>
                        <Button onClick={() => openEdit(selectedOffer)}><Edit size={14} /> {t('mkt.lblEditOffer')}</Button>
                    </div>
                }
            >
                {selectedOffer && (
                    <div style={s.detailSection as React.CSSProperties}>
                        <div style={s.detailHeader as React.CSSProperties}>
                            <div style={{ ...s.detailIcon, background: selectedOffer.color }}><Tag size={24} /></div>
                            <div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-2)', marginBottom: 'var(--space-1)' }}>
                                    <div style={s.detailName}>{selectedOffer.name}</div>
                                    <Badge color={statusBadge[selectedOffer.status]}>{t(`mkt.lbl${selectedOffer.status.charAt(0).toUpperCase() + selectedOffer.status.slice(1)}`)}</Badge>
                                </div>
                                <div style={s.detailDiscount}>
                                    {selectedOffer.type === 'percentage' ? `${selectedOffer.discount}% ${t('mkt.lblOFF')}` : `-${selectedOffer.discount} ${t('mkt.lblEGP')}`}
                                </div>
                            </div>
                        </div>

                        <div style={{ fontSize: 'var(--text-sm)', color: 'var(--text-secondary)', lineHeight: 1.6 }}>
                            {selectedOffer.description}
                        </div>

                        <div style={s.infoGrid as React.CSSProperties}>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblStartDate')}</div>
                                <div style={s.infoValue}>{selectedOffer.startDate}</div>
                            </div>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblEndDate')}</div>
                                <div style={s.infoValue}>{selectedOffer.endDate}</div>
                            </div>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblDiscountType')}</div>
                                <div style={s.infoValue}>{selectedOffer.type === 'percentage' ? t('mkt.lblPercentage') : t('mkt.lblFixedAmount')}</div>
                            </div>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblUsageLimit')}</div>
                                <div style={s.infoValue}>{selectedOffer.limit} {t('mkt.lblRedemptions')}</div>
                            </div>
                        </div>

                        {/* Usage Progress */}
                        <div>
                            <div style={{ ...s.sectionTitle as React.CSSProperties, marginBottom: 'var(--space-3)' }}>{t('mkt.lblUsage')}</div>
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 'var(--space-2)' }}>
                                <span style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)' }}>{selectedOffer.uses} / {selectedOffer.limit}</span>
                                <span style={{ fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)' }}>{Math.round(selectedOffer.uses / selectedOffer.limit * 100)}%</span>
                            </div>
                            <div style={s.progressContainer}>
                                <div style={{ ...s.progressFill, width: `${Math.min(selectedOffer.uses / selectedOffer.limit * 100, 100)}%`, background: selectedOffer.uses >= selectedOffer.limit ? 'var(--color-error)' : 'var(--color-primary-500)' }} />
                            </div>
                        </div>

                        {/* Services */}
                        <div>
                            <div style={{ ...s.sectionTitle as React.CSSProperties, marginBottom: 'var(--space-3)' }}>{t('mkt.lblIncludedServices')}</div>
                            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                                {selectedOffer.services.map((svc: string) => (
                                    <span key={svc} style={{ padding: '6px 14px', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-full)', fontSize: 'var(--text-sm)', color: 'var(--text-secondary)' }}>{svc}</span>
                                ))}
                            </div>
                        </div>
                    </div>
                )}
            </SlideOver>

            {/* Add Offer SlideOver */}
            <SlideOver
                open={isAddOpen}
                onClose={() => setIsAddOpen(false)}
                title={t('mkt.lblCreateNewOffer')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('rtn.btnBack')}</Button>
                        <Button onClick={() => { setIsAddOpen(false); addToast('success', t('mkt.btnNewOffer')); }}>{t('mkt.btnNewOffer')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('mkt.lblOfferName')} placeholder="e.g. Summer Special" />
                    <Input label={t('mkt.lblDescription')} placeholder="Brief description of the offer" />
                    <Select label={t('mkt.lblDiscountType')} options={[{ label: t('mkt.lblPercentage'), value: 'percentage' }, { label: t('mkt.lblFixedAmount'), value: 'fixed' }]} />
                    <Input label={t('mkt.lblDiscountValue')} type="number" placeholder="0" />
                    <Input label={t('mkt.lblUsageLimit')} type="number" placeholder="e.g. 100" />
                    <Input label={t('mkt.lblStartDate')} type="date" />
                    <Input label={t('mkt.lblEndDate')} type="date" />
                    <Select label={t('mkt.lblStatus')} options={[{ label: t('mkt.lblActive'), value: 'active' }, { label: t('mkt.lblScheduled'), value: 'scheduled' }]} />
                </div>
            </SlideOver>

            {/* Edit Offer SlideOver */}
            <SlideOver
                open={isEditOpen}
                onClose={() => { setIsEditOpen(false); setSelectedOffer(null); }}
                title={t('mkt.lblEditOffer')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('rtn.btnBack')}</Button>
                        <Button onClick={() => { setIsEditOpen(false); addToast('success', t('mkt.lblEditOffer')); }}>{t('mkt.lblEditOffer')}</Button>
                    </div>
                }
            >
                {selectedOffer && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        <Input label={t('mkt.lblOfferName')} defaultValue={selectedOffer.name} />
                        <Input label={t('mkt.lblDescription')} defaultValue={selectedOffer.description} />
                        <Select label={t('mkt.lblDiscountType')} defaultValue={selectedOffer.type} options={[{ label: t('mkt.lblPercentage'), value: 'percentage' }, { label: t('mkt.lblFixedAmount'), value: 'fixed' }]} />
                        <Input label={t('mkt.lblDiscountValue')} type="number" defaultValue={selectedOffer.discount} />
                        <Input label={t('mkt.lblUsageLimit')} type="number" defaultValue={selectedOffer.limit} />
                        <Input label={t('mkt.lblStartDate')} type="date" defaultValue={selectedOffer.startDate} />
                        <Input label={t('mkt.lblEndDate')} type="date" defaultValue={selectedOffer.endDate} />
                        <Select label={t('mkt.lblStatus')} defaultValue={selectedOffer.status} options={[{ label: t('mkt.lblActive'), value: 'active' }, { label: t('mkt.lblScheduled'), value: 'scheduled' }, { label: t('mkt.lblExpired'), value: 'expired' }]} />
                    </div>
                )}
            </SlideOver>

            {/* Delete Confirmation Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedOffer(null); }}
                title={t('mkt.lblDeleteOffer')}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('rtn.btnBack')}</Button>
                        <Button variant="destructive" onClick={handleDelete}>{t('mkt.lblDeleteOffer')}</Button>
                    </div>
                }
            >
                <div>
                    <p style={{ color: 'var(--text-secondary)' }}>
                        {t('mkt.msgDeleteOfferConfirm')} <strong>{selectedOffer?.name}</strong>
                    </p>
                </div>
            </Modal>

            <style>{`.hoverRow:hover { background-color: var(--bg-secondary); }`}</style>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import { Plus, Package, Check, Users, Edit, Trash2, MoreVertical, Eye } from 'lucide-react';
import { useToast, SlideOver, Modal, Input, Button, DropdownMenu, Select, Badge } from '@/components/ui';

import MarketingTabs from '@/components/MarketingTabs';
import { useTranslation } from '@/hooks/useTranslation';

const initialPackages = [
    { id: 1, name: 'Summer Glow Campaign', price: 899, originalPrice: 1200, services: ['Body Scrub', 'Spray Tan', 'Gel Nails', 'Lash Lift'], target: 'New Clients', active: true, sold: 15, color: '#F59E0B', description: 'A complete glow-up package for the summer season. Perfect for new clients looking to try multiple services.' },
    { id: 2, name: 'Refer-a-Friend Bundle', price: 599, originalPrice: 800, services: ['Any Facial', 'Classic Manicure', 'Blow Dry'], target: 'Referral Program', active: true, sold: 28, color: '#10B981', description: 'Reward your referrals with this curated bundle of our most popular services.' },
    { id: 3, name: 'Birthday Special', price: 750, originalPrice: 1050, services: ['Full Styling', 'Makeup', 'Nail Art', 'Photo Shoot'], target: 'Birthday Month', active: true, sold: 12, color: '#EC4899', description: 'Make their birthday extra special with styling, makeup, and a professional photo shoot.' },
    { id: 4, name: 'Corporate Wellness', price: 450, originalPrice: 600, services: ['Chair Massage', 'Mini Facial', 'Express Mani'], target: 'Corporate Partners', active: false, sold: 0, color: '#3B82F6', description: 'Quick wellness sessions designed for busy professionals. Ideal for corporate partner programs.' },
];

const s: Record<string, React.CSSProperties> = {
    page: { display: 'flex', flexDirection: 'column', gap: 'var(--space-5)' },
    toolbar: { display: 'flex', alignItems: 'center', justifyContent: 'flex-end' },
    addBtn: { display: 'flex', alignItems: 'center', gap: 'var(--space-2)', padding: 'var(--space-2) var(--space-5)', background: 'var(--color-primary-500)', color: 'white', borderRadius: 'var(--radius-lg)', fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)' },
    grid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: 'var(--space-5)' },
    card: { background: 'var(--bg-primary)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-xl)', overflow: 'hidden', cursor: 'pointer', transition: 'all 0.2s' },
    cardHead: { padding: 'var(--space-5)', display: 'flex', alignItems: 'center', gap: 'var(--space-3)' },
    icon: { width: 44, height: 44, borderRadius: 'var(--radius-lg)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', flexShrink: 0 },
    name: { fontSize: 'var(--text-lg)', fontWeight: 'var(--font-semibold)' },
    price: { fontSize: 'var(--text-xl)', fontWeight: 'var(--font-bold)', color: 'var(--color-primary-600)' },
    target: { fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' },
    services: { padding: '0 var(--space-5) var(--space-4)', display: 'flex', flexDirection: 'column', gap: 6 },
    svcItem: { display: 'flex', alignItems: 'center', gap: 'var(--space-2)', fontSize: 'var(--text-sm)', color: 'var(--text-secondary)' },
    footer: { display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: 'var(--space-3) var(--space-5)', borderTop: '1px solid var(--border-color)', background: 'var(--bg-secondary)', fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' },
    // Detail styles
    detailSection: { display: 'flex', flexDirection: 'column', gap: 'var(--space-5)' },
    detailHeader: { display: 'flex', alignItems: 'center', gap: 'var(--space-4)' },
    detailIcon: { width: 56, height: 56, borderRadius: 'var(--radius-xl)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', flexShrink: 0 },
    infoGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-4)' },
    infoCard: { background: 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)', padding: 'var(--space-4)' },
    infoLabel: { fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)', textTransform: 'uppercase', letterSpacing: '0.05em', marginBottom: 'var(--space-1)' },
    infoValue: { fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)', color: 'var(--text-primary)' },
    sectionTitle: { fontSize: 'var(--text-sm)', fontWeight: 'var(--font-semibold)', color: 'var(--text-secondary)', textTransform: 'uppercase', letterSpacing: '0.05em' },
};

export default function MarketingPackagesPage() {
    const { addToast } = useToast();
    const { t } = useTranslation();
    const [packages, setPackages] = useState(initialPackages);
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [isDetailOpen, setIsDetailOpen] = useState(false);
    const [selectedPackage, setSelectedPackage] = useState<any>(null);

    const openDetail = (pkg: any) => { setSelectedPackage(pkg); setIsDetailOpen(true); };
    const openEdit = (pkg: any) => { setSelectedPackage(pkg); setIsDetailOpen(false); setIsEditOpen(true); };
    const openDelete = (pkg: any) => { setSelectedPackage(pkg); setIsDetailOpen(false); setIsDeleteOpen(true); };

    const handleDelete = () => {
        setPackages(prev => prev.filter(p => p.id !== selectedPackage?.id));
        setIsDeleteOpen(false);
        setSelectedPackage(null);
        addToast('success', t('mkt.lblDeletePackage'));
    };

    return (
        <div style={s.page}>
            <MarketingTabs />
            <div style={s.toolbar}><button style={s.addBtn} onClick={() => setIsAddOpen(true)}><Plus size={16} /> {t('mkt.btnNewPackage')}</button></div>
            <div style={s.grid}>
                {packages.map(pkg => (
                    <div key={pkg.id} style={{ ...s.card, opacity: pkg.active ? 1 : 0.6 }} onClick={() => openDetail(pkg)}>
                        <div style={s.cardHead}>
                            <div style={{ ...s.icon, background: pkg.color }}><Package size={20} /></div>
                            <div style={{ flex: 1 }}>
                                <div style={s.name}>{pkg.name}</div>
                                <div style={s.price}>{pkg.price} {t('mkt.lblEGP')}</div>
                                <div style={s.target}>{t('mkt.lblTarget')} {pkg.target}</div>
                            </div>
                            <div style={{ marginLeft: 'auto' }} onClick={e => e.stopPropagation()}>
                                <DropdownMenu
                                    trigger={<button style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-tertiary)' }}><MoreVertical size={16} /></button>}
                                    items={[
                                        { label: t('bk.actionView'), icon: <Eye size={14} />, onClick: () => openDetail(pkg) },
                                        { label: t('mkt.lblEditPackage'), icon: <Edit size={14} />, onClick: () => openEdit(pkg) },
                                        { label: t('mkt.lblDeletePackage'), destructive: true, icon: <Trash2 size={14} />, onClick: () => openDelete(pkg) }
                                    ]}
                                />
                            </div>
                        </div>
                        <div style={s.services as React.CSSProperties}>
                            {pkg.services.map((svc, i) => <div key={i} style={s.svcItem}><Check size={14} style={{ color: 'var(--color-success)' }} /> {svc}</div>)}
                        </div>
                        <div style={s.footer}>
                            <span><Users size={12} style={{ display: 'inline', marginRight: 4 }} /> {pkg.sold} {t('mkt.lblSold')}</span>
                            <span>{pkg.active ? `🟢 ${t('mkt.lblActive')}` : '⚪ Inactive'}</span>
                        </div>
                    </div>
                ))}
            </div>

            {/* Detail SlideOver */}
            <SlideOver
                open={isDetailOpen}
                onClose={() => { setIsDetailOpen(false); setSelectedPackage(null); }}
                title={t('mkt.lblPackageDetails')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => openDelete(selectedPackage)}><Trash2 size={14} /> {t('mkt.lblDeletePackage')}</Button>
                        <Button onClick={() => openEdit(selectedPackage)}><Edit size={14} /> {t('mkt.lblEditPackage')}</Button>
                    </div>
                }
            >
                {selectedPackage && (
                    <div style={s.detailSection as React.CSSProperties}>
                        <div style={s.detailHeader as React.CSSProperties}>
                            <div style={{ ...s.detailIcon, background: selectedPackage.color }}><Package size={24} /></div>
                            <div>
                                <div style={{ fontSize: 'var(--text-xl)', fontWeight: 'var(--font-bold)', marginBottom: 'var(--space-1)' }}>{selectedPackage.name}</div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-2)' }}>
                                    <span style={{ fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)', color: 'var(--color-primary-600)' }}>{selectedPackage.price} {t('mkt.lblEGP')}</span>
                                    <span style={{ fontSize: 'var(--text-sm)', color: 'var(--text-tertiary)', textDecoration: 'line-through' }}>{selectedPackage.originalPrice} {t('mkt.lblEGP')}</span>
                                    <Badge color={selectedPackage.active ? 'success' : 'neutral'} size="sm">{selectedPackage.active ? t('mkt.lblActive') : 'Inactive'}</Badge>
                                </div>
                            </div>
                        </div>

                        <div style={{ fontSize: 'var(--text-sm)', color: 'var(--text-secondary)', lineHeight: 1.6 }}>
                            {selectedPackage.description}
                        </div>

                        <div style={s.infoGrid as React.CSSProperties}>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblTargetAudience')}</div>
                                <div style={s.infoValue}>{selectedPackage.target}</div>
                            </div>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblTotalSold')}</div>
                                <div style={s.infoValue}>{selectedPackage.sold} {t('mkt.lblPackages')}</div>
                            </div>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblRevenueGenerated')}</div>
                                <div style={s.infoValue}>{(selectedPackage.sold * selectedPackage.price).toLocaleString()} {t('mkt.lblEGP')}</div>
                            </div>
                            <div style={s.infoCard}>
                                <div style={s.infoLabel as React.CSSProperties}>{t('mkt.lblSavingsPerPackage')}</div>
                                <div style={s.infoValue}>{selectedPackage.originalPrice - selectedPackage.price} {t('mkt.lblEGP')} ({Math.round((1 - selectedPackage.price / selectedPackage.originalPrice) * 100)}% {t('mkt.lblOFF').toLowerCase()})</div>
                            </div>
                        </div>

                        <div>
                            <div style={{ ...s.sectionTitle as React.CSSProperties, marginBottom: 'var(--space-3)' }}>{t('mkt.lblIncludedServices')} ({selectedPackage.services.length})</div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                                {selectedPackage.services.map((svc: string, i: number) => (
                                    <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-3)', padding: 'var(--space-3)', background: 'var(--bg-secondary)', borderRadius: 'var(--radius-lg)' }}>
                                        <Check size={16} style={{ color: 'var(--color-success)' }} />
                                        <span style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)' }}>{svc}</span>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                )}
            </SlideOver>

            {/* Add Package SlideOver */}
            <SlideOver open={isAddOpen} onClose={() => setIsAddOpen(false)} title={t('mkt.lblCreateNewPackage')}
                footer={<div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}><Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('rtn.btnBack')}</Button><Button onClick={() => { setIsAddOpen(false); addToast('success', t('mkt.btnSavePackage')); }}>{t('mkt.btnSavePackage')}</Button></div>}
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('mkt.lblPackageName')} placeholder="e.g. Summer Glow" />
                    <Input label={t('mkt.lblDescription')} placeholder="Brief description" />
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-3)' }}>
                        <Input label={t('mkt.lblPrice')} type="number" placeholder="0.00" />
                        <Input label={t('mkt.lblOriginalPrice')} type="number" placeholder="0.00" />
                    </div>
                    <Input label={t('mkt.lblTargetAudience')} placeholder="e.g. New Clients" />
                    <Select label={t('mkt.lblStatus')} options={[{ label: t('mkt.lblActive'), value: 'active' }, { label: t('mkt.lblDraft'), value: 'draft' }]} />
                </div>
            </SlideOver>

            {/* Edit Package SlideOver */}
            <SlideOver open={isEditOpen} onClose={() => { setIsEditOpen(false); setSelectedPackage(null); }} title={t('mkt.lblEditPackage')}
                footer={<div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}><Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('rtn.btnBack')}</Button><Button onClick={() => { setIsEditOpen(false); addToast('success', t('settings.saveChanges')); }}>{t('settings.saveChanges')}</Button></div>}
            >
                {selectedPackage && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        <Input label={t('mkt.lblPackageName')} defaultValue={selectedPackage.name} />
                        <Input label={t('mkt.lblDescription')} defaultValue={selectedPackage.description} />
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-3)' }}>
                            <Input label={t('mkt.lblPrice')} type="number" defaultValue={selectedPackage.price} />
                            <Input label={t('mkt.lblOriginalPrice')} type="number" defaultValue={selectedPackage.originalPrice} />
                        </div>
                        <Input label={t('mkt.lblTargetAudience')} defaultValue={selectedPackage.target} />
                        <Select label={t('mkt.lblStatus')} defaultValue={selectedPackage.active ? 'active' : 'draft'} options={[{ label: t('mkt.lblActive'), value: 'active' }, { label: t('mkt.lblDraft'), value: 'draft' }]} />
                    </div>
                )}
            </SlideOver>

            {/* Delete Confirmation Modal */}
            <Modal open={isDeleteOpen} onClose={() => { setIsDeleteOpen(false); setSelectedPackage(null); }} title={t('mkt.lblDeletePackage')}
                footer={<div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}><Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('rtn.btnBack')}</Button><Button variant="destructive" onClick={handleDelete}>{t('mkt.lblDeletePackage')}</Button></div>}
            >
                <p style={{ color: 'var(--text-secondary)' }}>{t('mkt.msgDeletePackageConfirm')} <strong>{selectedPackage?.name}</strong></p>
            </Modal>
        </div>
    );
}

