        </div>
    );
}

export default function BranchesPage() {
    const { addToast } = useToast();
    const { t } = useTranslation();
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [selectedBranch, setSelectedBranch] = useState<any>(null);

    return (
        <div style={s.page}>
            <SettingsTabs />
            <div style={s.toolbar}>
                <Button onClick={() => setIsAddOpen(true)}><Plus size={16} style={{ marginRight: 8 }} /> {t('settings.branches.addBranch')}</Button>
            </div>
            <div style={s.grid}>
                {branches.map(b => (
                    <div key={b.id} style={s.card}>
                        <div style={{ ...s.cardHead as React.CSSProperties, justifyContent: 'space-between' }}>
                            <div style={{ display: 'flex', gap: 'var(--space-3)' }}>
                                <div style={s.icon}><Building2 size={20} /></div>
                                <div><div style={s.name}>{b.name}</div><span style={s.badge}>{b.status}</span></div>
