                <div style={cs.actionRow}>
                    <div style={cs.actionInfo}>
                        <div style={cs.iconBox}><Database size={20} /></div>
                        <div>
                            <div style={{ fontWeight: 'var(--font-medium)' }}>{t('settings.data.autoBackup')}</div>
