                        <div style={{ color: 'var(--text-tertiary)', marginBottom: 'var(--space-2)' }}>{t('settings.data.dragDrop')}</div>
                        <Button variant="outline" size="sm">{t('settings.data.browseFiles')}</Button>
                    </div>
                </div>
            </Modal>
        </div>
    );
