export default function IntegrationsPage() {
    const { addToast } = useToast();
    const { t, lang } = useTranslation();
    const [integrations, setIntegrations] = React.useState(initialIntegrations);
    const [selectedIntegration, setSelectedIntegration] = React.useState<any>(null);
    const [isModalOpen, setIsModalOpen] = React.useState(false);
    const [isSettingsOpen, setIsSettingsOpen] = React.useState(false);

    const connectedCount = integrations.filter(i => i.status === 'connected').length;
    const totalCount = integrations.length;

    const handleDisconnect = (integration: any) => {
        setSelectedIntegration(integration);
        setIsModalOpen(true);
    };

    const handleConnect = (integration: any) => {
        setSelectedIntegration(integration);
        setIsModalOpen(true);
    };

    const handleSettings = (integration: any) => {
        setSelectedIntegration(integration);
        setIsSettingsOpen(true);
    };

    const confirmAction = () => {
        const isConnecting = selectedIntegration.status === 'disconnected';
        setIntegrations(prev => prev.map(i =>
            i.id === selectedIntegration.id
                ? { ...i, status: isConnecting ? 'connected' : 'disconnected' }
                : i
        ));
        addToast(isConnecting ? 'success' : 'info', `${selectedIntegration.name} ${isConnecting ? 'connected' : 'disconnected'} successfully.`);
        setIsModalOpen(false);
        setSelectedIntegration(null);
    };

    return (
        <div style={s.page} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
            <SettingsTabs />

            {/* Stats */}
            <div style={s.statsRow}>
                <div style={s.statCard}>
                    <div style={{ ...s.statIcon, background: 'var(--color-success-light)', color: 'var(--color-success)' }}>
                        <CheckCircle size={20} />
                    </div>
                    <div>
                        <div style={{ fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)' }}>{connectedCount}</div>
                        <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{t('settings.integrations.connected')}</div>
                    </div>
                </div>
                <div style={s.statCard}>
                    <div style={{ ...s.statIcon, background: 'var(--color-gray-100)', color: 'var(--text-tertiary)' }}>
                        <XCircle size={20} />
                    </div>
                    <div>
                        <div style={{ fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)' }}>{totalCount - connectedCount}</div>
                        <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{t('settings.integrations.available')}</div>
                    </div>
                </div>
                <div style={s.statCard}>
                    <div style={{ ...s.statIcon, background: 'var(--color-primary-50)', color: 'var(--color-primary-600)' }}>
                        <Zap size={20} />
                    </div>
                    <div>
                        <div style={{ fontSize: 'var(--text-2xl)', fontWeight: 'var(--font-bold)' }}>{totalCount}</div>
                        <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{t('settings.integrations.total')}</div>
                    </div>
                </div>
            </div>

            {/* Grouped by Category */}
            {CATEGORIES.map(cat => {
                const items = integrations.filter(i => i.category === cat.key);
                if (items.length === 0) return null;
                const catLabelKey: Record<string, string> = {
                    'communication': 'settings.integrations.catComm',
                    'payment': 'settings.integrations.catPay',
                    'scheduling': 'settings.integrations.catSched',
                    'marketing': 'settings.integrations.catMarket',
                    'automation': 'settings.integrations.catAuto',
                    'location': 'settings.integrations.catLoc'
                };
                return (
                    <div key={cat.key}>
                        <div style={s.categoryLabel}>{t(catLabelKey[cat.key] || cat.label)}</div>
                        <div style={s.grid}>
                            {items.map(i => (
                                <div key={i.id} style={{
                                    ...s.card,
                                    ...(i.status === 'connected' ? { borderColor: `${i.color}40` } : {}),
                                }}>
                                    <div style={{ ...s.icon, background: i.color }}>{i.icon}</div>
                                    <div style={{ flex: 1 }}>
                                        <div style={s.name}>{i.name}</div>
                                        <div style={s.desc}>{i.desc}</div>
                                        <div style={s.statusRow}>
                                            {i.status === 'connected' ? (
                                                <>
                                                    <span style={{ ...s.badge, background: 'var(--color-success-light)', color: 'var(--color-success)' }}>
                                                        <CheckCircle size={12} /> {t('settings.integrations.connected')}
                                                    </span>
                                                    <button
                                                        onClick={() => handleSettings(i)}
                                                        style={{ ...s.actionBtn, color: 'var(--text-tertiary)' }}
                                                    >
                                                        <Settings size={12} style={{ marginInlineEnd: 4 }} /> {t('settings.integrations.settings')}
                                                    </button>
                                                    <button
                                                        onClick={() => handleDisconnect(i)}
                                                        style={{ ...s.actionBtn, color: 'var(--color-error)', borderColor: 'var(--color-error)' }}
                                                    >
                                                        <XCircle size={12} style={{ marginInlineEnd: 4 }} /> {t('settings.integrations.disconnect')}
                                                    </button>
                                                </>
                                            ) : (
                                                <button onClick={() => handleConnect(i)} style={{ ...s.actionBtn, color: 'var(--color-primary-600)', borderColor: 'var(--color-primary-400)' }}>
                                                    <Zap size={12} style={{ marginInlineEnd: 4 }} /> {t('settings.integrations.connect')}
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                );
            })}

            {/* Connect/Disconnect Modal */}
            <Modal
                open={isModalOpen}
                onClose={() => { setIsModalOpen(false); setSelectedIntegration(null); }}
                title={`${selectedIntegration?.status === 'disconnected' ? t('settings.integrations.connect') : t('settings.integrations.disconnect')} ${selectedIntegration?.name}`}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsModalOpen(false)}>{t('settings.integrations.cancel')}</Button>
                        <Button
                            variant={selectedIntegration?.status === 'disconnected' ? 'primary' : 'destructive'}
                            onClick={confirmAction}
                        >
                            {selectedIntegration?.status === 'disconnected' ? t('settings.integrations.confirmConn') : t('settings.integrations.confirmDisconn')}
                        </Button>
                    </div>
                }
            >
                <p style={{ color: 'var(--text-secondary)' }}>
                    {selectedIntegration?.status === 'disconnected' ? t('settings.integrations.connMsg1') : t('settings.integrations.disconnMsg1')}
                    <strong>{selectedIntegration?.name}</strong>
                    {selectedIntegration?.status === 'disconnected' ? t('settings.integrations.connMsg2') : t('settings.integrations.disconnMsg2')}
                </p>
            </Modal>

            {/* Integration Settings SlideOver */}
            <SlideOver
                open={isSettingsOpen}
                onClose={() => { setIsSettingsOpen(false); setSelectedIntegration(null); }}
                title={`${selectedIntegration?.name} ${t('settings.integrations.settings')}`}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsSettingsOpen(false)}>{t('settings.integrations.cancel')}</Button>
                        <Button onClick={() => { setIsSettingsOpen(false); addToast('success', `${selectedIntegration?.name} settings saved.`); }}>{t('settings.integrations.saveSettings')}</Button>
                    </div>
                }
            >
                {selectedIntegration && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-5)' }}>
                        {/* Status */}
                        <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--space-3)', padding: 'var(--space-4)', background: 'var(--color-success-light)', borderRadius: 'var(--radius-lg)' }}>
                            <CheckCircle size={18} style={{ color: 'var(--color-success)' }} />
                            <div>
                                <div style={{ fontWeight: 'var(--font-semibold)', fontSize: 'var(--text-sm)' }}>{t('settings.integrations.activeStatus')}</div>
                                <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{t('settings.integrations.lastSynced')}</div>
                            </div>
                        </div>

                        {/* API Key */}
                        <div>
                            <label style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', display: 'block', marginBottom: 'var(--space-2)' }}>{t('settings.integrations.apiKey')}</label>
                            <div style={{
                                padding: 'var(--space-3)', background: 'var(--bg-secondary)',
                                borderRadius: 'var(--radius-md)', fontFamily: 'monospace',
                                fontSize: 'var(--text-sm)', color: 'var(--text-secondary)',
                                border: '1px solid var(--border-color)',
                            }} dir="ltr">
                                sk-••••••••••••••••{selectedIntegration.name.slice(0, 4).toUpperCase()}
                            </div>
                        </div>

                        {/* Webhook URL */}
                        <div>
                            <label style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', display: 'block', marginBottom: 'var(--space-2)' }}>{t('settings.integrations.webhookUrl')}</label>
                            <Input
                                defaultValue={`https://api.waqty.com/webhooks/${selectedIntegration.name.toLowerCase().replace(/\s/g, '-')}`}
                                dir="ltr"
                            />
                        </div>

                        {/* Sync Settings */}
                        <div>
                            <label style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', display: 'block', marginBottom: 'var(--space-2)' }}>{t('settings.integrations.syncFreq')}</label>
                            <Select
                                options={[
                                    { label: t('settings.integrations.syncRealtime'), value: 'realtime' },
                                    { label: t('settings.integrations.sync5min'), value: '5min' },
                                    { label: t('settings.integrations.sync15min'), value: '15min' },
                                    { label: t('settings.integrations.sync1hr'), value: '1hr' },
                                    { label: t('settings.integrations.syncManual'), value: 'manual' },
                                ]}
                                defaultValue="realtime"
                            />
                        </div>

                        {/* Notifications */}
                        <div>
                            <label style={{ fontSize: 'var(--text-sm)', fontWeight: 'var(--font-medium)', display: 'block', marginBottom: 'var(--space-2)' }}>{t('settings.integrations.notifications')}</label>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-3)' }}>
                                <Switch checked={true} label={t('settings.integrations.notifyError')} />
                                <Switch checked={true} label={t('settings.integrations.notifyDisconn')} />
                                <Switch checked={false} label={t('settings.integrations.notifySummary')} />
                            </div>
                        </div>

                        {/* Danger Zone */}
                        <div style={{
                            padding: 'var(--space-4)', borderRadius: 'var(--radius-lg)',
                            border: '1px solid var(--color-error)', background: 'var(--color-error-light)',
                        }}>
                            <div style={{ fontWeight: 'var(--font-semibold)', fontSize: 'var(--text-sm)', color: 'var(--color-error)', marginBottom: 'var(--space-2)' }}>{t('settings.integrations.dangerZone')}</div>
                            <div style={{ fontSize: 'var(--text-xs)', color: 'var(--text-secondary)', marginBottom: 'var(--space-3)' }}>
                                {t('settings.integrations.dangerDesc')}
                            </div>
                            <Button
                                variant="destructive"
                                size="sm"
                                onClick={() => {
                                    setIsSettingsOpen(false);
                                    handleDisconnect(selectedIntegration);
                                }}
                            >
                                <XCircle size={14} style={{ marginInlineEnd: 8 }} /> {t('settings.integrations.disconnect')} {selectedIntegration.name}
                            </Button>
                        </div>
                    </div>
                )}
            </SlideOver>
        </div>
    );
}

'use client';

import React, { useState, useEffect } from 'react';
import SettingsTabs from '@/components/SettingsTabs';
import { Button, Input, Textarea } from '@/components/ui';
import { Save, Check } from 'lucide-react';
import { useSettings } from '@/contexts/SettingsContext';
import styles from './settings.module.css';
import { useTranslation } from '@/hooks/useTranslation';

// Simple Toggle Component (since we don't have a reusable Switch component in ui/index yet, or maybe we do? 
// Based on previous logs, I saw Button, Input, Select, Textarea in imports. 
// I'll check ui/index.tsx content from previous logs. 
// Ah, the previous settings page imported Switch from '@/components/ui'.
// Let me double check if Switch is exported from components/ui/index.tsx.
// It was imported in the previous file. safely assume it exists.
import { Switch } from '@/components/ui';

export default function SettingsPage() {
    const { settings, updateSettings } = useSettings();
    const [localSettings, setLocalSettings] = useState(settings);
    const [saved, setSaved] = useState(false);
    const { t, lang } = useTranslation();

    // Sync local state when context settings load/change
    useEffect(() => {
        setLocalSettings(settings);
    }, [settings]);

    const handleSave = () => {
        updateSettings(localSettings);
        setSaved(true);
        setTimeout(() => setSaved(false), 2000);
    };

    const handleChange = (field: keyof typeof settings, value: any) => {
        setLocalSettings(prev => ({ ...prev, [field]: value }));
        setSaved(false);
    };

    return (
        <div className={styles.page} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
            <div className={styles.header}>
                <h1 className={styles.title}>{t('settings.title')}</h1>
                <p className={styles.description}>{t('settings.desc')}</p>
            </div>

            <SettingsTabs />

            {/* Business Info Card */}
            <div className={styles.card}>
                <div className={styles.cardTitle}>{t('settings.bizInfo')}</div>
                <div className={styles.cardDesc}>{t('settings.bizDesc')}</div>

                <div className={styles.formGrid}>
                    <div className={styles.field}>
                        <Input
                            label={t('settings.bizName')}
                            value={localSettings.businessName}
                            onChange={(e) => handleChange('businessName', e.target.value)}
                        />
                    </div>
                    <div className={styles.field}>
                        <Input
                            label={t('settings.legalName')}
                            value={localSettings.legalName}
                            onChange={(e) => handleChange('legalName', e.target.value)}
                        />
                    </div>
                    <div className={styles.field}>
                        <Input
                            label={t('settings.crNumber')}
                            value={localSettings.crNumber}
                            onChange={(e) => handleChange('crNumber', e.target.value)}
                        />
                    </div>
                    <div className={styles.field}>
                        <Input
                            label={t('settings.vatNumber')}
                            value={localSettings.vatNumber}
                            onChange={(e) => handleChange('vatNumber', e.target.value)}
                        />
                    </div>
                    <div className={styles.field}>
                        <Textarea
                            label={t('settings.address')}
                            value={localSettings.address}
                            onChange={(e) => handleChange('address', e.target.value)}
                        />
                    </div>
                    <div className={styles.field}>
                        <Input
                            label={t('settings.phone')}
                            value={localSettings.phone}
                            onChange={(e) => handleChange('phone', e.target.value)}
                        />
                    </div>
                    <div className={styles.field}>
                        <Input
                            label={t('settings.email')}
                            type="email"
                            value={localSettings.email}
                            onChange={(e) => handleChange('email', e.target.value)}
                        />
                    </div>
                </div>
            </div>

            {/* Booking Preferences Card */}
            <div className={styles.card}>
                <div className={styles.cardTitle}>{t('settings.bookPrefTitle')}</div>
                <div className={styles.cardDesc}>{t('settings.bookPrefDesc')}</div>

                <div className={styles.formGrid}>
                    <div className={styles.switchRow}>
                        <div className={styles.switchLabel}>
                            <span className={styles.switchTitle}>{t('settings.onlineBooking')}</span>
                            <span className={styles.switchDesc}>{t('settings.onlineBookingDesc')}</span>
                        </div>
                        <Switch
                            checked={localSettings.allowOnlineBooking}
                            onChange={(c) => handleChange('allowOnlineBooking', c)}
                        />
                    </div>

                    <div className={styles.switchRow}>
                        <div className={styles.switchLabel}>
                            <span className={styles.switchTitle}>{t('settings.walkIn')}</span>
                            <span className={styles.switchDesc}>{t('settings.walkInDesc')}</span>
                        </div>
                        <Switch
                            checked={localSettings.allowWalkIn}
                            onChange={(c) => handleChange('allowWalkIn', c)}
                        />
                    </div>

                    <div className={styles.switchRow}>
                        <div className={styles.switchLabel}>
                            <span className={styles.switchTitle}>{t('settings.reqDeposit')}</span>
                            <span className={styles.switchDesc}>{t('settings.reqDepositDesc')}</span>
                        </div>
                        <Switch
                            checked={localSettings.requireDeposit}
                            onChange={(c) => handleChange('requireDeposit', c)}
                        />
                    </div>

                    <div className={styles.switchRow}>
                        <div className={styles.switchLabel}>
                            <span className={styles.switchTitle}>{t('settings.smsReminders')}</span>
                            <span className={styles.switchDesc}>{t('settings.smsRemindersDesc')}</span>
                        </div>
                        <Switch
                            checked={localSettings.sendSmsReminders}
                            onChange={(c) => handleChange('sendSmsReminders', c)}
                        />
                    </div>

                    <div className={styles.switchRow}>
                        <div className={styles.switchLabel}>
                            <span className={styles.switchTitle}>{t('settings.autoConfirm')}</span>
                            <span className={styles.switchDesc}>{t('settings.autoConfirmDesc')}</span>
                        </div>
                        <Switch
                            checked={localSettings.autoConfirm}
                            onChange={(c) => handleChange('autoConfirm', c)}
                        />
                    </div>

                    <div className={styles.field}>
                        <Input
                            label={t('settings.defaultGap')}
                            type="number"
                            value={localSettings.defaultGap}
                            onChange={(e) => handleChange('defaultGap', parseInt(e.target.value) || 0)}
                            hint={t('settings.defaultGapHint')}
                            style={{ maxWidth: 200 }}
                            dir="ltr"
                        />
                    </div>
                    <div className={styles.field}>
                        <Input
                            label={t('settings.cancelWindow')}
                            type="number"
                            value={localSettings.cancellationWindow}
                            onChange={(e) => handleChange('cancellationWindow', parseInt(e.target.value) || 0)}
                            hint={t('settings.cancelWindowHint')}
                            style={{ maxWidth: 200 }}
                            dir="ltr"
                        />
                    </div>
                </div>
            </div>

            <div className={styles.actions}>
                <Button onClick={handleSave} style={{ width: '100%', maxWidth: '200px' }}>
                    {saved ? <><Check size={16} /> {t('settings.saved')}</> : <><Save size={16} /> {t('settings.saveChanges')}</>}
                </Button>
            </div>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import {
    Plus,
    Edit,
    Trash2,
    CreditCard,
    Move
} from 'lucide-react';
import {
    Button,
    Badge,
    Modal,
    Input,
    Select,
    useToast
} from '@/components/ui';
import SettingsTabs from '@/components/SettingsTabs';
import styles from './page.module.css';
import { useTranslation } from '@/hooks/useTranslation';

// Mock Data
const methods = [
    { id: 1, name: 'Cash', type: 'Cash', fee: '0%', status: 'Active' },
    { id: 2, name: 'Credit Card (Visa/Master)', type: 'Card', fee: '2.5%', status: 'Active' },
    { id: 3, name: 'Bank Transfer', type: 'Bank', fee: '0%', status: 'Active' },
    { id: 4, name: 'Vodafone Cash', type: 'Mobile Wallet', fee: '1%', status: 'Active' },
];

export default function PaymentMethodsPage() {
    const { addToast } = useToast();
    const { t } = useTranslation();
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [selectedMethod, setSelectedMethod] = useState<any>(null);

    return (
        <div className={styles.page}>
            <div className={styles.header}>
                <div className={styles.titleGroup}>
                    <h1>{t('settings.paymentMethods.title')}</h1>
                    <div className={styles.subtitle}>{t('settings.paymentMethods.desc')}</div>
                </div>
                <div className={styles.actions}>
                    <Button onClick={() => setIsAddOpen(true)}><Plus size={16} /> {t('settings.paymentMethods.addMethod')}</Button>
                </div>
            </div>

            <SettingsTabs />

            <div className={styles.card}>
                <div className={styles.cardHeader}>
                    <span className={styles.cardTitle}><CreditCard size={18} /> {t('settings.paymentMethods.listTitle')}</span>
                </div>
                <div className={styles.tableWrapper}>
                    <table className={styles.dataTable}>
                        <thead>
                            <tr>
                                <th style={{ width: 50 }}></th>
                                <th>{t('settings.paymentMethods.colName')}</th>
                                <th>{t('settings.paymentMethods.colType')}</th>
                                <th>{t('settings.paymentMethods.colFee')}</th>
                                <th>{t('settings.paymentMethods.colStatus')}</th>
                                <th>{t('settings.paymentMethods.colActions')}</th>
                            </tr>
                        </thead>
                        <tbody>
                            {methods.map(method => (
                                <tr key={method.id}>
                                    <td><Move size={14} style={{ cursor: 'grab', color: 'var(--text-tertiary)' }} /></td>
                                    <td style={{ fontWeight: 'var(--font-medium)' }}>{method.name}</td>
                                    <td>{method.type}</td>
                                    <td>{method.fee}</td>
                                    <td>
                                        <Badge color={method.status === 'Active' ? 'success' : 'neutral'}>{method.status === 'Active' ? t('settings.safes.active') : t('settings.safes.inactive')}</Badge>
                                    </td>
                                    <td>
                                        <div style={{ display: 'flex', gap: 8 }}>
                                            <Button variant="ghost" size="sm" iconOnly onClick={() => { setSelectedMethod(method); setIsEditOpen(true); }}><Edit size={14} /></Button>
                                            <Button variant="destructive" size="sm" iconOnly onClick={() => { setSelectedMethod(method); setIsDeleteOpen(true); }}><Trash2 size={14} /></Button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Add Payment Method Modal */}
            <Modal
                open={isAddOpen}
                onClose={() => setIsAddOpen(false)}
                title={t('settings.paymentMethods.createTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('settings.paymentMethods.cancel')}</Button>
                        <Button onClick={() => { setIsAddOpen(false); addToast('success', 'Payment method added'); }}>{t('settings.paymentMethods.saveMethod')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('settings.paymentMethods.methodName')} placeholder="e.g. Credit Card (Visa/Master)" />
                    <Select label={t('settings.paymentMethods.methodType')} options={[
                        { label: t('settings.paymentMethods.types.cash'), value: 'Cash' },
                        { label: t('settings.paymentMethods.types.card'), value: 'Card' },
                        { label: t('settings.paymentMethods.types.bank'), value: 'Bank Transfer' },
                        { label: t('settings.paymentMethods.types.wallet'), value: 'Mobile Wallet' }
                    ]} />
                    <Input label={t('settings.paymentMethods.transactionFee')} type="number" defaultValue={0} />
                    <Select label={t('settings.paymentMethods.colStatus')} options={[{ label: t('settings.safes.active'), value: 'Active' }, { label: t('settings.safes.inactive'), value: 'Inactive' }]} />
                </div>
            </Modal>

            {/* Edit Payment Method Modal */}
            <Modal
                open={isEditOpen}
                onClose={() => { setIsEditOpen(false); setSelectedMethod(null); }}
                title={t('settings.paymentMethods.editTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('settings.paymentMethods.cancel')}</Button>
                        <Button onClick={() => { setIsEditOpen(false); addToast('success', 'Payment method updated'); }}>{t('settings.paymentMethods.saveChanges')}</Button>
                    </div>
                }
            >
                {selectedMethod && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        <Input label={t('settings.paymentMethods.methodName')} defaultValue={selectedMethod.name} />
                        <Select label={t('settings.paymentMethods.methodType')} defaultValue={selectedMethod.type} options={[
                            { label: t('settings.paymentMethods.types.cash'), value: 'Cash' },
                            { label: t('settings.paymentMethods.types.card'), value: 'Card' },
                            { label: t('settings.paymentMethods.types.bank'), value: 'Bank' },
                            { label: t('settings.paymentMethods.types.wallet'), value: 'Mobile Wallet' }
                        ]} />
                        <Input label={t('settings.paymentMethods.transactionFee')} type="number" defaultValue={parseFloat(selectedMethod.fee)} />
                        <Select label={t('settings.paymentMethods.colStatus')} defaultValue={selectedMethod.status} options={[{ label: t('settings.safes.active'), value: 'Active' }, { label: t('settings.safes.inactive'), value: 'Inactive' }]} />
                    </div>
                )}
            </Modal>

            {/* Delete Confirmation Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedMethod(null); }}
                title={t('settings.paymentMethods.deleteTitle')}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('settings.paymentMethods.cancel')}</Button>
                        <Button variant="destructive" onClick={() => { setIsDeleteOpen(false); addToast('error', 'Payment method deleted'); }}>{t('settings.paymentMethods.confirmDelete')}</Button>
                    </div>
                }
            >
                <div>
                    <p style={{ color: 'var(--text-secondary)' }}>
                        {t('settings.paymentMethods.deleteWarning')}
                    </p>
                </div>
            </Modal>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import {
    Plus,
    Edit,
    Trash2,
    ShoppingBag
} from 'lucide-react';
import {
    Button,
    Badge,
    Modal,
    Input,
    Select,
    useToast
} from '@/components/ui';
import { useTranslation } from '@/hooks/useTranslation';
import styles from './page.module.css';

// Mock Data
const items = [
    { id: 1, name: 'Office Supplies', category: 'Administrative', limit: '500 EGP', status: 'Active' },
    { id: 2, name: 'Coffee & Tea', category: 'Kitchen', limit: '300 EGP', status: 'Active' },
    { id: 3, name: 'Cleaning Materials', category: 'Maintenance', limit: '400 EGP', status: 'Active' },
    { id: 4, name: 'Cab Fare (Staff)', category: 'Transportation', limit: '200 EGP', status: 'Active' },
];

export default function PettyCashItemsPage() {
    const { addToast } = useToast();
    const { t, lang } = useTranslation();
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [selectedItem, setSelectedItem] = useState<any>(null);

    const getTranslatedCategory = (cat: string) => {
        const key = `settings.petty.cat${cat}` as any;
        return t(key) || cat;
    };

    const getTranslatedStatus = (status: string) => {
        if (status === 'Active') return t('settings.petty.statusActive');
        if (status === 'Inactive') return t('settings.petty.statusInactive');
        return status;
    };

    return (
        <div className={styles.page}>
            <div className={styles.header}>
                <div className={styles.titleGroup}>
                    <h1>{t('settings.petty.title')}</h1>
                    <div className={styles.subtitle}>{t('settings.petty.subtitle')}</div>
                </div>
                <div className={styles.actions}>
                    <Button onClick={() => setIsAddOpen(true)}><Plus size={16} className={lang === 'ar' ? 'ml-2' : 'mr-2'} /> {t('settings.petty.addItem')}</Button>
                </div>
            </div>

            <div className={styles.card}>
                <div className={styles.cardHeader}>
                    <span className={styles.cardTitle}><ShoppingBag size={18} className={lang === 'ar' ? 'ml-2' : 'mr-2'} /> {t('settings.petty.expenseItems')}</span>
                </div>
                <div className="table-wrapper">
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.petty.colName')}</th>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.petty.colCategory')}</th>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.petty.colLimit')}</th>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.petty.colStatus')}</th>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.petty.colActions')}</th>
                            </tr>
                        </thead>
                        <tbody>
                            {items.map(item => (
                                <tr key={item.id}>
                                    <td style={{ fontWeight: 'var(--font-medium)', textAlign: lang === 'ar' ? 'right' : 'left' }}>{item.name}</td>
                                    <td style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}><Badge color="neutral">{getTranslatedCategory(item.category)}</Badge></td>
                                    <td style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{item.limit}</td>
                                    <td style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>
                                        <Badge color={item.status === 'Active' ? 'success' : 'neutral'}>{getTranslatedStatus(item.status)}</Badge>
                                    </td>
                                    <td style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>
                                        <div style={{ display: 'flex', gap: 8 }}>
                                            <Button variant="ghost" size="sm" iconOnly onClick={() => { setSelectedItem(item); setIsEditOpen(true); }}><Edit size={14} /></Button>
                                            <Button variant="destructive" size="sm" iconOnly onClick={() => { setSelectedItem(item); setIsDeleteOpen(true); }}><Trash2 size={14} /></Button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Add Item Modal */}
            <Modal
                open={isAddOpen}
                onClose={() => setIsAddOpen(false)}
                title={t('settings.petty.addModalTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('settings.petty.cancel')}</Button>
                        <Button onClick={() => { setIsAddOpen(false); addToast('success', t('settings.petty.toastAdded')); }}>{t('settings.petty.saveItem')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('settings.petty.itemName')} placeholder="e.g. Office Supplies" />
                    <Select label={t('settings.petty.colCategory')} options={[
                        { label: t('settings.petty.catAdministrative'), value: 'Administrative' },
                        { label: t('settings.petty.catKitchen'), value: 'Kitchen' },
                        { label: t('settings.petty.catMaintenance'), value: 'Maintenance' },
                        { label: t('settings.petty.catTransportation'), value: 'Transportation' }
                    ]} />
                    <Input label={t('settings.petty.limitEgp')} type="number" defaultValue={0} />
                    <Select label={t('settings.petty.colStatus')} options={[{ label: t('settings.petty.statusActive'), value: 'Active' }, { label: t('settings.petty.statusInactive'), value: 'Inactive' }]} />
                </div>
            </Modal>

            {/* Edit Item Modal */}
            <Modal
                open={isEditOpen}
                onClose={() => { setIsEditOpen(false); setSelectedItem(null); }}
                title={t('settings.petty.editModalTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('settings.petty.cancel')}</Button>
                        <Button onClick={() => { setIsEditOpen(false); addToast('success', t('settings.petty.toastUpdated')); }}>{t('settings.petty.saveChanges')}</Button>
                    </div>
                }
            >
                {selectedItem && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        <Input label={t('settings.petty.itemName')} defaultValue={selectedItem.name} />
                        <Select label={t('settings.petty.colCategory')} defaultValue={selectedItem.category} options={[
                            { label: t('settings.petty.catAdministrative'), value: 'Administrative' },
                            { label: t('settings.petty.catKitchen'), value: 'Kitchen' },
                            { label: t('settings.petty.catMaintenance'), value: 'Maintenance' },
                            { label: t('settings.petty.catTransportation'), value: 'Transportation' }
                        ]} />
                        <Input label={t('settings.petty.limitEgp')} type="number" defaultValue={parseInt(selectedItem.limit)} />
                        <Select label={t('settings.petty.colStatus')} defaultValue={selectedItem.status} options={[{ label: t('settings.petty.statusActive'), value: 'Active' }, { label: t('settings.petty.statusInactive'), value: 'Inactive' }]} />
                    </div>
                )}
            </Modal>

            {/* Delete Confirmation Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedItem(null); }}
                title={t('settings.petty.deleteModalTitle')}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('settings.petty.cancel')}</Button>
                        <Button variant="destructive" onClick={() => { setIsDeleteOpen(false); addToast('error', t('settings.petty.toastDeleted')); }}>{t('settings.petty.confirmDelete')}</Button>
                    </div>
                }
            >
                <div>
                    <p style={{ color: 'var(--text-secondary)' }}>
                        {t('settings.petty.deleteConfirmMsg1')}<strong>{selectedItem?.name}</strong>{t('settings.petty.deleteConfirmMsg2')}
                    </p>
                </div>
            </Modal>
        </div>
    );
}

'use client';

import React, { useState } from 'react';
import {
    Plus,
    Edit,
    Trash2,
    LayoutGrid,
    Armchair,
    DoorClosed,
    Monitor
} from 'lucide-react';
import {
    Button,
    Badge,
    useToast,
    Modal,
    Input,
    Select
} from '@/components/ui';
import styles from './page.module.css';
import { useTranslation } from '@/hooks/useTranslation';

// Mock Data
const resources = [
    { id: 1, name: 'Styling Station 1', type: 'Chair', icon: <Armchair size={16} />, capacity: 1, status: 'Active' },
    { id: 2, name: 'Styling Station 2', type: 'Chair', icon: <Armchair size={16} />, capacity: 1, status: 'Active' },
    { id: 3, name: 'Spa Room A', type: 'Room', icon: <DoorClosed size={16} />, capacity: 1, status: 'Maintenance' },
    { id: 4, name: 'Reception PC 1', type: 'Equipment', icon: <Monitor size={16} />, capacity: 0, status: 'Active' },
];

export default function ResourcesPage() {
    const { addToast } = useToast();
    const { t, lang } = useTranslation();
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [selectedResource, setSelectedResource] = useState<any>(null);

    return (
        <div className={styles.page} dir={lang === 'ar' ? 'rtl' : 'ltr'}>
            <div className={styles.header}>
                <div className={styles.titleGroup}>
                    <h1>{t('settings.resources.title')}</h1>
                    <div className={styles.subtitle}>{t('settings.resources.desc')}</div>
                </div>
                <div className={styles.actions}>
                    <Button onClick={() => setIsAddOpen(true)}><Plus size={16} style={{ marginInlineEnd: 8 }} /> {t('settings.resources.add')}</Button>
                </div>
            </div>

            <div className={styles.card}>
                <div className={styles.cardHeader}>
                    <span className={styles.cardTitle}><LayoutGrid size={18} /> {t('settings.resources.listTitle')}</span>
                </div>
                <div className="table-wrapper">
                    <table className="data-table">
                        <thead>
                            <tr>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.resources.colName')}</th>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.resources.colType')}</th>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.resources.colCapacity')}</th>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.resources.colStatus')}</th>
                                <th style={{ textAlign: lang === 'ar' ? 'right' : 'left' }}>{t('settings.resources.colActions')}</th>
                            </tr>
                        </thead>
                        <tbody>
                            {resources.map(res => (
                                <tr key={res.id}>
                                    <td style={{ fontWeight: 'var(--font-medium)', display: 'flex', alignItems: 'center', gap: 8 }}>
                                        {res.icon} {res.name}
                                    </td>
                                    <td>{res.type === 'Chair' ? t('settings.resources.typeChair') : res.type === 'Room' ? t('settings.resources.typeRoom') : t('settings.resources.typeEquip')}</td>
                                    <td>{res.capacity > 0 ? `${res.capacity} ${t('settings.resources.persons')}` : '-'}</td>
                                    <td>
                                        <Badge color={res.status === 'Active' ? 'success' : 'warning'}>{res.status === 'Active' ? t('settings.resources.statusActive') : t('settings.resources.statusMaint')}</Badge>
                                    </td>
                                    <td>
                                        <div style={{ display: 'flex', gap: 8 }}>
                                            <Button variant="ghost" size="sm" iconOnly onClick={() => { setSelectedResource(res); setIsEditOpen(true); }}><Edit size={14} /></Button>
                                            <Button variant="destructive" size="sm" iconOnly onClick={() => { setSelectedResource(res); setIsDeleteOpen(true); }}><Trash2 size={14} /></Button>
                                        </div>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Add Resource Modal */}
            <Modal
                open={isAddOpen}
                onClose={() => setIsAddOpen(false)}
                title={t('settings.resources.createTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('settings.resources.cancel')}</Button>
                        <Button onClick={() => { setIsAddOpen(false); addToast('success', 'Resource created successfully'); }}>{t('settings.resources.saveResource')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('settings.resources.resName')} placeholder="e.g. Styling Station 3" />
                    <Select label={t('settings.resources.resType')} options={[{ label: t('settings.resources.typeChair'), value: 'chair' }, { label: t('settings.resources.typeRoom'), value: 'room' }, { label: t('settings.resources.typeEquip'), value: 'equipment' }]} />
                    <Input label={t('settings.resources.capPersons')} type="number" placeholder="1" dir="ltr" />
                    <Select label={t('settings.resources.colStatus')} options={[{ label: t('settings.resources.statusActive'), value: 'active' }, { label: t('settings.resources.statusMaint'), value: 'maintenance' }]} />
                </div>
            </Modal>

            {/* Edit Resource Modal */}
            <Modal
                open={isEditOpen}
                onClose={() => { setIsEditOpen(false); setSelectedResource(null); }}
                title={t('settings.resources.editTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('settings.resources.cancel')}</Button>
                        <Button onClick={() => { setIsEditOpen(false); addToast('success', 'Resource updated successfully'); }}>{t('settings.resources.saveChanges')}</Button>
                    </div>
                }
            >
                {selectedResource && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        <Input label={t('settings.resources.resName')} defaultValue={selectedResource.name} />
                        <Select label={t('settings.resources.resType')} defaultValue={selectedResource.type.toLowerCase()} options={[{ label: t('settings.resources.typeChair'), value: 'chair' }, { label: t('settings.resources.typeRoom'), value: 'room' }, { label: t('settings.resources.typeEquip'), value: 'equipment' }]} />
                        <Input label={t('settings.resources.capPersons')} type="number" defaultValue={selectedResource.capacity} dir="ltr" />
                        <Select label={t('settings.resources.colStatus')} defaultValue={selectedResource.status.toLowerCase()} options={[{ label: t('settings.resources.statusActive'), value: 'active' }, { label: t('settings.resources.statusMaint'), value: 'maintenance' }]} />
                    </div>
                )}
            </Modal>

            {/* Delete Confirmation Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedResource(null); }}
                title={t('settings.resources.deleteTitle')}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('settings.resources.cancel')}</Button>
                        <Button variant="destructive" onClick={() => { setIsDeleteOpen(false); addToast('error', 'Resource deleted permanently'); }}>{t('settings.resources.confirmDelete')}</Button>
                    </div>
                }
            >
                <div>
                    <p style={{ color: 'var(--text-secondary)' }}>
                        {t('settings.resources.deleteWarning1')}<strong>{selectedResource?.name}</strong>{t('settings.resources.deleteWarning2')}
                    </p>
                </div>
            </Modal>
        </div >
    );
}

'use client';

import React, { useState } from 'react';
import {
    Plus, Edit, Trash2, Lock, DollarSign,
    Vault, MapPin,
} from 'lucide-react';
import {
    Button, Badge, useToast, Modal, Input, Select, SlideOver
} from '@/components/ui';
import styles from './page.module.css';
import SettingsTabs from '@/components/SettingsTabs';
import { useTranslation } from '@/hooks/useTranslation';

const initialSafes = [
    { id: 1, name: 'Main Reception Safe', branch: 'Downtown', balance: 12450, lastActivity: 'Today, 3:20 PM', status: 'Active', color: '#3B82F6' },
    { id: 2, name: 'Back Office Safe', branch: 'Downtown', balance: 50000, lastActivity: 'Today, 11:00 AM', status: 'Active', color: '#10B981' },
    { id: 3, name: 'Petty Cash Box', branch: 'Downtown', balance: 1200, lastActivity: 'Yesterday', status: 'Active', color: '#F59E0B' },
    { id: 4, name: 'Mall Branch Safe', branch: 'Mall of Arabia', balance: 8750, lastActivity: 'Today, 1:45 PM', status: 'Active', color: '#8B5CF6' },
    { id: 5, name: 'New Cairo Drawer', branch: 'New Cairo', balance: 3200, lastActivity: 'Feb 20', status: 'Inactive', color: '#6B7280' },
];

export default function SafesPage() {
    const { addToast } = useToast();
    const { t } = useTranslation();
    const [safesList, setSafesList] = useState(initialSafes);
    const [isAddOpen, setIsAddOpen] = useState(false);
    const [isEditOpen, setIsEditOpen] = useState(false);
    const [isDeleteOpen, setIsDeleteOpen] = useState(false);
    const [selectedSafe, setSelectedSafe] = useState<any>(null);
    const [newSafe, setNewSafe] = useState({ name: '', branch: 'downtown', balance: '', status: 'active' });

    const totalBalance = safesList.reduce((s, safe) => s + safe.balance, 0);
    const activeSafes = safesList.filter(s => s.status === 'Active').length;

    const handleAddSafe = () => {
        if (!newSafe.name) return addToast('error', 'Safe name is required');
        const colors = ['#3B82F6', '#10B981', '#F59E0B', '#8B5CF6', '#EC4899'];
        const branchMap: Record<string, string> = { downtown: 'Downtown', mall: 'Mall of Arabia', newcairo: 'New Cairo' };
        const added = {
            id: Date.now(),
            name: newSafe.name,
            branch: branchMap[newSafe.branch] || 'Downtown',
            balance: parseFloat(newSafe.balance) || 0,
            lastActivity: 'Just now',
            status: newSafe.status === 'active' ? 'Active' : 'Inactive',
            color: colors[Math.floor(Math.random() * colors.length)],
        };
        setSafesList([...safesList, added]);
        setIsAddOpen(false);
        setNewSafe({ name: '', branch: 'downtown', balance: '', status: 'active' });
        addToast('success', `"${added.name}" created successfully`);
    };

    const handleDeleteSafe = () => {
        setSafesList(safesList.filter(s => s.id !== selectedSafe?.id));
        setIsDeleteOpen(false);
        setSelectedSafe(null);
        addToast('success', 'Safe deleted permanently');
    };

    const fmt = (n: number) => n.toLocaleString('en-US');

    return (
        <div className={styles.page}>
            <SettingsTabs />

            <div className={styles.header}>
                <div className={styles.titleGroup}>
                    <h1><Lock size={24} /> {t('settings.safes.title')}</h1>
                    <div className={styles.subtitle}>{t('settings.safes.desc')}</div>
                </div>
                <div className={styles.actions}>
                    <Button onClick={() => setIsAddOpen(true)}><Plus size={16} /> {t('settings.safes.newSafe')}</Button>
                </div>
            </div>

            {/* KPIs */}
            <div className={styles.kpiRow}>
                <div className={styles.kpiCard}>
                    <div className={styles.kpiIcon} style={{ background: 'var(--color-success-light)', color: 'var(--color-success)' }}>
                        <DollarSign size={22} />
                    </div>
                    <div className={styles.kpiContent}>
                        <span className={styles.kpiValue}>{fmt(totalBalance)} EGP</span>
                        <span className={styles.kpiLabel}>{t('settings.safes.totalBalance')}</span>
                    </div>
                </div>
                <div className={styles.kpiCard}>
                    <div className={styles.kpiIcon} style={{ background: 'var(--color-primary-50)', color: 'var(--color-primary-600)' }}>
                        <Vault size={22} />
                    </div>
                    <div className={styles.kpiContent}>
                        <span className={styles.kpiValue}>{activeSafes} / {safesList.length}</span>
                        <span className={styles.kpiLabel}>{t('settings.safes.activeSafes')}</span>
                    </div>
                </div>
                <div className={styles.kpiCard}>
                    <div className={styles.kpiIcon} style={{ background: 'var(--color-info-light)', color: 'var(--color-info)' }}>
                        <MapPin size={22} />
                    </div>
                    <div className={styles.kpiContent}>
                        <span className={styles.kpiValue}>{new Set(safesList.map(s => s.branch)).size}</span>
                        <span className={styles.kpiLabel}>{t('settings.safes.branchesCovered')}</span>
                    </div>
                </div>
            </div>

            {/* Table */}
            <div className={styles.card}>
                <div className={styles.cardHeader}>
                    <span className={styles.cardTitle}><Lock size={16} /> {t('settings.safes.allSafes')}</span>
                    <span style={{ fontSize: 'var(--text-xs)', color: 'var(--text-tertiary)' }}>{safesList.length} {t('settings.safes.safesTotal')}</span>
                </div>
                <table className={styles.dataTable}>
                    <thead>
                        <tr>
                            <th>{t('settings.safes.colSafe')}</th>
                            <th>{t('settings.safes.colBalance')}</th>
                            <th>{t('settings.safes.colLastActivity')}</th>
                            <th>{t('settings.safes.colStatus')}</th>
                            <th style={{ textAlign: 'right' }}>{t('settings.safes.colActions')}</th>
                        </tr>
                    </thead>
                    <tbody>
                        {safesList.map(safe => (
                            <tr key={safe.id}>
                                <td>
                                    <div className={styles.safeName}>
                                        <div className={styles.safeIcon} style={{ background: `${safe.color}18`, color: safe.color }}>
                                            <Vault size={18} />
                                        </div>
                                        <div className={styles.safeInfo}>
                                            <span className={styles.safeLabel}>{safe.name}</span>
                                            <span className={styles.safeBranch}><MapPin size={10} /> {safe.branch}</span>
                                        </div>
                                    </div>
                                </td>
                                <td>
                                    <span className={styles.balance}>{fmt(safe.balance)} EGP</span>
                                </td>
                                <td style={{ fontSize: 'var(--text-sm)', color: 'var(--text-secondary)' }}>
                                    {safe.lastActivity}
                                </td>
                                <td>
                                    <Badge color={safe.status === 'Active' ? 'success' : 'neutral'}>{safe.status === 'Active' ? t('settings.safes.active') : t('settings.safes.inactive')}</Badge>
                                </td>
                                <td>
                                    <div className={styles.actions} style={{ justifyContent: 'flex-end' }}>
                                        <Button variant="ghost" size="sm" iconOnly onClick={() => { setSelectedSafe(safe); setIsEditOpen(true); }}><Edit size={14} /></Button>
                                        <Button variant="ghost" size="sm" iconOnly style={{ color: 'var(--color-error)' }} onClick={() => { setSelectedSafe(safe); setIsDeleteOpen(true); }}><Trash2 size={14} /></Button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {/* Add Safe SlideOver */}
            <SlideOver
                open={isAddOpen}
                onClose={() => setIsAddOpen(false)}
                title={t('settings.safes.createTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsAddOpen(false)}>{t('settings.safes.cancel')}</Button>
                        <Button onClick={handleAddSafe}>{t('settings.safes.createSafe')}</Button>
                    </div>
                }
            >
                <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                    <Input label={t('settings.safes.safeName')} placeholder="e.g. Front Desk Safe" value={newSafe.name} onChange={e => setNewSafe({ ...newSafe, name: e.target.value })} />
                    <Select
                        label={t('settings.safes.branch')}
                        value={newSafe.branch}
                        onChange={e => setNewSafe({ ...newSafe, branch: e.target.value })}
                        options={[{ label: 'Downtown', value: 'downtown' }, { label: 'Mall of Arabia', value: 'mall' }, { label: 'New Cairo', value: 'newcairo' }]}
                    />
                    <Input label={t('settings.safes.initialBalance')} type="number" placeholder="0.00" value={newSafe.balance} onChange={e => setNewSafe({ ...newSafe, balance: e.target.value })} />
                    <Select
                        label={t('settings.safes.status')}
                        value={newSafe.status}
                        onChange={e => setNewSafe({ ...newSafe, status: e.target.value })}
                        options={[{ label: t('settings.safes.active'), value: 'active' }, { label: t('settings.safes.inactive'), value: 'inactive' }]}
                    />
                </div>
            </SlideOver>

            {/* Edit Safe SlideOver */}
            <SlideOver
                open={isEditOpen}
                onClose={() => { setIsEditOpen(false); setSelectedSafe(null); }}
                title={t('settings.safes.editTitle')}
                footer={
                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 'var(--space-3)' }}>
                        <Button variant="ghost" onClick={() => setIsEditOpen(false)}>{t('settings.safes.cancel')}</Button>
                        <Button onClick={() => { setIsEditOpen(false); addToast('success', 'Safe updated successfully'); }}>{t('settings.safes.saveChanges')}</Button>
                    </div>
                }
            >
                {selectedSafe && (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: 'var(--space-4)' }}>
                        <Input label={t('settings.safes.safeName')} defaultValue={selectedSafe.name} />
                        <Select label={t('settings.safes.branch')} defaultValue="downtown" options={[{ label: 'Downtown', value: 'downtown' }, { label: 'Mall of Arabia', value: 'mall' }, { label: 'New Cairo', value: 'newcairo' }]} />
                        <Input label={t('settings.safes.currentBalance')} type="number" defaultValue={selectedSafe.balance} />
                        <Select label={t('settings.safes.status')} defaultValue={selectedSafe.status.toLowerCase()} options={[{ label: t('settings.safes.active'), value: 'active' }, { label: t('settings.safes.inactive'), value: 'inactive' }]} />
                    </div>
                )}
            </SlideOver>

            {/* Delete Confirmation Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedSafe(null); }}
                title={t('settings.safes.deleteTitle')}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('settings.safes.cancel')}</Button>
                        <Button variant="destructive" onClick={handleDeleteSafe}>{t('settings.safes.confirmDelete')}</Button>
                    </div>
                }
            >
                <div>
                    <p style={{ color: 'var(--text-secondary)' }}>
                        {t('settings.safes.deleteWarning')}
                    </p>
                </div>
            </Modal>
        </div>
    );
}

