                        <Select label={t('settings.services.category')} defaultValue={selectedService.category} options={[
                            { label: t('settings.services.hair'), value: 'Hair' },
                            { label: t('settings.services.skin'), value: 'Skin' },
                            { label: t('settings.services.body'), value: 'Body' },
                            { label: t('settings.services.nails'), value: 'Nails' }
                        ]} />
                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 'var(--space-4)' }}>
                            <Input label={t('settings.services.duration')} type="number" defaultValue={selectedService.duration} />
                            <Input label={t('settings.services.price')} type="number" defaultValue={selectedService.price} />
                        </div>
                    </div>
                )}
            </Modal>

            {/* Delete Confirmation Modal */}
            <Modal
                open={isDeleteOpen}
                onClose={() => { setIsDeleteOpen(false); setSelectedService(null); }}
                title={t('settings.services.delete')}
                footer={
                    <div style={{ display: 'flex', gap: 'var(--space-3)', justifyContent: 'flex-end' }}>
                        <Button variant="ghost" onClick={() => setIsDeleteOpen(false)}>{t('settings.services.cancel')}</Button>
                        <Button variant="destructive" onClick={() => { setIsDeleteOpen(false); addToast('error', 'Service permanently removed'); }}>{t('settings.services.confirmDelete')}</Button>
                    </div>
                }
            >
                <div>
                    <p style={{ color: 'var(--text-secondary)' }}>
                        {t('settings.services.deleteWarning')}
                    </p>
                </div>
            </Modal>
        </div>
    );
}

'use client';

import React, { createContext, useContext, useState, useEffect } from 'react';

// Define the shape of our settings
export interface SettingsState {
    businessName: string;
    legalName: string;
    crNumber: string; // Commercial Registration
    vatNumber: string;
    address: string;
    phone: string;
    email: string;
    language: 'en' | 'ar';

    // Preferences
    allowOnlineBooking: boolean;
    allowWalkIn: boolean;
    requireDeposit: boolean;
    sendSmsReminders: boolean;
    autoConfirm: boolean;
    defaultGap: number;
    cancellationWindow: number;
}

// Default values
const defaultSettings: SettingsState = {
    businessName: 'Waqty Beauty Salon',
    legalName: 'Waqty Beauty Services LLC',
    crNumber: 'CR-2024-12345',
    vatNumber: '300-456-789',
    address: '12 El-Nozha St, Heliopolis, Cairo, Egypt',
    phone: '+20 2 1234 5678',
    email: 'info@waqty.com',
    language: 'en',
    allowOnlineBooking: true,
    allowWalkIn: true,
    requireDeposit: false,
    sendSmsReminders: true,
    autoConfirm: true,
    defaultGap: 15,
    cancellationWindow: 24,
};

interface SettingsContextType {
    settings: SettingsState;
    updateSettings: (newSettings: Partial<SettingsState>) => void;
    resetSettings: () => void;
}

const SettingsContext = createContext<SettingsContextType | undefined>(undefined);

export function SettingsProvider({ children }: { children: React.ReactNode }) {
    const [settings, setSettings] = useState<SettingsState>(defaultSettings);
    const [isLoaded, setIsLoaded] = useState(false);

    // Load from localStorage on mount
    useEffect(() => {
        try {
            const stored = localStorage.getItem('waqty_settings');
            if (stored) {
                setSettings({ ...defaultSettings, ...JSON.parse(stored) });
            }
        } catch (error) {
            console.error('Failed to load settings', error);
        } finally {
            setIsLoaded(true);
        }
    }, []);

    // Sync language with HTML document
    useEffect(() => {
        if (typeof document !== 'undefined') {
            document.documentElement.lang = settings.language === 'ar' ? 'ar-EG' : 'en';
            document.documentElement.dir = settings.language === 'ar' ? 'rtl' : 'ltr';
        }
    }, [settings.language]);

    // Update settings wrapper
    const updateSettings = (newSettings: Partial<SettingsState>) => {
        setSettings((prev) => {
            const updated = { ...prev, ...newSettings };
            try {
                localStorage.setItem('waqty_settings', JSON.stringify(updated));
            } catch (error) {
                console.error('Failed to save settings', error);
            }
            return updated;
        });
    };

    const resetSettings = () => {
        setSettings(defaultSettings);
        localStorage.removeItem('waqty_settings');
    };

    // Prevent hydration mismatch by rendering children only after load (optional, 
    // but for settings usually fine to render defaults or loading state)
    // For dashboard, immediate render with defaults is often acceptable to avoid flicker

    return (
        <SettingsContext.Provider value={{ settings, updateSettings, resetSettings }}>
            {children}
        </SettingsContext.Provider>
    );
}

export function useSettings() {
    const context = useContext(SettingsContext);
    if (context === undefined) {
        throw new Error('useSettings must be used within a SettingsProvider');
    }
    return context;
}
